#!/usr/bin/env node

/**
 * Render graphviz diagrams from a skill's SKILL.md to SVG files.
 *
 * Usage:
 *   ./render-graphs.js <skill-directory>           # Render each diagram separately
 *   ./render-graphs.js <skill-directory> --combine # Combine all into one diagram
 *
 * Extracts all ```dot blocks from SKILL.md and renders to SVG.
 * Useful for helping your human partner visualize the process flows.
 *
 * Requires: graphviz (dot) installed on system
 */

const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');

function extractDotBlocks(markdown) {
  const blocks = [];
  const regex = /```dot\n([\s\S]*?)```/g;
  let match;

  while ((match = regex.exec(markdown)) !== null) {
    const content = match[1].trim();

    // Extract digraph name
    const nameMatch = content.match(/digraph\s+(\w+)/);
    const name = nameMatch ? nameMatch[1] : `graph_${blocks.length + 1}`;

    blocks.push({ name, content });
  }

  return blocks;
}

function extractGraphBody(dotContent) {
  // Extract just the body (nodes and edges) from a digraph
  const match = dotContent.match(/digraph\s+\w+\s*\{([\s\S]*)\}/);
  if (!match) return '';

  let body = match[1];

  // Remove rankdir (we'll set it once at the top level)
  body = body.replace(/^\s*rankdir\s*=\s*\w+\s*;?\s*$/gm, '');

  return body.trim();
}

function combineGraphs(blocks, skillName) {
  const bodies = blocks.map((block, i) => {
    const body = extractGraphBody(block.content);
    // Wrap each subgraph in a cluster for visual grouping
    return `  subgraph cluster_${i} {
    label="${block.name}";
    ${body.split('\n').map(line => '  ' + line).join('\n')}
  }`;
  });

  return `digraph ${skillName}_combined {
  rankdir=TB;
  compound=true;
  newrank=true;

${bodies.join('\n\n')}
}`;
}

function renderToSvg(dotContent) {
  try {
    return execSync('dot -Tsvg', {
      input: dotContent,
      encoding: 'utf-8',
      maxBuffer: 10 * 1024 * 1024
    });
  } catch (err) {
    console.error('Error running dot:', err.message);
    if (err.stderr) console.error(err.stderr.toString());
    return null;
  }
}

function main() {
  const args = process.argv.slice(2);
  const combine = args.includes('--combine');
  const skillDirArg = args.find(a => !a.startsWith('--'));

  if (!skillDirArg) {
    console.error('Usage: render-graphs.js <skill-directory> [--combine]');
    console.error('');
    console.error('Options:');
    console.error('  --combine    Combine all diagrams into one SVG');
    console.error('');
    console.error('Example:');
    console.error('  ./render-graphs.js ../subagent-driven-development');
    console.error('  ./render-graphs.js ../subagent-driven-development --combine');
    process.exit(1);
  }

  const skillDir = path.resolve(skillDirArg);
  const skillFile = path.join(skillDir, 'SKILL.md');
  const skillName = path.basename(skillDir).replace(/-/g, '_');

  if (!fs.existsSync(skillFile)) {
    console.error(`Error: ${skillFile} not found`);
    process.exit(1);
  }

  // Check if dot is available
  try {
    execSync('which dot', { encoding: 'utf-8' });
  } catch {
    console.error('Error: graphviz (dot) not found. Install with:');
    console.error('  brew install graphviz    # macOS');
    console.error('  apt install graphviz     # Linux');
    process.exit(1);
  }

  const markdown = fs.readFileSync(skillFile, 'utf-8');
  const blocks = extractDotBlocks(markdown);

  if (blocks.length === 0) {
    console.log('No ```dot blocks found in', skillFile);
    process.exit(0);
  }

  console.log(`Found ${blocks.length} diagram(s) in ${path.basename(skillDir)}/SKILL.md`);

  const outputDir = path.join(skillDir, 'diagrams');
  if (!fs.existsSync(outputDir)) {
    fs.mkdirSync(outputDir);
  }

  if (combine) {
    // Combine all graphs into one
    const combined = combineGraphs(blocks, skillName);
    const svg = renderToSvg(combined);
    if (svg) {
      const outputPath = path.join(outputDir, `${skillName}_combined.svg`);
      fs.writeFileSync(outputPath, svg);
      console.log(`  Rendered: ${skillName}_combined.svg`);

      // Also write the dot source for debugging
      const dotPath = path.join(outputDir, `${skillName}_combined.dot`);
      fs.writeFileSync(dotPath, combined);
      console.log(`  Source: ${skillName}_combined.dot`);
    } else {
      console.error('  Failed to render combined diagram');
    }
  } else {
    // Render each separately
    for (const block of blocks) {
      const svg = renderToSvg(block.content);
      if (svg) {
        const outputPath = path.join(outputDir, `${block.name}.svg`);
        fs.writeFileSync(outputPath, svg);
        console.log(`  Rendered: ${block.name}.svg`);
      } else {
        console.error(`  Failed: ${block.name}`);
      }
    }
  }

  console.log(`\nOutput: ${outputDir}/`);
}

main();

import { Page, Locator, expect } from '@playwright/test';
import { BasePage } from './BasePage';

export class ProfilePage extends BasePage {
  readonly avatar: Locator;
  readonly userName: Locator;
  readonly userLevel: Locator;
  readonly xpProgress: Locator;
  readonly settingsButton: Locator;
  readonly statsCards: Locator;
  readonly tabsList: Locator;

  constructor(page: Page) {
    super(page);
    this.avatar = page.locator(
      '.flex-col.md\\:flex-row.items-start.md\\:items-center.gap-6 >> .h-24.w-24',
    );
    this.userName = page.getByRole('heading', { level: 1 });
    this.userLevel = page.locator('.badge, .bg-primary\\/20');
    this.xpProgress = page.locator('.progress, .h-2');
    this.settingsButton = page.getByRole('link', { name: /settings/i });
    this.statsCards = page.locator('.glass-card.card-hover');
    this.tabsList = page.getByRole('tablist');
  }

  async goto(locale: string = 'en') {
    await this.page.goto(`/${locale}/profile`);
  }

  async verifyProfileVisible() {
    // Wait for the skeleton to disappear or the username to appear with a longer timeout
    await expect(this.userName).toBeVisible({ timeout: 15000 });
    await expect(this.avatar).toBeVisible();
  }

  async switchTab(tabName: 'progress' | 'activity' | 'achievements') {
    await this.page
      .getByRole('tab', { name: new RegExp(tabName, 'i') })
      .click();
  }
}

import { test, expect } from '@playwright/test';
import { ChallengesPage } from '../pages/ChallengesPage';
import fs from 'fs';
import path from 'path';

const solutionsPath = path.resolve(
  process.cwd(),
  'e2e/fixtures/solutions.json',
);
const solutions = JSON.parse(fs.readFileSync(solutionsPath, 'utf-8')) as Record<
  string,
  string
>;
// import { ensureLoggedIn } from '../utils/auth';

test.describe('Challenges', () => {
  let challengesPage: ChallengesPage;

  test.beforeAll(async () => {
    // Ensure solutions exist
    expect(Object.keys(solutions).length).toBeGreaterThan(0);
  });

  test.beforeEach(async ({ page, context, request }) => {
    const { loginViaApi } = await import('../utils/auth');
    await loginViaApi(context, request, page);

    challengesPage = new ChallengesPage(page);
  });

  for (const [slug, solution] of Object.entries(solutions)) {
    test(`should solve challenge: ${slug}`, async () => {
      test.slow(); // Give it more time
      await challengesPage.gotoChallenge(slug);
      await challengesPage.solveChallenge(solution, slug);
    });
  }
});

import { test, expect } from '@playwright/test';
import { ChallengesPage } from '../pages/ChallengesPage';
import { TutorialsPage } from '../pages/TutorialsPage';
import fs from 'fs';
import path from 'path';

const solutionsPath = path.resolve(
    process.cwd(),
    'e2e/fixtures/solutions.json',
);
const solutions = JSON.parse(fs.readFileSync(solutionsPath, 'utf-8')) as Record<
    string,
    string
>;

test.describe('Hide/Show Completed', () => {
    let challengesPage: ChallengesPage;
    let tutorialsPage: TutorialsPage;

    test.beforeEach(async ({ page, context, request }) => {
        const { loginViaApi } = await import('../utils/auth');
        await loginViaApi(context, request, page);

        challengesPage = new ChallengesPage(page);
        tutorialsPage = new TutorialsPage(page);
    });

    test('should hide completed challenges', async ({ page }) => {
        // 1. Solve a simple challenge (e.g. css-id) if not already solved
        // We pick one that is quick and stable
        const slug = 'css-id';
        const solution = solutions[slug];

        await challengesPage.gotoChallenge(slug);
        await challengesPage.solveChallenge(solution, slug);

        // 2. Go back to list
        await challengesPage.gotoList();

        // 3. Verify it is marked data-completed="true" or has check circle
        // The implementation adds CheckCircle2 which we can check, or class on the row/card
        // Let's check for the check circle icon inside a link pointing to this slug
        const challengeLink = page.locator(`a[href*="/challenges/${slug}"]`);
        const checkIcon = challengeLink.locator('.lucide-check-circle-2');

        // It should be visible initially (show completed by default or just in list)
        // Wait for list to load
        await expect(challengeLink.first()).toBeVisible();

        // 4. Toggle Hide Completed
        await challengesPage.hideCompletedToggle.click();

        // 5. Verify it is hidden
        await expect(challengeLink.first()).toBeHidden();

        // 6. Toggle back to show (optional, but good for symmetry)
        await challengesPage.hideCompletedToggle.click();
        await expect(challengeLink.first()).toBeVisible();
    });

    test('should hide completed tutorials', async ({ page }) => {
        // 1. Complete a tutorial
        await tutorialsPage.gotoList();
        const firstTutorial = tutorialsPage.tutorialCards.first();
        const firstTutorialHref = await firstTutorial.getAttribute('href');
        const slug = firstTutorialHref?.split('/').pop();

        expect(slug).toBeDefined();

        await firstTutorial.click();
        await tutorialsPage.verifyTutorialContent();

        // Force scroll and complete like in tutorials.spec.ts
        await page.evaluate(() => {
            document.body.style.minHeight = '10000px';
        });
        for (let i = 0; i < 5; i++) {
            await page.mouse.wheel(0, 2000);
            await page.waitForTimeout(200);
        }
        await page.evaluate(() => window.scrollTo(0, document.body.scrollHeight));
        await page.waitForTimeout(1000);

        await expect(tutorialsPage.completeButton).toBeVisible({ timeout: 10000 });
        await tutorialsPage.completeTutorial();

        // 2. Go back to list
        await tutorialsPage.gotoList();

        // 3. Verify it is visible
        const tutorialLink = page.locator(`a[href*="/tutorials/${slug}"]`);
        await expect(tutorialLink.first()).toBeVisible();

        // 4. Toggle Hide Completed
        await tutorialsPage.hideCompletedToggle.click();

        // 5. Verify it is hidden
        await expect(tutorialLink.first()).toBeHidden();

        // 6. Toggle back
        await tutorialsPage.hideCompletedToggle.click();
        await expect(tutorialLink.first()).toBeVisible();
    });
});

import { test, expect } from '@playwright/test';
import { DashboardPage } from '../pages/DashboardPage';
import { TutorialsPage } from '../pages/TutorialsPage';
import { ChallengesPage } from '../pages/ChallengesPage';
import { ProfilePage } from '../pages/ProfilePage';
import { loginViaApi } from '../utils/auth';

test.describe('Indonesian (ID) Locale Scenarios', () => {
  let dashboardPage: DashboardPage;
  let tutorialsPage: TutorialsPage;
  let challengesPage: ChallengesPage;
  let profilePage: ProfilePage;

  test.beforeEach(async ({ page, context, request }) => {
    await loginViaApi(context, request, page);
    dashboardPage = new DashboardPage(page);
    tutorialsPage = new TutorialsPage(page);
    challengesPage = new ChallengesPage(page);
    profilePage = new ProfilePage(page);
  });

  test('ID Dashboard: should display Indonesian content', async ({ page }) => {
    await dashboardPage.goto('id');
    // Hero title in ID: "Kuasai Pengujian Perangkat Lunak"
    await expect(dashboardPage.heroTitle).toContainText(/Kuasai Pengujian/i);

    // Stats in ID usually remain 'Challenges' etc if not localized in stats section yet,
    // but we verify the page loaded.
    await expect(page).toHaveURL(/.*\/id\/.*/);
  });

  test('ID Tutorials: should list tutorials in ID', async ({ page }) => {
    await tutorialsPage.gotoList('id');
    await expect(tutorialsPage.tutorialCards.first()).toBeVisible();
    // Check for "Mulai Belajar" or similar ID-specific text if applicable
  });

  test('ID Challenges: should list challenges in ID', async ({ page }) => {
    await challengesPage.gotoList('id');
    await expect(page.locator('h1')).toContainText(/Tantangan/i);
  });

  test('ID Profile: should display profile in ID context', async ({ page }) => {
    await profilePage.goto('id');
    await profilePage.verifyProfileVisible();
    // Tabs in ID: "Progress", "Aktivitas", "Pencapaian"
    await expect(page.getByRole('tab', { name: /Pencapaian/i })).toBeVisible();
  });
});

