import { test, expect } from '@playwright/test';
import { TutorialsPage } from '../pages/TutorialsPage';

test.describe('Tutorials', () => {
  let tutorialsPage: TutorialsPage;
  test.beforeEach(async ({ page, context, request }) => {
    const { loginViaApi } = await import('../utils/auth');
    await loginViaApi(context, request, page);

    tutorialsPage = new TutorialsPage(page);
    await tutorialsPage.gotoList();
  });

  test('should list tutorials', async ({ page }) => {
    await expect(tutorialsPage.tutorialCards.first()).toBeVisible();
  });

  test('should navigate to tutorial detail', async ({ page }) => {
    const firstTutorial = tutorialsPage.tutorialCards.first();
    await firstTutorial.click();
    await page.waitForLoadState('domcontentloaded');
    await tutorialsPage.verifyTutorialContent();
  });

  test('should mark tutorial as complete', async ({ page }) => {
    const firstTutorial = tutorialsPage.tutorialCards.first();
    await firstTutorial.click();
    await tutorialsPage.verifyTutorialContent();

    // 1. Force a huge body height to ensure we can scroll a lot
    await page.evaluate(() => {
      document.body.style.minHeight = '10000px';
    });

    // 2. Perform multiple scrolls to ensure progress hits 100%
    // We use a loop for robustness in headless mode
    for (let i = 0; i < 10; i++) {
      await page.mouse.wheel(0, 2000);
      await page.waitForTimeout(200);
    }

    // 3. Scroll to the bottom where the button usually lives
    await page.evaluate(() => window.scrollTo(0, document.body.scrollHeight));
    await page.waitForTimeout(1000);

    // 4. Verify and Click Complete
    await expect(tutorialsPage.completeButton).toBeVisible({ timeout: 10000 });
    await tutorialsPage.completeTutorial();
  });
});

import http from 'k6/http';
import { check, sleep, group } from 'k6';
import { Rate, Trend } from 'k6/metrics';

// Custom metrics
const errorRate = new Rate('errors');
const tutorialResponseTime = new Trend('tutorial_response_time');
const challengeResponseTime = new Trend('challenge_response_time');

// Test configuration
export const options = {
    stages: [
        { duration: '30s', target: 25 },   // Ramp-up to 25 users
        { duration: '1m', target: 25 },    // Stay at 25 (baseline)
        { duration: '2m', target: 50 },    // Ramp to 50 (load)
        { duration: '1m', target: 75 },    // Peak at 75
        { duration: '30s', target: 0 },    // Cool-down
    ],
    thresholds: {
        http_req_duration: ['p(95)<500'],  // 95% of requests < 500ms
        errors: ['rate<0.01'],              // Error rate < 1%
    },
};

const BASE_URL = __ENV.BASE_URL || 'https://qa.testingwithekki.com';
const TEST_USER_EMAIL = __ENV.TEST_EMAIL || 'ekkisyam2310@gmail.com';
const TEST_USER_PASSWORD = __ENV.TEST_PASSWORD || 'PhJ5C9hgwWSKRrP';

// Sample tutorial and challenge slugs (real ones from the project)
const TUTORIAL_SLUGS = [
    'html-element-anatomy',
    'dom-tree-hierarchy',
    'devtools-mastery',
    'css-selector-strategies',
];

const CHALLENGE_SLUGS = [
    'css-selector-101-id-class',
    'css-tag-selectors',
    'css-combining-basics',
];

export default function () {
    // Randomly choose between scenarios
    if (Math.random() < 0.6) {
        tutorialFlow();
    } else {
        challengeFlow();
    }
}

// Scenario 1: Public Tutorial Flow (60% of traffic)
function tutorialFlow() {
    group('Tutorial Flow', () => {
        // Step 1: Homepage
        let homeRes = http.get(`${BASE_URL}/en`);
        check(homeRes, {
            'homepage status 200': (r) => r.status === 200,
        });
        errorRate.add(homeRes.status !== 200);
        sleep(1);

        // Step 2: Tutorial List
        let tutorialListRes = http.get(`${BASE_URL}/en/tutorials`);
        check(tutorialListRes, {
            'tutorial list status 200': (r) => r.status === 200,
        });
        errorRate.add(tutorialListRes.status !== 200);
        tutorialResponseTime.add(tutorialListRes.timings.duration);
        sleep(1);

        // Step 3: View a random tutorial
        const randomSlug = TUTORIAL_SLUGS[Math.floor(Math.random() * TUTORIAL_SLUGS.length)];
        let tutorialRes = http.get(`${BASE_URL}/en/tutorials/${randomSlug}`);
        check(tutorialRes, {
            'tutorial page loads': (r) => r.status === 200 || r.status === 404,
        });
        tutorialResponseTime.add(tutorialRes.timings.duration);
        sleep(2);
    });
}

// Scenario 2: Challenge Flow (40% of traffic - authenticated)
function challengeFlow() {
    group('Challenge Flow', () => {
        // Step 1: Homepage
        let homeRes = http.get(`${BASE_URL}/en`);
        check(homeRes, {
            'homepage status 200': (r) => r.status === 200,
        });
        errorRate.add(homeRes.status !== 200);
        sleep(1);

        // Step 2: Login (get session cookie)
        // Note: Adjust this based on your actual auth endpoint
        let loginRes = http.post(
            `${BASE_URL}/api/auth/sign-in/email`,
            JSON.stringify({
                email: TEST_USER_EMAIL,
                password: TEST_USER_PASSWORD,
            }),
            {
                headers: { 'Content-Type': 'application/json' },
            }
        );

        // Check login success (adjust based on your auth response)
        const loginSuccess = loginRes.status === 200 || loginRes.status === 302;
        check(loginRes, {
            'login successful': () => loginSuccess,
        });

        if (!loginSuccess) {
            errorRate.add(1);
            return; // Skip rest if login failed
        }
        sleep(1);

        // Step 3: Challenge List
        let challengeListRes = http.get(`${BASE_URL}/en/challenges`);
        check(challengeListRes, {
            'challenge list status 200': (r) => r.status === 200,
        });
        challengeResponseTime.add(challengeListRes.timings.duration);
        sleep(1);

        // Step 4: View a random challenge
        const randomSlug = CHALLENGE_SLUGS[Math.floor(Math.random() * CHALLENGE_SLUGS.length)];
        let challengeRes = http.get(`${BASE_URL}/en/challenges/${randomSlug}`);
        check(challengeRes, {
            'challenge page loads': (r) => r.status === 200 || r.status === 404,
        });
        challengeResponseTime.add(challengeRes.timings.duration);
        sleep(2);
    });
}

// Setup function - runs once before the test
export function setup() {
    console.log(`Starting load test against ${BASE_URL}`);
    console.log(`Test user: ${TEST_USER_EMAIL}`);

    // Verify the target is reachable
    let res = http.get(`${BASE_URL}/en`);
    if (res.status !== 200) {
        throw new Error(`Target unreachable: ${BASE_URL} returned ${res.status}`);
    }

    return { startTime: new Date().toISOString() };
}

// Teardown function - runs once after the test
export function teardown(data) {
    console.log(`Test completed. Started at: ${data.startTime}`);
}

// @ts-expect-error - dist import is untyped
import server from '../dist/server/server.js';

const PORT = process.env.PORT || 3000;

import * as Sentry from "@sentry/bun";
import { getSentryConfig } from "../src/lib/sentry.config";

Sentry.init(getSentryConfig());

const env = process.env.NODE_ENV || 'development';
console.log(`🚀 ${env.charAt(0).toUpperCase() + env.slice(1)} server starting on port ${PORT}...`);

Bun.serve({
    port: PORT,
    async fetch(req) {
        const url = new URL(req.url);
        const path = url.pathname;

        // Security: basic directory traversal protection
        if (path.includes('..')) {
            return new Response('Not Found', { status: 404 });
        }

        // Static assets from dist/client
        // We only serve files if they aren't the root path (SSR handles /)
        // and if they actually exist in the client dist folder.
        if (path !== '/') {
            const filePath = `./dist/client${path}`;
            const file = Bun.file(filePath);
            if (await file.exists()) {
                const response = new Response(file);

                // Cache Control
                if (path.startsWith('/assets/')) {
                    // Immutable assets (hashed by Vite) - 1 year
                    response.headers.set('Cache-Control', 'public, max-age=31536000, immutable');
                } else {
                    // Other static files (favicon, robots.txt, etc) - 1 hour
                    response.headers.set('Cache-Control', 'public, max-age=3600');
                }

                return response;
            }
        }

        // SSR fallback to TanStack Start handler
        try {
            return await (server as any).fetch(req);
        } catch (error) {
            Sentry.captureException(error);
            console.error('SSR Error:', error);
            return new Response('Internal Server Error', { status: 500 });
        }
    },
});

import { useEffect, useRef, useCallback, useState } from 'react';
import { loader, type OnMount, type Monaco } from '@monaco-editor/react';
import type { editor, IDisposable } from 'monaco-editor';
import { storage } from '@/lib/storage-adapter';
import { CUSTOM_DARK_THEME, CUSTOM_LIGHT_THEME } from './themes';
import type { CodeEditorProps } from './types';

let monacoConfigured = false;

export function useMonacoSetup(
    props: CodeEditorProps,
    monacoTheme: string
) {
    const { onRun, storageKey, onReady, extraLibs } = props;
    const editorRef = useRef<editor.IStandaloneCodeEditor | null>(null);
    const monacoRef = useRef<Monaco | null>(null);
    const [isMounted, setIsMounted] = useState(false);

    // Configure Monaco loader on client side
    useEffect(() => {
        if (!monacoConfigured && typeof window !== 'undefined') {
            void import('monaco-editor').then((monaco) => {
                loader.config({ monaco });
                monacoConfigured = true;
            });
        }
    }, []);


    // Update theme dynamically
    useEffect(() => {
        if (monacoRef.current) {
            monacoRef.current.editor.setTheme(monacoTheme);
        }
    }, [monacoTheme]);

    // Handle editor mount and configuration
    const handleEditorMount: OnMount = useCallback(
        (editor, monaco) => {
            editorRef.current = editor;
            monacoRef.current = monaco;

            // Compiler Options
            monaco.languages.typescript.typescriptDefaults.setCompilerOptions({
                target: monaco.languages.typescript.ScriptTarget.ESNext,
                module: monaco.languages.typescript.ModuleKind.ESNext,
                allowNonTsExtensions: true,
                moduleResolution: monaco.languages.typescript.ModuleResolutionKind.NodeJs,
            });

            // Diagnostics
            const diagOptions = {
                noSemanticValidation: true,
                noSyntaxValidation: false,
            };
            monaco.languages.typescript.typescriptDefaults.setDiagnosticsOptions(diagOptions);
            monaco.languages.typescript.javascriptDefaults.setDiagnosticsOptions(diagOptions);

            // Register Themes
            monaco.editor.defineTheme('customDark', CUSTOM_DARK_THEME);
            monaco.editor.defineTheme('customLight', CUSTOM_LIGHT_THEME);
            monaco.editor.setTheme(monacoTheme);

            // Shortcuts: Run Code
            editor.addAction({
                id: 'run-code',
                label: 'Run Code',
                keybindings: [monaco.KeyMod.CtrlCmd | monaco.KeyCode.Enter],
                run: () => onRun?.(editor.getValue()),
            });

            // Shortcuts: Save Code
            editor.addAction({
                id: 'save-code',
                label: 'Save Code',
                keybindings: [monaco.KeyMod.CtrlCmd | monaco.KeyCode.KeyS],
                run: () => {
                    if (storageKey) {
                        void storage.setItem(storageKey, editor.getValue());
                    }
                },
            });

            setIsMounted(true);
            editor.focus();
            onReady?.();
        },
        [onRun, storageKey, onReady, monacoTheme]
    );

    // Re-register 'Run Code' action when onRun changes
    useEffect(() => {
        if (editorRef.current && monacoRef.current) {
            editorRef.current.addAction({
                id: 'run-code',
                label: 'Run Code',
                keybindings: [monacoRef.current.KeyMod.CtrlCmd | monacoRef.current.KeyCode.Enter],
                run: (editor) => onRun?.(editor.getValue()),
            });
        }
    }, [onRun]);

    // Handle extraLibs with cleanup
    useEffect(() => {
        if (!isMounted || !monacoRef.current || !extraLibs) return;

        const monaco = monacoRef.current;
        const disposables: IDisposable[] = [];

        extraLibs.forEach((lib) => {
            disposables.push(monaco.languages.typescript.javascriptDefaults.addExtraLib(lib.content, lib.filePath));
            disposables.push(monaco.languages.typescript.typescriptDefaults.addExtraLib(lib.content, lib.filePath));
        });

        return () => {
            disposables.forEach(d => d.dispose());
        };
    }, [isMounted, extraLibs]);

    return {
        editorRef,
        monacoRef,
        handleEditorMount,
    };
}

import React, { useState, useMemo } from 'react';
import {
    File,
    Folder,
    FolderOpen,
    Lock,
    Edit3,
    ChevronRight,
    ChevronDown,
    FileCode,
    Globe
} from 'lucide-react';
import { cn } from '@/lib/utils';

interface FileExplorerProps {
    files: Record<string, string>;
    editableFiles?: string[];
    selectedFile: string;
    onSelectFile: (path: string) => void;
    className?: string;
}

interface FileNode {
    name: string;
    path: string;
    type: 'file' | 'folder';
    children?: Record<string, FileNode>;
}

export function FileExplorer({
    files,
    editableFiles = [],
    selectedFile,
    onSelectFile,
    className,
}: FileExplorerProps) {
    // State for expanded folders
    const [expandedFolders, setExpandedFolders] = useState<Record<string, boolean>>({
        '': true, // Root always expanded
    });

    // Convert flat files Record to a hierarchical tree
    const fileTree = useMemo(() => {
        const root: FileNode = { name: '', path: '', type: 'folder', children: {} };

        Object.keys(files).forEach((path) => {
            const parts = path.split('/').filter(Boolean);
            let current = root;

            parts.forEach((part, index) => {
                if (!current.children) current.children = {};

                if (!current.children[part]) {
                    const isLast = index === parts.length - 1;
                    const currentPath = '/' + parts.slice(0, index + 1).join('/');

                    current.children[part] = {
                        name: part,
                        path: currentPath,
                        type: isLast ? 'file' : 'folder',
                        children: isLast ? undefined : {},
                    };
                }
                current = current.children[part];
            });
        });

        return root;
    }, [files]);

    const toggleFolder = (path: string, e: React.MouseEvent) => {
        e.stopPropagation();
        setExpandedFolders((prev) => ({
            ...prev,
            [path]: !prev[path],
        }));
    };

    const getFileIcon = (fileName: string) => {
        if (fileName.endsWith('.html')) return <Globe className="h-4 w-4 text-blue-400" />;
        if (fileName.endsWith('.ts') || fileName.endsWith('.js')) return <FileCode className="h-4 w-4 text-brand-teal-dark" />;
        return <File className="h-4 w-4 text-slate-400" />;
    };

    const renderNode = (node: FileNode, depth: number = 0) => {
        const isExpanded = expandedFolders[node.path];
        const isSelected = selectedFile === node.path;
        const isEditable = editableFiles.includes(node.path);
        const hasChildren = node.type === 'folder' && node.children && Object.keys(node.children).length > 0;

        if (node.path === '') {
            // Don't render root itself, only children
            return (
                <div className="space-y-0.5">
                    {node.children && Object.values(node.children)
                        .sort((a, b) => {
                            // Folders first, then files
                            if (a.type !== b.type) return a.type === 'folder' ? -1 : 1;
                            return a.name.localeCompare(b.name);
                        })
                        .map((child) => renderNode(child, depth))}
                </div>
            );
        }

        return (
            <div key={node.path}>
                <div
                    className={cn(
                        'group flex items-center py-1.5 px-2 cursor-pointer rounded-md transition-colors',
                        isSelected
                            ? 'bg-brand-teal/20 text-brand-teal-dark'
                            : 'hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400'
                    )}
                    style={{ paddingLeft: `${depth * 12 + 8}px` }}
                    onClick={() => node.type === 'file' && onSelectFile(node.path)}
                >
                    {node.type === 'folder' ? (
                        <div
                            className="mr-1.5 flex items-center"
                            onClick={(e) => toggleFolder(node.path, e)}
                        >
                            {isExpanded ? (
                                <ChevronDown className="h-3.5 w-3.5" />
                            ) : (
                                <ChevronRight className="h-3.5 w-3.5" />
                            )}
                        </div>
                    ) : (
                        <div className="w-5" /> // Spacer for file icons to align with folder icons
                    )}

                    <div className="mr-2 shrink-0">
                        {node.type === 'folder' ? (
                            isExpanded ? (
                                <FolderOpen className="h-4 w-4 text-amber-400 fill-amber-400/20" />
                            ) : (
                                <Folder className="h-4 w-4 text-amber-400 fill-amber-400/20" />
                            )
                        ) : (
                            getFileIcon(node.name)
                        )}
                    </div>

                    <span
                        className={cn(
                            "text-xs font-medium truncate flex-1 min-w-0",
                            isSelected ? "font-bold" : ""
                        )}
                        title={node.name}
                    >
                        {node.name}
                    </span>

                    {node.type === 'file' && (
                        <div className="ml-auto pl-2 flex items-center gap-1 opacity-60 group-hover:opacity-100">
                            {isEditable ? (
                                <Edit3 className="h-3 w-3 text-brand-teal" />
                            ) : (
                                <Lock className="h-3 w-3 text-slate-400" />
                            )}
                        </div>
                    )}
                </div>

                {node.type === 'folder' && isExpanded && node.children && (
                    <div className="mt-0.5">
                        {Object.values(node.children)
                            .sort((a, b) => {
                                if (a.type !== b.type) return a.type === 'folder' ? -1 : 1;
                                return a.name.localeCompare(b.name);
                            })
                            .map((child) => renderNode(child, depth + 1))}
                    </div>
                )}
            </div>
        );
    };

    return (
        <div className={cn("flex flex-col h-full bg-slate-50 dark:bg-slate-900 border-r border-slate-200 dark:border-slate-800", className)}>
            <div className="p-3 border-b border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-950">
                <h3 className="text-[10px] font-bold uppercase tracking-wider text-slate-400">
                    Explorer
                </h3>
            </div>
            <div className="flex-1 overflow-y-auto p-2 scrollbar-thin">
                {renderNode(fileTree)}
            </div>
        </div>
    );
}

export default FileExplorer;

import React, { useMemo } from 'react';
import { X, Lock, Edit3 } from 'lucide-react';
import { cn } from '@/lib/utils';
import { CodeEditor } from './code-editor';

interface MultiTabEditorProps {
    files: Record<string, string>;
    editableFiles?: string[];
    selectedFile: string;
    openFiles: string[];
    onSelectFile: (path: string) => void;
    onCloseFile: (path: string) => void;
    onCodeChange: (path: string, code: string) => void;
    onRun?: () => void;
    onReady?: () => void;
    storageKeyPrefix?: string;
    className?: string;
    height?: string | number;
    extraLibs?: { content: string; filePath?: string }[];
}

export function MultiTabEditor({
    files,
    editableFiles = [],
    selectedFile,
    openFiles,
    onSelectFile,
    onCloseFile,
    onCodeChange,
    onRun,
    onReady,
    storageKeyPrefix,
    className,
    height = '100%',
    extraLibs,
}: MultiTabEditorProps) {

    const getLanguage = (path: string) => {
        if (path.endsWith('.html')) return 'html';
        if (path.endsWith('.css')) return 'css';
        if (path.endsWith('.ts')) return 'typescript';
        if (path.endsWith('.js')) return 'javascript';
        return 'javascript';
    };

    const isEditable = useMemo(() => {
        return editableFiles.includes(selectedFile);
    }, [selectedFile, editableFiles]);

    return (
        <div className={cn("flex flex-col h-full bg-white dark:bg-slate-950", className)}>
            {/* Tab Bar */}
            <div className="flex items-center h-10 bg-slate-100 dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 overflow-x-auto no-scrollbar">
                {openFiles.map((path) => {
                    const isSelected = selectedFile === path;
                    const isFileEditable = editableFiles.includes(path);
                    const fileName = path.split('/').pop() || path;

                    return (
                        <div
                            key={path}
                            className={cn(
                                "group flex items-center h-full px-3 border-r border-slate-200 dark:border-slate-800 cursor-pointer min-w-[120px] max-w-[200px] transition-colors relative",
                                isSelected
                                    ? "bg-white dark:bg-slate-950 border-b-2 border-b-brand-teal"
                                    : "bg-slate-100 dark:bg-slate-900 hover:bg-slate-50 dark:hover:bg-slate-800"
                            )}
                            onClick={() => onSelectFile(path)}
                        >
                            <div className="mr-2 opacity-50">
                                {isFileEditable ? (
                                    <Edit3 className="h-3 w-3 text-brand-teal" />
                                ) : (
                                    <Lock className="h-3 w-3" />
                                )}
                            </div>

                            <span className={cn(
                                "text-xs font-medium truncate",
                                isSelected ? "text-slate-900 dark:text-slate-100" : "text-slate-500"
                            )}>
                                {fileName}
                            </span>

                            {/* Only show close button if not the only editable file? Or just allow closing reference files */}
                            {!isFileEditable && (
                                <button
                                    className="ml-2 p-0.5 rounded-sm hover:bg-slate-200 dark:hover:bg-slate-700 opacity-0 group-hover:opacity-100 transition-opacity"
                                    onClick={(e) => {
                                        e.stopPropagation();
                                        onCloseFile(path);
                                    }}
                                >
                                    <X className="h-3 w-3" />
                                </button>
                            )}
                        </div>
                    );
                })}
            </div>

            {/* Editor Header */}
            <div className="flex items-center justify-between px-4 py-2 bg-white dark:bg-slate-950 border-b border-slate-200 dark:border-slate-800">
                <div className="flex items-center gap-2">
                    <span className="text-[10px] font-bold uppercase tracking-widest text-slate-400">
                        {getLanguage(selectedFile)}
                    </span>
                    {!isEditable && (
                        <div className="flex items-center gap-1.5 px-2 py-0.5 bg-slate-100 dark:bg-slate-900 rounded text-[10px] text-slate-500 font-medium">
                            <Lock className="h-2.5 w-2.5" />
                            READ ONLY
                        </div>
                    )}
                </div>
            </div>

            {/* Code Editor */}
            <div className="flex-1 relative overflow-hidden">
                <CodeEditor
                    key={selectedFile}
                    initialCode={files[selectedFile] || ''}
                    language={getLanguage(selectedFile)}
                    onChange={(code) => isEditable && onCodeChange(selectedFile, code)}
                    onRun={onRun}
                    onReady={onReady}
                    readOnly={!isEditable}
                    storageKey={
                        isEditable && storageKeyPrefix
                            ? `${storageKeyPrefix}-${selectedFile}`
                            : undefined
                    }
                    height="100%"
                    showMinimap={true}
                    className="h-full"
                    extraLibs={extraLibs}
                />
            </div>
        </div>
    );
}

