import { TestResult } from '../test-results';
import { LogEntry } from '../console-output';

export type ChallengeType =
    | 'JAVASCRIPT'
    | 'TYPESCRIPT'
    | 'PLAYWRIGHT'
    | 'CSS_SELECTOR'
    | 'XPATH_SELECTOR'
    | 'SELECTOR';

export interface Challenge {
    id: string;
    slug: string;
    title: string;
    description: string;
    type: ChallengeType;
    difficulty: 'Easy' | 'Medium' | 'Hard';
    xp: number;
    instructions: string;
    hints?: string[];
    starterCode: string;
    htmlContent?: string;
    targetSelector?: string | string[];
    files?: Record<string, string>; // VFS: multi-page content for E2E challenges
    editableFiles?: string[]; // Which files user can edit
    preloadModules?: Record<string, {
        exports: string[];
        source: string;
    }>;

    testCases?: {
        id: string;
        name: string;
        input?: unknown;
        expectedOutput?: unknown;
    }[];
    expectedState?: {
        selector: string;
        visible?: boolean;
        hidden?: boolean;
        containsText?: string;
        count?: number;
    }[];
    category?: string;
    tutorial?: {
        slug: string;
        title: string;
    };
    isCompleted?: boolean;
    nextChallenge?: {
        slug: string;
        title: string;
    };
    prevChallenge?: {
        slug: string;
        title: string;
    };
}

export interface ChallengePlaygroundProps {
    challenge: Challenge;
    onSubmit: (data: {
        code: string;
        passed: boolean;
        testResults: TestResult[];
        executionTime?: number;
    }) => void;
    userId?: string;
    className?: string;
    hintUsed?: boolean; // Whether user has already used hint for this challenge
    initialHintContent?: string | null;
}

export interface PlaygroundState {
    // State
    code: string;
    setCode: (code: string) => void;
    selector: string;
    setSelector: (selector: string) => void;
    selectorType: 'css' | 'xpath';
    setSelectorType: (type: 'css' | 'xpath') => void;
    fileContents: Record<string, string>;
    setFileContents: (contents: Record<string, string>) => void;
    selectedFile: string;
    setSelectedFile: (file: string) => void;
    openFiles: string[];
    setOpenFiles: (files: string[]) => void;
    resetCount: number;
    setResetCount: (count: (prev: number) => number) => void;
    isResetConfirmOpen: boolean;
    setIsResetConfirmOpen: (open: boolean) => void;
    isHintDialogOpen: boolean;
    setIsHintDialogOpen: (open: boolean) => void;
    hintContent: string | null;
    setHintContent: (content: string | null) => void;
    storedHint: string | null;
    setStoredHint: (content: string | null) => void;
    hintUsed: boolean;
    setHintUsed: (used: boolean) => void;
    isMobile: boolean;
    isLayoutReady: boolean;
    setIsLayoutReady: (ready: boolean) => void;
    testResults: TestResult[];
    setTestResults: (results: TestResult[]) => void;
    consoleLogs: LogEntry[];
    setConsoleLogs: (logs: LogEntry[]) => void;
    resultsTab: 'results' | 'console';
    setResultsTab: (tab: 'results' | 'console') => void;
    isRunning: boolean;
    setIsRunning: (running: boolean) => void;
    hasPassed: boolean;
    setHasPassed: (passed: boolean) => void;
    activeTab: string;
    setActiveTab: (tab: string) => void;
    previewValidation: { isValid: boolean; matchCount: number } | null;
    setPreviewValidation: (validation: { isValid: boolean; matchCount: number } | null) => void;
    currentVfsPath: string;
    setCurrentVfsPath: (path: string) => void;
    revealedHintsCount: number;
    setRevealedHintsCount: (count: number) => void;

    // Derived
    isCodeChallenge: boolean;
    isSelectorChallenge: boolean;
    extraLibs?: any; // Type from generateTypeDefinitions
    locale: string;
    t: any; // i18n t function
}

import { useCallback } from 'react';
import { useMutation } from '@tanstack/react-query';
import { toast } from 'sonner';
import { executePlaywrightCode } from '@/core/executor';
import { generatePreloadCode } from '@/core/executor/module-preloader';
import { storage } from '@/lib/storage-adapter';
import { defaultSelectorStyles, e2eSelectorStyles } from './constants';
import { INJECTED_SCRIPTS, HIGHLIGHT_STYLES } from '../preview/constants';
import type {
    ChallengePlaygroundProps,
    PlaygroundState
} from './types';
import type { TestResult } from '../test-results';
import type { SelectorType } from '../selector-input';

export function useChallengeExecution(
    state: PlaygroundState,
    props: ChallengePlaygroundProps,
    previewIframeRef: React.RefObject<HTMLIFrameElement | null>
) {
    const { challenge, onSubmit, userId } = props;
    const {
        code,
        selector,
        fileContents,
        testResults,
        setTestResults,
        setConsoleLogs,
        setIsRunning,
        setHasPassed,
        setActiveTab,
        setCurrentVfsPath,
        previewValidation,
        setPreviewValidation,
        setCode,
        setSelector,
        setSelectorType,
        setResetCount,
        setIsResetConfirmOpen,
        setHintContent,
        setIsHintDialogOpen,
        setHintUsed,
        t,
        locale,
        hasPassed,
        isCodeChallenge,
        isSelectorChallenge
    } = state;

    // Run code for Playwright/JS challenges
    const handleRunCode = useCallback(async () => {
        const needsHtmlRun =
            (challenge.htmlContent || challenge.files) && challenge.type !== 'JAVASCRIPT';

        if (!isCodeChallenge) return;

        // Initial path is set by usePlaygroundState. We don't reset it here
        // to avoid blank previews for challenges starting on /app/ or other paths.

        if (needsHtmlRun) {
            setActiveTab('preview');
        }

        setIsRunning(true);
        setTestResults([]);
        setConsoleLogs([]);

        await new Promise((resolve) => setTimeout(resolve, 100));

        try {
            let codeToRun = code;
            if (
                challenge.type === 'JAVASCRIPT' ||
                challenge.type === 'TYPESCRIPT'
            ) {
                codeToRun += '\nif (typeof result !== "undefined") return result;';
            }

            const initialHtml = challenge.files
                ? challenge.files['/index.html'] || '<div></div>'
                : challenge.htmlContent || '<div></div>';

            let preloadCode = '';
            if (challenge.preloadModules) {

                preloadCode = generatePreloadCode({
                    modules: challenge.preloadModules,
                    files: challenge.files || {}
                });
            }

            const result = await executePlaywrightCode(
                preloadCode + '\n' + codeToRun,
                initialHtml,
                {
                    timeout: 10000,
                    existingIframe: previewIframeRef.current || undefined,
                    strictMode: challenge.type === 'PLAYWRIGHT',
                    cssContent: (challenge.category?.startsWith('e2e')) ? e2eSelectorStyles : defaultSelectorStyles,
                    files: challenge.files,
                    onNavigate: (path) => setCurrentVfsPath(path),
                    expectedState: challenge.expectedState,
                    isTypeScript: challenge.type === 'TYPESCRIPT' || challenge.type === 'PLAYWRIGHT',
                },
            );

            let validationPassed = result.status === 'PASSED';
            let outputMessage = result.output;

            const hasExpectedState = (challenge.expectedState?.length ?? 0) > 0;
            // All Playwright challenges that aren't checking specific DOM state side-effects
            // generally require assertions to happen in the test code to be considered valid.
            const isAssertionChallenge =
                challenge.type === 'PLAYWRIGHT' && !hasExpectedState;

            if (
                isAssertionChallenge &&
                !hasExpectedState &&
                result.status === 'PASSED'
            ) {
                const assertionCount = result.assertionCount ?? 0;
                if (assertionCount === 0) {
                    validationPassed = false;
                    outputMessage =
                        "No assertions were called. Write assertions like: await expect(locator).toHaveText('...');";
                    result.status = 'FAILED';
                } else {
                    // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-unsafe-call
                    outputMessage = t('challenges:playground.correct');
                }
            }
            else if (
                isCodeChallenge &&
                !isAssertionChallenge &&
                challenge.testCases?.length &&
                result.status === 'PASSED'
            ) {
                const expected = challenge.testCases[0].expectedOutput;
                const actual = result.returnValue;

                let expectedValue = expected;
                if (expected && typeof expected === 'object' && 'value' in expected) {
                    expectedValue = (expected as { value: unknown }).value;
                }

                if (
                    actual != expectedValue &&
                    String(actual) !== String(expectedValue)
                ) {
                    validationPassed = false;
                    // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment
                    outputMessage =
                        actual === undefined
                            ? `${t('challenges:playground.jsUndefined')} (Did you forget to assign your answer to 'result'?)`
                            : t('challenges:playground.jsMismatch');
                    result.status = 'FAILED';
                } else {
                    // eslint-disable-next-line @typescript-eslint/no-unsafe-call
                    outputMessage = `${t('challenges:playground.correct')} Result is ${String(actual)}`;
                }
            }

            const testResult: TestResult = {
                id: 'main',
                // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-unsafe-call
                name: t('challenges:playground.results'),
                passed: validationPassed,
                error: !validationPassed ? result.error || outputMessage : undefined,
                executionTime: result.executionTime,
            };

            setTestResults([testResult]);
            setHasPassed(validationPassed);

            if (result.logs) {
                setConsoleLogs(
                    result.logs.map((log) => ({
                        type: log.type as 'log' | 'warn' | 'error',
                        message: log.message,
                    })),
                );
            }
        } catch (error) {
            setTestResults([
                {
                    id: 'error',
                    // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-unsafe-call
                    name: t('challenges:playground.executionError'),
                    passed: false,
                    error:
                        error instanceof Error ? error.message : t('common:messages.error'),
                },
            ]);
            setHasPassed(false);
        } finally {
            setIsRunning(false);

            // Re-inject inspector scripts after execution
            // This is necessary because executePlaywrightCode overwrites the iframe content
            const iframe = previewIframeRef.current;
            if (iframe?.contentDocument) {
                const doc = iframe.contentDocument;

                // Re-inject styles if not present
                if (!doc.querySelector('style[data-twe-inspector]')) {
                    const style = doc.createElement('style');
                    style.setAttribute('data-twe-inspector', 'true');
                    style.textContent = HIGHLIGHT_STYLES;
                    doc.head?.appendChild(style);
                }

                // Re-inject scripts
                if (!doc.querySelector('script[data-twe-inspector]')) {
                    const script = doc.createElement('script');
                    script.setAttribute('data-twe-inspector', 'true');
                    script.textContent = INJECTED_SCRIPTS;
                    doc.body?.appendChild(script);
                }
            }
        }
    }, [
        code,
        challenge,
        isCodeChallenge,
        previewIframeRef,
        setCurrentVfsPath,
        setActiveTab,
        setIsRunning,
        setTestResults,
        setConsoleLogs,
        setHasPassed,
        t
    ]);

    // AI Hint mutation
    const hintMutation = useMutation({
        mutationFn: async () => {
            const { getAIHint } = await import('@/server/ai.fn');

            let currentCode = isCodeChallenge ? code : selector;

            // For multi-file challenges (POM), bundle all files into the user attempt
            if (isCodeChallenge && challenge.files && fileContents) {
                currentCode = Object.entries(fileContents)
                    .map(([path, content]) => `// File: ${path}\n${content}`)
                    .join('\n\n');
            }

            return getAIHint({
                data: {
                    challengeSlug: challenge.slug,
                    userAttempt: currentCode || undefined,
                    locale,
                    staticHints: challenge.hints?.slice(0, state.revealedHintsCount),
                },
            });
        },
        onSuccess: (result) => {
            setIsHintDialogOpen(false);

            if (result.success && result.hint) {
                setHintContent(result.hint);
                state.setStoredHint(result.hint);
                setHintUsed(true);
            } else if (!result.success && result.error) {
                // eslint-disable-next-line @typescript-eslint/no-unsafe-call
                toast.error(t('challenges:hints.errorTitle', 'Hint Generation Failed'), {
                    description: result.error,
                });
            }
        },
        onError: (error) => {
            console.error('[AI Hint] Error:', error);
            setIsHintDialogOpen(false);
            // eslint-disable-next-line @typescript-eslint/no-unsafe-call
            toast.error(t('challenges:hints.errorTitle', 'Error'), {
                // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-unsafe-call
                description: t('challenges:hints.errorGeneric', 'Something went wrong. Please try again.'),
            });
        },
    });

    const handlePreviewValidation = useCallback(
        (result: { isValid: boolean; matchCount: number }) => {
            setPreviewValidation(result);
        },
        [setPreviewValidation],
    );

    const handleValidateSelector = useCallback(() => {
        if (!isSelectorChallenge || !challenge.targetSelector) return;

        let isValid = false;
        if (previewValidation) {
            isValid = previewValidation.isValid;
        } else {
            const targetSelectors = Array.isArray(challenge.targetSelector)
                ? challenge.targetSelector
                : [challenge.targetSelector];
            isValid = targetSelectors.includes(selector);
        }

        setHasPassed(isValid);

        if (isValid) {
            setTestResults([
                {
                    id: 'selector',
                    name: 'Selector Validation',
                    passed: true,
                },
            ]);
        } else {
            setTestResults([
                {
                    id: 'selector',
                    name: 'Selector Validation',
                    passed: false,
                    // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-unsafe-call
                    error: t('challenges:playground.selectorMismatch'),
                },
            ]);
        }
    }, [
        selector,
        challenge.targetSelector,
        isSelectorChallenge,
        previewValidation,
        setHasPassed,
        setTestResults,
        t
    ]);

    const handleReset = useCallback(() => {
        setIsResetConfirmOpen(true);
    }, [setIsResetConfirmOpen]);

    const confirmReset = useCallback(async () => {
        const storageKey = userId
            ? `challenge-${challenge.id}-${userId}`
            : `challenge-${challenge.id}`;

        await storage.removeItem(storageKey);

        setCode(challenge.starterCode);
        setSelector('');
        setTestResults([]);
        setHasPassed(false);
        setPreviewValidation(null);
        setResetCount((prev) => prev + 1);
        setIsResetConfirmOpen(false);
    }, [challenge, userId, setCode, setSelector, setTestResults, setHasPassed, setPreviewValidation, setResetCount, setIsResetConfirmOpen]);

    const handleSubmit = useCallback(() => {
        const submissionCode = isCodeChallenge
            ? (challenge.files ? JSON.stringify(fileContents) : code)
            : selector;
        const totalExecutionTime = testResults.reduce(
            (acc, r) => acc + (r.executionTime || 0),
            0,
        );

        onSubmit({
            code: submissionCode,
            passed: hasPassed,
            testResults,
            executionTime: totalExecutionTime,
        });
    }, [code, selector, hasPassed, onSubmit, isCodeChallenge, testResults, challenge.files, fileContents]);

    const handleSelectorChange = useCallback(
        (value: string, type: SelectorType) => {
            setSelector(value);
            setSelectorType(type);
        },
        [setSelector, setSelectorType],
    );

    const handleFileChange = useCallback((path: string, newCode: string) => {
        state.setFileContents({
            ...state.fileContents,
            [path]: newCode
        });

        const mainFile = challenge.editableFiles?.[0] || '/test.spec.ts';
        if (path === mainFile) {
            setCode(newCode);
        }
    }, [challenge.editableFiles, state.fileContents, state.setFileContents, setCode]);

    const handleSelectFile = useCallback((path: string) => {
        state.setSelectedFile(path);
        if (!state.openFiles.includes(path)) {
            state.setOpenFiles([...state.openFiles, path]);
        }
    }, [state.openFiles, state.setOpenFiles, state.setSelectedFile]);

    const handleCloseFile = useCallback((path: string) => {
        const newOpenFiles = state.openFiles.filter(p => p !== path);
        state.setOpenFiles(newOpenFiles);
        if (state.selectedFile === path) {
            if (newOpenFiles.length > 0) {
                state.setSelectedFile(newOpenFiles[newOpenFiles.length - 1]);
            }
        }
    }, [state.openFiles, state.setOpenFiles, state.selectedFile, state.setSelectedFile]);

    return {
        handleRunCode,
        handleValidateSelector,
        handleReset,
        confirmReset,
        handleSubmit,
        handleSelectorChange,
        handleFileChange,
        handleSelectFile,
        handleCloseFile,
        handlePreviewValidation,
        hintMutation,
    };
}

import { useState, useEffect, useCallback } from 'react';
import { HIGHLIGHT_STYLES, INJECTED_SCRIPTS } from './constants';
import type {
    WebComponentPreviewProps,
    ViewMode,
    PreviewState,
    SelectorType
} from './types';

export function usePreviewState(
    props: WebComponentPreviewProps,
    iframeRef: React.RefObject<HTMLIFrameElement | null>
) {
    const {
        htmlContent,
        cssContent,
        targetElementId,
        targetSelector,
        userSelector,
        selectorType = 'css',
        onElementClick,
        onValidationChange,
        onNavigate,
        targetSelectorType = 'css',
    } = props;

    const [zoom, setZoom] = useState(100);
    const [hoveredElement, setHoveredElement] = useState<string | null>(null);
    const [isFullscreen, setIsFullscreen] = useState(false);
    const [viewMode, setViewMode] = useState<ViewMode>('preview');

    // Generate the full HTML document for the iframe
    const getFullIframeDocument = useCallback(() => {
        return `
      <!DOCTYPE html>
      <html>
      <head>
        <meta charset="UTF-8">
        <meta name="viewport" content="width=device-width, initial-scale=1.0">
        <style>
          * { box-sizing: border-box; }
          body {
            margin: 0;
            padding: 16px;
            font-family: 'Outfit', system-ui, -apple-system, sans-serif;
            background: #ffffff;
            color: #1f2937;
            min-height: 100vh;
          }
          ${HIGHLIGHT_STYLES}
          ${cssContent || ''}
        </style>
      </head>
      <body>
        ${htmlContent}
        <script>${INJECTED_SCRIPTS}</script>
        <script>
          // Initial highlight of target element
          setTimeout(() => {
            ${targetElementId
                ? `
                const target = document.getElementById('${targetElementId}');
                if (target) target.classList.add('twe-target-highlight');
              `
                : ''
            }
            ${targetSelector && !targetElementId
                ? `highlightElements('${targetSelector}', 'css', 'twe-target-highlight');`
                : ''
            }
          }, 100);
        </script>
      </body>
      </html>
    `;
    }, [htmlContent, cssContent, targetElementId, targetSelector]);

    // Effect: Update iframe content when HTML/CSS or viewMode changes
    useEffect(() => {
        const iframe = iframeRef.current;
        if (!iframe || viewMode !== 'preview') return;

        const doc = iframe.contentDocument || iframe.contentWindow?.document;
        if (doc) {
            doc.open();
            doc.write(getFullIframeDocument());
            doc.close();
        }
    }, [getFullIframeDocument, viewMode, iframeRef]);

    // Effect: Listen for messages from the iframe
    useEffect(() => {
        const handleMessage = (event: MessageEvent) => {
            const data = event.data;
            if (!data || typeof data !== 'object') return;

            switch (data.type) {
                case 'elementClick':
                    onElementClick?.(data.path);
                    break;
                case 'elementHover':
                    setHoveredElement(data.path);
                    break;
                case 'validationResult':
                    onValidationChange?.({
                        isValid: data.isValid,
                        matchCount: data.matchCount,
                    });
                    break;
                case 'vfsNavigate':
                    onNavigate?.(data.path);
                    break;
            }
        };

        window.addEventListener('message', handleMessage);
        return () => window.removeEventListener('message', handleMessage);
    }, [onElementClick, onValidationChange, onNavigate]);

    // Effect: Highlight user's selector matches
    useEffect(() => {
        const iframe = iframeRef.current;
        if (!iframe?.contentWindow || !userSelector || viewMode !== 'preview') return;

        iframe.contentWindow.postMessage(
            {
                type: 'highlight',
                selector: userSelector,
                selectorType,
                className: 'twe-user-match',
                targetSelector,
                targetSelectorType,
            },
            '*',
        );

        return () => {
            if (iframe?.contentWindow) {
                iframe.contentWindow.postMessage({ type: 'clearHighlights' }, '*');
            }
        };
    }, [userSelector, selectorType, viewMode, targetSelector, targetSelectorType, iframeRef]);

    const handleZoomIn = () => setZoom((prev) => Math.min(prev + 25, 200));
    const handleZoomOut = () => setZoom((prev) => Math.max(prev - 25, 50));

    return {
        zoom,
        setZoom,
        hoveredElement,
        viewMode,
        setViewMode,
        isFullscreen,
        setIsFullscreen,
        handleZoomIn,
        handleZoomOut,
    };
}

/**
 * TestResults - Component to display test case execution results
 *
 * Features:
 * - Show pass/fail status for each test
 * - Expandable error details
 * - Summary stats (passed/total)
 * - Animation for results
 */

import { useState } from 'react';
import { cn } from '@/lib/utils';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import {
  CheckCircle2,
  XCircle,
  ChevronDown,
  ChevronUp,
  Clock,
  AlertTriangle,
  Loader2,
} from 'lucide-react';
import type { ChallengeType } from './challenge-playground';

export interface TestResult {
  id: string;
  name: string;
  description?: string;
  passed: boolean;
  output?: unknown;
  expected?: unknown;
  error?: string;
  executionTime?: number;
  isHidden?: boolean;
}

// Copy configuration for different challenge types
const COPY_CONFIG: Record<
  ChallengeType | 'DEFAULT',
  { success: string; failure: string; testName: string }
> = {
  CSS_SELECTOR: {
    success: 'Target Acquired!',
    failure: 'Target Missed',
    testName: 'Element Selection',
  },
  XPATH_SELECTOR: {
    success: 'XPath Verified!',
    failure: 'XPath Missed',
    testName: 'Element Selection',
  },
  JAVASCRIPT: {
    success: 'Tests Passed!',
    failure: 'Logic Error',
    testName: 'Logical Verification',
  },
  PLAYWRIGHT: {
    success: 'Scenario Passed!',
    failure: 'Scenario Failed',
    testName: 'Workflow Execution',
  },
  SELECTOR: {
    success: 'Target Hit!',
    failure: 'Target Missed',
    testName: 'Selector Verification',
  },
  DEFAULT: {
    success: 'Mission Accomplished!',
    failure: 'Refinement Needed',
    testName: 'Test Case',
  },
};

export interface TestResultsProps {
  results: TestResult[];
  isRunning?: boolean;
  totalHiddenTests?: number;
  hiddenTestsPassed?: number;
  challengeType?: ChallengeType;
  className?: string;
}

export function TestResults({
  results,
  isRunning = false,
  totalHiddenTests = 0,
  hiddenTestsPassed = 0,
  challengeType,
  className,
}: TestResultsProps) {
  const [expandedTests, setExpandedTests] = useState<Set<string>>(new Set());

  // Get copy based on challenge type
  const copy = COPY_CONFIG[challengeType || 'DEFAULT'] || COPY_CONFIG.DEFAULT;
  const isSingleTest = results.length === 1 && totalHiddenTests === 0;

  // Calculate stats
  const visiblePassed = results.filter((r) => r.passed).length;
  const totalPassed = visiblePassed + hiddenTestsPassed;
  const totalTests = results.length + totalHiddenTests;
  const allPassed = totalPassed === totalTests && totalTests > 0;

  // Toggle test expansion
  const toggleExpand = (id: string) => {
    const newExpanded = new Set(expandedTests);
    if (newExpanded.has(id)) {
      newExpanded.delete(id);
    } else {
      newExpanded.add(id);
    }
    setExpandedTests(newExpanded);
  };

  // Expand/collapse all
  const expandAll = () => {
    const failedIds = results
      .filter((r) => !r.passed && r.error)
      .map((r) => r.id);
    setExpandedTests(new Set(failedIds));
  };

  const collapseAll = () => {
    setExpandedTests(new Set());
  };

  if (isRunning) {
    return (
      <div
        className={cn('p-4 rounded-lg border border-border bg-card', className)}
      >
        <div className="flex items-center gap-3 text-muted-foreground">
          <Loader2 className="h-5 w-5 animate-spin" />
          <span>Running tests...</span>
        </div>
      </div>
    );
  }

  if (results.length === 0) {
    return (
      <div
        className={cn(
          'p-8 rounded-xl border-2 border-black bg-muted/10 border-dashed text-center flex flex-col items-center justify-center h-full min-h-[160px] animate-fade-in',
          className,
        )}
      >
        <div className="bg-brand-teal/20 p-4 rounded-full mb-3 border border-black shadow-[2px_2px_0px_0px_rgba(0,0,0,1)]">
          <Clock className="h-6 w-6 text-black" />
        </div>
        <h3 className="text-base font-bold text-foreground mb-1">
          Ready to Validate
        </h3>
        <p className="text-sm text-muted-foreground max-w-[240px] font-medium">
          Run your solution to see test results and validation details here.
        </p>
      </div>
    );
  }

  return (
    <div
      className={cn(
        'rounded-xl border-2 border-black bg-white dark:bg-slate-950 overflow-hidden animate-fade-in hard-shadow-sm',
        className,
      )}
    >
      {/* Header with Summary */}
      <div
        className={cn(
          'px-4 py-4 border-b-2 border-black flex items-center justify-between',
          allPassed ? 'bg-green-500/10' : 'bg-destructive/10',
        )}
      >
        <div className="flex items-center gap-3">
          {allPassed ? (
            <CheckCircle2 className="h-6 w-6 text-green-600" />
          ) : (
            <XCircle className="h-6 w-6 text-destructive" />
          )}
          <div>
            <span
              className={cn(
                'font-bold text-base',
                allPassed ? 'text-green-600' : 'text-destructive',
              )}
            >
              {allPassed ? copy.success : copy.failure}
            </span>
            <span className="text-muted-foreground ml-2 font-bold font-mono">
              [{totalPassed}/{totalTests}]
            </span>
          </div>
        </div>

        <div className="flex items-center gap-2">
          {results.some((r) => !r.passed && r.error) && (
            <Button
              variant="ghost"
              size="sm"
              onClick={expandAll}
              className="h-8 text-xs font-bold border border-black/10 hover:border-black/20"
            >
              Expand Failed
            </Button>
          )}
          {expandedTests.size > 0 && (
            <Button
              variant="ghost"
              size="sm"
              onClick={collapseAll}
              className="h-8 text-xs font-bold border border-black/10 hover:border-black/20"
            >
              Collapse All
            </Button>
          )}
        </div>
      </div>

      {/* Test Results List */}
      <div className="divide-y divide-border">
        {results.map((result, index) => (
          <div key={result.id} className="group">
            {/* Test Header Row */}
            <button
              onClick={() => result.error && toggleExpand(result.id)}
              className={cn(
                'w-full px-4 py-3 flex items-center gap-3 text-left transition-colors',
                result.error && 'hover:bg-muted/50 cursor-pointer',
                !result.error && 'cursor-default',
              )}
            >
              {/* Pass/Fail Icon */}
              {result.passed ? (
                <CheckCircle2 className="h-4 w-4 text-green-500 shrink-0" />
              ) : (
                <XCircle className="h-4 w-4 text-destructive shrink-0" />
              )}

              {/* Test Info */}
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2">
                  <span className="text-sm font-medium truncate">
                    {isSingleTest
                      ? result.name || copy.testName
                      : `Test ${index + 1}: ${result.name || result.description || 'Test Case'}`}
                  </span>
                  {result.isHidden && (
                    <Badge variant="secondary" className="text-xs">
                      Hidden
                    </Badge>
                  )}
                </div>
                {result.description && result.name !== result.description && (
                  <p className="text-xs text-muted-foreground truncate">
                    {result.description}
                  </p>
                )}
              </div>

              {/* Execution Time */}
              {result.executionTime !== undefined && (
                <div className="flex items-center gap-1 text-xs text-muted-foreground shrink-0">
                  <Clock className="h-3 w-3" />
                  {result.executionTime}ms
                </div>
              )}

              {/* Expand Icon */}
              {result.error && (
                <div className="shrink-0">
                  {expandedTests.has(result.id) ? (
                    <ChevronUp className="h-4 w-4 text-muted-foreground" />
                  ) : (
                    <ChevronDown className="h-4 w-4 text-muted-foreground" />
                  )}
                </div>
              )}
            </button>

            {/* Expanded Error Details */}
            {expandedTests.has(result.id) && result.error && (
              <div className="px-4 pb-4 pt-0 ml-7 space-y-4">
                {/* Error Message */}
                <div className="p-4 rounded-xl bg-destructive/5 border-2 border-black hard-shadow-xs">
                  <div className="flex items-start gap-2">
                    <AlertTriangle className="h-4 w-4 text-destructive shrink-0 mt-1" />
                    <pre className="text-sm text-destructive font-bold font-mono whitespace-pre-wrap break-words leading-relaxed">
                      {result.error}
                    </pre>
                  </div>
                </div>

                {/* Expected vs Actual */}
                {(result.expected !== undefined ||
                  result.output !== undefined) && (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      {result.expected !== undefined && (
                        <div className="p-3 rounded-lg bg-green-500/5 border-2 border-green-500/20">
                          <div className="text-xs font-bold text-green-600 mb-2 uppercase tracking-tight">
                            Expected
                          </div>
                          <pre className="text-sm font-bold font-mono text-green-600 whitespace-pre-wrap break-words">
                            {JSON.stringify(result.expected, null, 2)}
                          </pre>
                        </div>
                      )}
                      {result.output !== undefined && (
                        <div className="p-3 rounded-lg bg-destructive/5 border-2 border-destructive/20">
                          <div className="text-xs font-bold text-destructive mb-2 uppercase tracking-tight">
                            Received
                          </div>
                          <pre className="text-sm font-bold font-mono text-destructive whitespace-pre-wrap break-words">
                            {JSON.stringify(result.output, null, 2)}
                          </pre>
                        </div>
                      )}
                    </div>
                  )}
              </div>
            )}
          </div>
        ))}

        {/* Hidden Tests Summary */}
        {totalHiddenTests > 0 && (
          <div className="px-4 py-3 flex items-center gap-3 bg-muted/30">
            <div
              className={cn(
                'h-4 w-4 rounded-full flex items-center justify-center text-[10px] font-bold',
                hiddenTestsPassed === totalHiddenTests
                  ? 'bg-green-500 text-white'
                  : 'bg-muted-foreground text-background',
              )}
            >
              ?
            </div>
            <span className="text-sm text-muted-foreground">
              {hiddenTestsPassed}/{totalHiddenTests} hidden tests passed
            </span>
          </div>
        )}
      </div>
    </div>
  );
}

export default TestResults;

import { Check, Copy } from 'lucide-react';
import { useState } from 'react';
import { cn } from '@/lib/utils';
import { toast } from 'sonner';

interface CodeBlockProps extends React.HTMLAttributes<HTMLElement> {
  children?: React.ReactNode;
  className?: string;
}

export function CodeBlock({ children, className, ...props }: CodeBlockProps) {
  const [isCopied, setIsCopied] = useState(false);

  // Extract text content safely
  const getTextContent = (node: React.ReactNode): string => {
    if (typeof node === 'string') return node;
    if (Array.isArray(node)) return node.map(getTextContent).join('');
    if (typeof node === 'object' && node !== null && 'props' in node) {
      return getTextContent((node as any).props.children);
    }
    return '';
  };

  const copyToClipboard = async () => {
    const text = getTextContent(children);
    if (!text) return;

    try {
      await navigator.clipboard.writeText(text);
      setIsCopied(true);
      toast.success('Code copied to clipboard');
      setTimeout(() => setIsCopied(false), 2000);
    } catch (err) {
      toast.error('Failed to copy code');
    }
  };

  return (
    <div className="relative group rounded-lg bg-muted border border-border my-4 overflow-hidden">
      <div className="flex justify-between items-center px-4 py-2 bg-muted/50 border-b border-white/5">
        <div className="flex gap-1.5">
          <div className="w-2.5 h-2.5 rounded-full bg-red-500/20 opacity-50"></div>
          <div className="w-2.5 h-2.5 rounded-full bg-yellow-500/20 opacity-50"></div>
          <div className="w-2.5 h-2.5 rounded-full bg-green-500/20 opacity-50"></div>
        </div>
        <button
          onClick={copyToClipboard}
          className="p-1.5 rounded-md hover:bg-background/50 text-muted-foreground transition-colors"
          title="Copy code"
        >
          {isCopied ? (
            <Check className="w-3.5 h-3.5 text-green-500" />
          ) : (
            <Copy className="w-3.5 h-3.5" />
          )}
        </button>
      </div>
      <div className="overflow-x-auto p-4">
        <code className={cn('text-sm font-mono block whitespace-pre-wrap', className)} {...props}>
          {children}
        </code>
      </div>
    </div>
  );
}

import { useQueryErrorResetBoundary } from '@tanstack/react-query';
import { useRouter } from '@tanstack/react-router';
import { Button } from '@/components/ui/button';
import {
    Card,
    CardContent,
    CardDescription,
    CardFooter,
    CardHeader,
    CardTitle,
} from '@/components/ui/card';
import { AlertCircle, RefreshCcw, Home } from 'lucide-react';
import { useEffect } from 'react';
import * as Sentry from '@sentry/react';

export function DefaultErrorComponent({ error }: { error: Error }) {
    const router = useRouter();
    const queryErrorResetBoundary = useQueryErrorResetBoundary();

    useEffect(() => {
        // Log the error to Sentry when the error boundary catches it
        Sentry.captureException(error);
    }, [error]);

    return (
        <div className="flex min-h-[80vh] items-center justify-center p-4">
            <Card className="w-full max-w-md border-destructive/50 bg-destructive/5 dark:bg-destructive/10">
                <CardHeader className="text-center">
                    <div className="mx-auto mb-4 flex h-12 w-12 items-center justify-center rounded-full bg-destructive/10 text-destructive dark:bg-destructive/20">
                        <AlertCircle className="h-6 w-6" />
                    </div>
                    <CardTitle className="text-xl">Something went wrong</CardTitle>
                    <CardDescription>
                        An unexpected error occurred while rendering this page.
                    </CardDescription>
                </CardHeader>
                <CardContent className="text-center text-sm text-muted-foreground">
                    <p className="mb-2 font-mono text-xs bg-muted/50 p-2 rounded max-h-32 overflow-auto text-left">
                        {error.message || 'Unknown error'}
                    </p>
                </CardContent>
                <CardFooter className="flex justify-center gap-4">
                    <Button
                        variant="outline"
                        onClick={() => {
                            router.history.go(-1);
                        }}
                    >
                        Go Back
                    </Button>
                    <Button
                        onClick={() => {
                            // Invalidate all queries and reload the page
                            queryErrorResetBoundary.reset();
                            router.invalidate();
                            window.location.reload();
                        }}
                    >
