import { useEffect } from 'react';
import { I18nextProvider } from 'react-i18next';
import i18n from '@/lib/i18n';
import { isValidLocale, fallbackLng } from '@/lib/i18n/settings';
import type { Locale } from '@/lib/i18n/settings';

interface I18nProviderProps {
  children: React.ReactNode;
  locale?: string;
}

/**
 * I18n Provider that syncs the language with the route locale parameter.
 * Wrap this around your app content to enable translations.
 */
export function I18nProvider({ children, locale }: I18nProviderProps) {
  // TANSTACK UPDATE: Language switching is handled in the route's beforeLoad
  // to prevent flash of unlocalized content.
  // HOWEVER, we keep this useEffect to ensure client-side transitions are
  // caught if the router doesn't re-trigger beforeLoad.
  const targetLocale: Locale = isValidLocale(locale ?? '')
    ? (locale as Locale)
    : fallbackLng;

  // Synchronously set language if mismatch is detected during render
  // This ensures the I18nextProvider receives the correct state immediately during hydration
  if (i18n.language !== targetLocale) {
    i18n.changeLanguage(targetLocale);
  }

  useEffect(() => {
    if (i18n.language !== targetLocale) {
      i18n.changeLanguage(targetLocale);
    }
  }, [targetLocale]);


  return <I18nextProvider i18n={i18n}>{children}</I18nextProvider>;
}

'use client';

import { useParams, useLocation } from '@tanstack/react-router';
import { Button } from '@/components/ui/button';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { Globe } from 'lucide-react';
import { supportedLngs, type Locale } from '@/lib/i18n/settings';

const languageNames: Record<Locale, string> = {
  en: 'English',
  id: 'Bahasa Indonesia',
};

const languageFlags: Record<Locale, string> = {
  en: '🇺🇸',
  id: '🇮🇩',
};

export function LanguageSwitcher() {
  const location = useLocation();
  const params = useParams({ strict: false });
  const currentLocale = (params.locale as Locale) || 'en';

  const handleLanguageChange = (newLocale: Locale) => {
    if (newLocale === currentLocale) return;

    // Replace the locale segment in the current path
    const currentPath = location.pathname;
    const pathSegments = currentPath.split('/');

    // The locale is always the first segment after the leading slash
    if (
      pathSegments.length > 1 &&
      supportedLngs.includes(pathSegments[1] as Locale)
    ) {
      pathSegments[1] = newLocale;
      const newPath = pathSegments.join('/');
      // Use window.location for clean navigation with dynamic paths
      window.location.href = newPath;
    } else {
      // If no locale in path, navigate to /$locale
      window.location.href = `/${newLocale}`;
    }
  };

  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button variant="ghost" size="sm" className="gap-2 px-2">
          <Globe className="h-4 w-4" />
          <span className="hidden sm:inline">
            {languageFlags[currentLocale]}
          </span>
          <span className="sr-only">Switch language</span>
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end">
        {supportedLngs.map((locale) => (
          <DropdownMenuItem
            key={locale}
            onClick={() => handleLanguageChange(locale)}
            className={currentLocale === locale ? 'bg-accent' : ''}
          >
            <span className="mr-2">{languageFlags[locale]}</span>
            {languageNames[locale]}
          </DropdownMenuItem>
        ))}
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

import React from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import rehypeHighlight from 'rehype-highlight';
// Explicitly import languages that might not be in the common set
import xquery from 'highlight.js/lib/languages/xquery';
import bash from 'highlight.js/lib/languages/bash'; // Often good for CLI commands
import json from 'highlight.js/lib/languages/json';
import typescript from 'highlight.js/lib/languages/typescript';

