    status: 'PASSED' | 'FAILED' | 'ERROR' | 'TIMEOUT';
    output: string;
    executionTime: number;
    error?: string;
    returnValue?: unknown;
    logs?: Array<{ id: string; type: string; message: string }>;
    assertionCount?: number;
}

export interface ExecuteOptions {
    timeout?: number;
    testCases?: TestCase[];
    cssContent?: string;
    files?: Record<string, string>; // VFS: multi-page content for E2E challenges
    onNavigate?: (path: string) => void; // Callback for URL bar updates
    expectedState?: ExpectedStateRule[]; // DOM validation rules
    isTypeScript?: boolean;
}

export interface TestCase {
    id: string;
    name: string;
    validate: (page: MockedPlaywrightPage) => Promise<boolean>;
}

export interface TestCaseResult {
    id: string;
    name: string;
    passed: boolean;
    error?: string;
}

export interface ExpectResult {
    expect: ((actual: unknown) => {
        // Generic Assertions
        toBe: (expected: unknown) => Promise<void>;
        toEqual: (expected: unknown) => Promise<void>;
        toBeTruthy: () => Promise<void>;
        toBeFalsy: () => Promise<void>;
        toBeNull: () => Promise<void>;
        toBeUndefined: () => Promise<void>;
        toBeDefined: () => Promise<void>;
        toBeGreaterThan: (expected: number) => Promise<void>;
        toBeGreaterThanOrEqual: (expected: number) => Promise<void>;
        toBeLessThan: (expected: number) => Promise<void>;
        toBeLessThanOrEqual: (expected: number) => Promise<void>;
        toBeCloseTo: (expected: number, precision?: number) => Promise<void>;
        toContain: (expected: any) => Promise<void>;
        toHaveLength: (expected: number) => Promise<void>;
        toMatch: (expected: string | RegExp) => Promise<void>;
        toHaveProperty: (path: string, value?: any) => Promise<void>;

        // Locator Assertions
        toBeVisible: (options?: { timeout?: number }) => Promise<void>;
        toBeHidden: (options?: { timeout?: number }) => Promise<void>;
        toHaveText: (text: string | RegExp, options?: { timeout?: number }) => Promise<void>;
        toHaveValue: (value: string | RegExp, options?: { timeout?: number }) => Promise<void>;
        toContainText: (text: string | RegExp, options?: { timeout?: number }) => Promise<void>;
        toHaveAttribute: (name: string, value?: string | RegExp, options?: { timeout?: number }) => Promise<void>;
        toHaveClass: (className: string | RegExp, options?: { timeout?: number }) => Promise<void>;
        toHaveCSS: (name: string, value: string | RegExp, options?: { timeout?: number }) => Promise<void>;
        toHaveJSProperty: (name: string, value: any, options?: { timeout?: number }) => Promise<void>;
        toHaveCount: (count: number, options?: { timeout?: number }) => Promise<void>;
        toBeChecked: (options?: { timeout?: number }) => Promise<void>;
        toBeEnabled: (options?: { timeout?: number }) => Promise<void>;
        toBeDisabled: (options?: { timeout?: number }) => Promise<void>;
        toBeEditable: (options?: { timeout?: number }) => Promise<void>;
        toBeFocused: (options?: { timeout?: number }) => Promise<void>;
        toBeEmpty: (options?: { timeout?: number }) => Promise<void>;
        toHaveTitle: (title: string | RegExp, options?: { timeout?: number }) => Promise<void>;
        toHaveURL: (url: string | RegExp, options?: { timeout?: number }) => Promise<void>;

        not: any; // Simplified for brevity in type definition, implementation handles it
    }) & {
        soft: (actual: unknown) => any;
    };
    getAssertionCount: () => number;
    getTestResults: () => Array<{ message: string; passed: boolean }>;
}

import type { ExpectResult } from './executor.types';

/**
 * Create a simple expect function for assertions
 * Returns both the expect function and assert count getter
 */
/**
 * Create a simple expect function for assertions
 * Returns both the expect function and assert count getter
 */
export function createExpect(options?: { timeout?: number; deadline?: number }): ExpectResult {
    let assertionCount = 0;
    const testResults: Array<{ message: string; passed: boolean }> = [];
    const defaultTimeout = options?.timeout ?? 5000;
    const globalDeadline = options?.deadline;

    const incrementCount = () => {
        assertionCount++;
        console.log(`[Expect] Assertion count incremented to ${assertionCount}`);
    };
    const getAssertionCount = () => assertionCount;
    const getTestResults = () => testResults;

    /* eslint-disable @typescript-eslint/no-explicit-any, @typescript-eslint/no-unsafe-member-access, @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-unsafe-call, @typescript-eslint/restrict-template-expressions, @typescript-eslint/no-unsafe-return */
    const createMatchers = (actual: any, isSoft = false, isNot = false) => {
        const handleResult = (pass: boolean, message: string) => {
            incrementCount();
            // Invert if isNot is true
            const finalPass = isNot ? !pass : pass;
            const finalMessage = isNot ? `Not Error: ${message}` : message;

            if (!finalPass) {
                if (isSoft) {
                    const formattedMessage = finalMessage.includes('Expected')
                        ? `Soft Assertion Failed: ${finalMessage}`
                        : `Soft Assertion Failed: ${finalMessage} (Actual value did not match expected criteria)`;
                    console.error(formattedMessage);
                    testResults.push({ message: formattedMessage, passed: false });
                } else {
                    const formattedMessage = finalMessage.includes('Expected')
                        ? `Assertion Error: ${finalMessage}`
                        : `Assertion Error: ${finalMessage} (Actual value did not match expected criteria)`;
                    throw new Error(formattedMessage);
                }
            }
        };

        /**
         * Web-first assertions helper that polls until passing or timeout.
         */
        const poll = async (
            assertion: () => Promise<{ pass: boolean; message: string }> | { pass: boolean; message: string },
            options?: { timeout?: number; deadline?: number }
        ) => {
            const timeout = options?.timeout ?? defaultTimeout;
            const pollDeadline = options?.deadline ?? globalDeadline;
            const startTime = Date.now();
            let lastResult: { pass: boolean; message: string } | null = null;

            while (Date.now() - startTime < timeout) {
                // If we have a global or specific deadline, don't exceed it
                if (pollDeadline && Date.now() >= pollDeadline) {
                    break;
                }
                try {
                    const result = await assertion();
                    // Invert if isNot is true to determine if we should stop polling
                    const finalPass = isNot ? !result.pass : result.pass;
                    if (finalPass) {
                        // Pass the raw result to handleResult, it will invert it again properly
                        handleResult(result.pass, result.message);
                        return;
                    }
                    lastResult = result;
                } catch (e) {
                    // Ignore transient errors during polling (e.g. element detached)
                    lastResult = { pass: false, message: e instanceof Error ? e.message : String(e) };
                }
                await new Promise(resolve => setTimeout(resolve, 100));
            }

            // Timeout reached, fail with last result
            if (!lastResult) {
                try {
                    lastResult = await assertion();
                } catch (e) {
                    lastResult = { pass: false, message: e instanceof Error ? e.message : String(e) };
                }
            }
            handleResult(lastResult.pass, lastResult.message);
        };

        return {
            async toHaveText(expected: string | RegExp, options?: { timeout?: number }) {
                await poll(async () => {
                    let text = '';
                    try {
                        if (actual && typeof actual.textContent === 'function') {
                            text = (await actual.textContent()) || '';
                        } else if (actual instanceof HTMLElement) {
                            text = actual.textContent || '';
                        } else {
                            text = String(actual || '');
                        }
                    } catch (e) {
                        // Element might be missing
                        text = '';
                    }

                    const pass = expected instanceof RegExp ? expected.test(text) : text === expected;
                    return {
                        pass,
                        message: `Expected text "${text}" ${isNot ? 'NOT ' : ''}to match "${expected}"`
                    };
                }, options);
            },

            async toContainText(expected: string | RegExp, options?: { timeout?: number }) {
                await poll(async () => {
                    let text = '';
                    try {
                        if (actual && typeof actual.textContent === 'function') {
                            text = (await actual.textContent()) || '';
                        } else if (actual instanceof HTMLElement) {
                            text = actual.textContent || '';
                        } else {
                            text = String(actual || '');
                        }
                    } catch (e) {
                        text = '';
                    }

                    // Handle RegExp for toContainText (uncommon but possible)
                    if (expected instanceof RegExp) {
                        return {
                            pass: expected.test(text),
                            message: `Expected text "${text}" ${isNot ? 'NOT ' : ''}to contain regex "${expected}"`
                        };
                    }

                    return {
                        pass: text.includes(expected),
                        message: `Expected text "${text}" ${isNot ? 'NOT ' : ''}to contain "${expected}"`
                    };
                }, options);
            },

            async toHaveValue(expected: string | RegExp, options?: { timeout?: number }) {
                await poll(async () => {
                    let value = '';
                    try {
                        if (actual && typeof actual.inputValue === 'function') {
                            value = (await actual.inputValue()) || '';
                        } else if (
                            actual instanceof HTMLInputElement ||
                            actual instanceof HTMLTextAreaElement ||
                            actual instanceof HTMLSelectElement ||
                            actual instanceof HTMLButtonElement
                        ) {
                            value = (actual as any).value || '';
                        }
                    } catch {
                        value = '';
                    }

                    const pass = expected instanceof RegExp ? expected.test(value) : value === expected;
                    return {
                        pass,
                        message: `Expected value "${value}" ${isNot ? 'NOT ' : ''}to match "${expected}"`
                    };
                }, options);
            },

            async toHaveAttribute(name: string, value?: string | RegExp, options?: { timeout?: number }) {
                await poll(async () => {
                    let attrValue: string | null = null;
                    try {
                        if (actual && typeof actual.getAttribute === 'function') {
                            attrValue = await actual.getAttribute(name);
                        } else if (actual instanceof HTMLElement) {
                            attrValue = actual.getAttribute(name);
                        }
                    } catch {
                        attrValue = null;
                    }

                    if (attrValue === null) {
                        return { pass: false, message: `Expected attribute "${name}" to exist` };
                    }

                    if (value !== undefined) {
                        const pass = value instanceof RegExp ? value.test(attrValue) : attrValue === value;
                        return {
                            pass,
                            message: `Expected attribute "${name}" ${isNot ? 'NOT ' : ''}to have value "${value}", got "${attrValue}"`
                        };
                    }
                    return { pass: true, message: '' };
                }, options);
            },

            async toHaveCount(expected: number, options?: { timeout?: number }) {
                await poll(async () => {
                    let count = 0;
                    if (actual && typeof actual.count === 'function') {
                        count = await actual.count();
                    } else if (Array.isArray(actual)) {
                        count = actual.length;
                    }
                    return {
                        pass: count === expected,
                        message: `Expected count ${expected}, got ${count}`
                    };
                }, options);
            },

            async toBeVisible(options?: { timeout?: number }) {
                await poll(async () => {
                    let visible = false;
                    if (actual && typeof actual.isVisible === 'function') {
                        visible = await actual.isVisible();
                    } else if (actual instanceof HTMLElement) {
                        visible = actual.style.display !== 'none';
                    }
                    return {
                        pass: visible,
                        message: `Expected element ${isNot ? 'NOT ' : ''}to be visible`
                    };
                }, options);
            },

            async toBeChecked(options?: { timeout?: number }) {
                await poll(async () => {
                    let checked = false;
                    if (actual && typeof actual.isChecked === 'function') {
                        checked = await actual.isChecked();
                    } else if (actual instanceof HTMLInputElement || actual instanceof HTMLTextAreaElement) {
                        checked = (actual as any).checked || false;
                    }
                    return {
                        pass: checked,
                        message: `Expected element ${isNot ? 'NOT ' : ''}to be checked`
                    };
                }, options);
            },

            async toBeEnabled(options?: { timeout?: number }) {
                await poll(async () => {
                    let disabled = false;
                    if (actual && typeof actual.isDisabled === 'function') {
                        disabled = await actual.isDisabled();
                    } else if (actual instanceof HTMLElement) {
                        disabled = (actual as any).disabled || false;
                    }
                    return {
                        pass: !disabled,
                        message: `Expected element ${isNot ? 'NOT ' : ''}to be enabled`
                    };
                }, options);
            },

            async toBeDisabled(options?: { timeout?: number }) {
                await poll(async () => {
                    let disabled = false;
                    if (actual && typeof actual.isDisabled === 'function') {
                        disabled = await actual.isDisabled();
                    } else if (actual instanceof HTMLElement) {
                        disabled = (actual as any).disabled || false;
                    }
                    return {
                        pass: disabled,
                        message: `Expected element ${isNot ? 'NOT ' : ''}to be disabled`
                    };
                }, options);
            },

            async toBeEditable(options?: { timeout?: number }) {
                await poll(async () => {
                    let editable = false;
                    if (actual && typeof actual.isEditable === 'function') {
                        editable = await actual.isEditable();
                    } else if (actual instanceof HTMLInputElement || actual instanceof HTMLTextAreaElement) {
                        editable = !(actual as any).readOnly && !(actual as any).disabled;
                    }
                    return {
                        pass: editable,
                        message: `Expected element ${isNot ? 'NOT ' : ''}to be editable`
                    };
                }, options);
            },

            async toHaveTitle(expected: string | RegExp, options?: { timeout?: number }) {
                await poll(async () => {
                    let title = '';
                    if (actual && typeof actual.title === 'function') {
                        title = await actual.title();
                    } else if (actual && actual.targetDocument) {
                        title = actual.targetDocument.title;
                    } else if (typeof actual === 'string') {
                        title = actual;
                    }
                    const pass = expected instanceof RegExp ? expected.test(title) : title === expected;
                    return {
                        pass,
                        message: `Expected title "${title}" ${isNot ? 'NOT ' : ''}to match "${expected}"`
                    };
                }, options);
            },

            async toHaveURL(expected: string | RegExp, options?: { timeout?: number }) {
                await poll(async () => {
                    let url = '';
                    if (actual && typeof actual.url === 'function') {
                        url = actual.url();
                    } else if (typeof actual === 'string') {
                        url = actual;
                    }
                    const pass = expected instanceof RegExp ? expected.test(url) : url === expected;
                    return {
                        pass,
                        message: `Expected URL "${url}" ${isNot ? 'NOT ' : ''}to match "${expected}"`
                    };
                }, options);
            },

            async toHaveClass(expected: string | RegExp, options?: { timeout?: number }) {
                await poll(async () => {
                    let className = '';
                    if (actual && typeof actual.getAttribute === 'function') {
                        className = (await actual.getAttribute('class')) || '';
                    } else if (actual instanceof HTMLElement) {
                        className = actual.className;
                    }
                    const pass = expected instanceof RegExp ? expected.test(className) : className === expected;
                    return {
                        pass,
                        message: `Expected class "${className}" ${isNot ? 'NOT ' : ''}to match "${expected}"`
                    };
                }, options);
            },

            async toHaveCSS(name: string, value: string | RegExp, options?: { timeout?: number }) {
                await poll(async () => {
                    let cssValue = '';
                    if (actual && typeof actual.evaluate === 'function') {
                        cssValue = await actual.evaluate((el: HTMLElement, name: string) => {
                            return window.getComputedStyle(el).getPropertyValue(name);
                        }, name);
                    } else if (actual instanceof HTMLElement) {
                        cssValue = window.getComputedStyle(actual).getPropertyValue(name);
                    }
                    const pass = value instanceof RegExp ? value.test(cssValue) : cssValue === value;
                    return {
                        pass,
                        message: `Expected CSS property "${name}" to be "${value}", got "${cssValue}"`
                    };
                }, options);
            },

            async toHaveJSProperty(name: string, value: any, options?: { timeout?: number }) {
                await poll(async () => {
                    let propValue: any = undefined;
                    if (actual && typeof actual.evaluate === 'function') {
                        propValue = await actual.evaluate((el: any, name: string) => el[name], name);
                    } else if (actual) {
                        propValue = (actual)[name];
                    }
                    const pass = JSON.stringify(propValue) === JSON.stringify(value);
                    return {
                        pass,
                        message: `Expected JS property "${name}" to be ${JSON.stringify(value)}, got ${JSON.stringify(propValue)}`
                    };
                }, options);
            },

            async toBeFocused(options?: { timeout?: number }) {
                await poll(async () => {
                    let isFocused = false;
                    if (actual && typeof actual.evaluate === 'function') {
                        isFocused = await actual.evaluate((el: any) => el === el.ownerDocument.activeElement);
                    } else if (actual instanceof HTMLElement) {
                        isFocused = actual === actual.ownerDocument.activeElement;
                    }
                    return {
                        pass: isFocused,
                        message: `Expected element ${isNot ? 'NOT ' : ''}to be focused`
                    };
                }, options);
            },

            async toBeEmpty(options?: { timeout?: number }) {
                await poll(async () => {
                    let isEmpty = false;
                    if (actual && typeof actual.evaluate === 'function') {
                        isEmpty = await actual.evaluate((el: HTMLElement) => {
                            if (['INPUT', 'TEXTAREA', 'SELECT'].includes(el.tagName)) return !(el as HTMLInputElement).value;
                            return !el.textContent;
                        });
                    } else if (actual instanceof HTMLElement) {
                        if (['INPUT', 'TEXTAREA', 'SELECT'].includes(actual.tagName)) isEmpty = !(actual as HTMLInputElement).value;
                        else isEmpty = !actual.textContent;
                    }
                    return {
                        pass: isEmpty,
                        message: `Expected element ${isNot ? 'NOT ' : ''}to be empty`
                    };
                }, options);
            },

            async toBeHidden(options?: { timeout?: number }) {
                await poll(async () => {
                    let visible = false;
                    if (actual && typeof actual.isVisible === 'function') {
                        visible = await actual.isVisible();
                    } else if (actual instanceof HTMLElement) {
                        visible = actual.style.display !== 'none';
                    }
                    return {
                        pass: !visible,
                        message: `Expected element ${isNot ? 'NOT ' : ''}to be hidden`
                    };
                }, options);
            },

            async toBeTruthy() {
                await Promise.resolve();
                handleResult(!!actual, `Expected value ${isNot ? 'NOT ' : ''}to be truthy, got ${actual}`);
            },

            async toBeFalsy() {
                await Promise.resolve();
                handleResult(!actual, `Expected value ${isNot ? 'NOT ' : ''}to be falsy, got ${actual}`);
            },

            async toBeNull() {
                await Promise.resolve();
                handleResult(actual === null, `Expected value ${isNot ? 'NOT ' : ''}to be null, got ${actual}`);
            },

            async toBeUndefined() {
                await Promise.resolve();
                handleResult(actual === undefined, `Expected value ${isNot ? 'NOT ' : ''}to be undefined, got ${actual}`);
            },

            async toBeDefined() {
                await Promise.resolve();
                handleResult(actual !== undefined, `Expected value ${isNot ? 'NOT ' : ''}to be defined`);
            },

            async toBeGreaterThan(expected: number) {
                await Promise.resolve();
                handleResult(actual > expected, `Expected ${actual} ${isNot ? 'NOT ' : ''}to be greater than ${expected}`);
            },

            async toBeGreaterThanOrEqual(expected: number) {
                await Promise.resolve();
                handleResult(actual >= expected, `Expected ${actual} ${isNot ? 'NOT ' : ''}to be greater than or equal to ${expected}`);
            },

            async toBeLessThan(expected: number) {
                await Promise.resolve();
                handleResult(actual < expected, `Expected ${actual} ${isNot ? 'NOT ' : ''}to be less than ${expected}`);
            },

            async toBeLessThanOrEqual(expected: number) {
                await Promise.resolve();
                handleResult(actual <= expected, `Expected ${actual} ${isNot ? 'NOT ' : ''}to be less than or equal to ${expected}`);
            },

            async toBeCloseTo(expected: number, precision = 2) {
                await Promise.resolve();
                const pass = Math.abs(actual - expected) < Math.pow(10, -precision) / 2;
                handleResult(pass, `Expected ${actual} ${isNot ? 'NOT ' : ''}to be close to ${expected} with precision ${precision}`);
            },

            async toContain(expected: any) {
                await Promise.resolve();
                let pass = false;
                if (Array.isArray(actual) || typeof actual === 'string') {
                    pass = actual.includes(expected);
                } else if (actual instanceof Set || actual instanceof Map) {
                    pass = actual.has(expected);
                }
                handleResult(pass, `Expected ${actual} ${isNot ? 'NOT ' : ''}to contain ${expected}`);
            },

            async toHaveLength(expected: number) {
                await Promise.resolve();
                const length = actual?.length ?? (actual?.size ?? 0);
                handleResult(length === expected, `Expected length ${expected}, got ${length}`);
            },

            async toMatch(expected: string | RegExp) {
                await Promise.resolve();
                const pass = expected instanceof RegExp ? expected.test(String(actual)) : String(actual).includes(expected);
                handleResult(pass, `Expected "${actual}" ${isNot ? 'NOT ' : ''}to match "${expected}"`);
            },

            async toHaveProperty(path: string, value?: any) {
                await Promise.resolve();
                // Simple dot-notation path resolver
                const parts = path.split('.');
                let current = actual;
                let found = true;
                for (const part of parts) {
                    if (current === null || current === undefined || typeof current !== 'object' || !(part in current)) {
                        found = false;
                        break;
                    }
                    current = current[part];
                }

                if (!found) {
                    handleResult(false, `Property "${path}" not found`);
                    return;
                }

                if (value !== undefined) {
                    const pass = JSON.stringify(current) === JSON.stringify(value);
                    handleResult(pass, `Expected property "${path}" to equal ${JSON.stringify(value)}, got ${JSON.stringify(current)}`);
                } else {
                    handleResult(true, `Property "${path}" exists`);
                }
            },

            async toBe(expected: unknown) {
                await Promise.resolve();
                handleResult(actual === expected, `Expected ${expected}, got ${actual}`);
            },
            async toEqual(expected: unknown) {
                await Promise.resolve();
                handleResult(JSON.stringify(actual) === JSON.stringify(expected), `Expected equal`);
            },
        };
    };

    const expectFunc = ((actual: any) => {
        const matchers: any = createMatchers(actual, false, false);
        matchers.not = createMatchers(actual, false, true);
        return matchers;
    }) as any;

    expectFunc.soft = (actual: any) => {
        const matchers: any = createMatchers(actual, true, false);
        matchers.not = createMatchers(actual, true, true);
        return matchers;
    };

    return { expect: expectFunc, getAssertionCount, getTestResults };
}

/**
 * Iframe Executor
 *
 * Creates an isolated iframe environment for executing user code
 * against HTML content using the MockedPlaywrightPage shim.
 */

import { MockedPlaywrightPage } from './playwright-shim';
import { logger } from '@/lib/logger';
import { transpileTypeScript } from './typescript-transpiler';
import {
  type ExecutionResult,
  type ExecuteOptions,
  type TestCase,
  type TestCaseResult
} from './executor.types';
import { createExpect } from './expect-matchers';
import { validateExpectedState } from './dom-validator';
import { createInterceptedConsole } from './console-interceptor';

/**
 * Executes Playwright-style code in a sandboxed iframe
 */
export async function executePlaywrightCode(
  code: string,
  htmlContent: string,
  options?: ExecuteOptions & {
    existingIframe?: HTMLIFrameElement;
    strictMode?: boolean;
  },
): Promise<ExecutionResult> {
  const timeout = options?.timeout || 10000;
  const startTime = Date.now();
  const useExistingIframe = !!options?.existingIframe;
  const logs: Array<{ id: string; type: string; message: string }> = [];
  const strictMode = options?.strictMode !== false; // Default to true for backward compatibility
  let executableCode = code;

  // Transpile if TypeScript
  if (options?.isTypeScript) {
    try {
      executableCode = await transpileTypeScript(code);
    } catch (error) {
      return {
        status: 'ERROR',
        output: error instanceof Error ? error.message : String(error),
        executionTime: 0,
        error: error instanceof Error ? error.message : String(error),
        logs: [],
      };
    }
  }

  // Determine standard log level mapping
  const getLogType = (level: string) => {
    if (level === 'error') return 'error';
    if (level === 'warn') return 'warn';
    return 'log';
  };

  // 1. Capture logger.debug() and other calls (e.g. from playwright-shim)
  // This redirects [Action] click logs from DevTools to the User Console UI
  let logCounter = 0;
  logger.setHandler((level, message, args) => {
    // console.log('[DEBUG] Handler intercepted:', level, message);
    // Basic formatting for args
    const argsStr = args.length ? ' ' + args.map(String).join(' ') : '';
    logs.push({
      id: `log-${Date.now()}-${logCounter++}`,
      type: getLogType(level),
      message: `${message}${argsStr}`,
    });
  });

  // Patch HTML content for specific challenges where happy-dom needs checking
  // e.g. pw-wait-for-response uses relative fetch which fails in happy-dom
  let finalHtml = htmlContent;
  const fetchRegex = /fetch\(('|")\/api\/data('|")\)/;
  if (htmlContent.match(fetchRegex)) {
    finalHtml = htmlContent.replace(
      fetchRegex,
      "fetch($1http://localhost/api/data$1)",
    );
  }

  // Static analysis for "Strict Mode" (Educational Check)
  // We want to catch uses of 'document' or 'window' that aren't inside page.evaluate()
  // This is a simple regex check, not a full AST parse, but catches most beginner mistakes.
  const forbiddenPatterns = [
    {
      pattern: /\bwindow\.localStorage\b/,
      message:
        "In Playwright, you cannot access 'window' directly. Use 'page.evaluate(() => window.localStorage...)'.",
    },
    {
      pattern: /\bwindow\.sessionStorage\b/,
      message:
        "In Playwright, you cannot access 'window' directly. Use 'page.evaluate(() => window.sessionStorage...)'.",
    },
    {
      pattern: /\bdocument\.(getElement|query|body|cookie)\b/,
      message:
        "In Playwright, you cannot access 'document' directly. Use 'page.locator()' or 'page.evaluate()'.",
    },
    {
      pattern: /alert\(/,
      message:
        'In Playwright, you cannot handle alerts this way. Use \'page.on("dialog", ...)\'.',
    },
  ];

  if (strictMode) {
    const codeToTest = executableCode.trim();
    for (const { pattern, message } of forbiddenPatterns) {
      if (pattern.test(codeToTest)) {
        return {
          status: 'FAILED',
          output: `Strict Mode Error: ${message}\n\nReal Playwright tests run in Node.js and cannot access the Browser DOM directly.`,
          executionTime: 0,
          error: `Strict Mode Error: ${message}`,
          logs: [],
        };
      }
    }
  }

  // Phase 2: Strip standard Playwright imports (they are decorative in the shim)
  // We use a robust regex to handle multi-line imports and various spacing
  executableCode = executableCode.replace(
    /^\s*import\s+[\s\S]+?from\s+['"]@playwright\/test['"];?/gm,
    '',
  );

  try {
    return await new Promise((resolve) => {
      let iframe: HTMLIFrameElement;

      if (useExistingIframe && options?.existingIframe) {
        // Use existing iframe - re-inject HTML content
        iframe = options.existingIframe;
        if (iframe.sandbox && iframe.sandbox.add) {
          iframe.sandbox.add('allow-scripts', 'allow-same-origin', 'allow-forms');
        }
      } else {
        // Create isolated iframe (fallback behavior)
        iframe = document.createElement('iframe');
        iframe.style.cssText = 'display: none;';
        iframe.sandbox.add('allow-scripts', 'allow-same-origin', 'allow-forms');
        document.body.appendChild(iframe);
      }

      // Use function declaration for hoisting so it can be called by setTimeout
      // and can see timeoutId defined below (TDZ is passed by the time this runs)
      function cleanup() {
        clearTimeout(timeoutId);
        // Only remove if we created it
        if (!useExistingIframe && iframe.parentNode) {
          document.body.removeChild(iframe);
        }
      }

      // Timeout handler
      const timeoutId = setTimeout(() => {
        cleanup();
        resolve({
          status: 'TIMEOUT',
          output: `Process timed out. Please review your logic for potential errors or long-running tasks.`,
          executionTime: timeout,
          error: `Process timed out. Please review your logic for potential errors or long-running tasks.`,
          logs,
        });
      }, timeout);

      try {
        const executeCode = async () => {
          try {
            // Inject HTML into iframe
            const iframeDoc = iframe.contentDocument;
            if (!iframeDoc) {
              throw new Error('Could not access iframe document');
            }

            // In Playwright tests, localStorage/sessionStorage should be empty at the start of a run
            // to ensure isolation. Since all challenges share the same origin, we clear manually.
            // We also initialize __APP_STATE__ for E2E app state that persists across VFS navigations.
            try {
              if (iframe.contentWindow) {
                iframe.contentWindow.localStorage?.clear();
                iframe.contentWindow.sessionStorage?.clear();
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                const win = iframe.contentWindow as any;
                win.__MOCK_ROUTES__ = [];
                // In-memory state that persists across VFS navigations within a single execution run
                win.__APP_STATE__ = {};
              }
            } catch (e) {
              console.warn('Failed to clear storage:', e);
            }

            // Set up the HTML content
            iframeDoc.open();

            // NOTE: Console interception is done AFTER iframeDoc.close() below
            // to ensure we intercept the final document's console object

            iframeDoc.write(`
                        <!DOCTYPE html>
                        <html>
                          <head>
                            <meta charset="utf-8">
                            <base href="http://localhost/" />
                            <style>
                              * { box-sizing: border-box; }
                              body { 
                                font-family: system-ui, sans-serif; 
                                padding: 16px;
                                margin: 0;
                              }
                              ${options?.cssContent || ''}
                            </style>
                            <script data-internal="true">
                              (function() {
                                if (window['__tweVfsPolyfillInstalled']) return;
                                window['__tweVfsPolyfillInstalled'] = true;

                                // Polyfill fetch to handle relative URLs and MOCK requests
                                window.fetch = function(input, init) {
                                    let url = input;
                                    if (typeof input === 'string') {
                                        if (input.startsWith('/')) {
                                            url = 'http://localhost' + input;
                                        } else if (input.startsWith('http')) {
                                            url = input;
                                        }
                                    }

                                    if (window.__MOCK_ROUTES__) {
                                        for (const route of window.__MOCK_ROUTES__) {
                                            let isMatch = false;
                                            if (typeof route.matcher === 'string') {
                                                if (route.matcher.includes('*')) {
                                                    const regex = new RegExp(route.matcher.replace(/\\*/g, '.*'));
                                                    isMatch = regex.test(url);
                                                } else {
                                                    isMatch = url.includes(route.matcher);
                                                }
                                            } else if (route.matcher instanceof RegExp) {
                                                isMatch = route.matcher.test(url);
                                            } else if (typeof route.matcher === 'function') {
                                                try {
                                                    isMatch = route.matcher(new URL(url));
                                                } catch {
                                                    isMatch = false;
                                                }
                                            }

                                            if (isMatch) {
                                                console.log('Mocking fetch via page.route to ' + url);
                                                const requestInfo = {
                                                    url,
                                                    method: init?.method || 'GET',
                                                    headers: init?.headers || {},
                                                    body: init?.body
                                                };

                                                return route.handler(requestInfo).then(result => {
                                                    if (result && result.type === 'fulfill') {
                                                        const resp = result.response;
                                                        return Promise.resolve({
                                                            ok: (resp.status || 200) >= 200 && (resp.status || 200) < 300,
                                                            status: resp.status || 200,
                                                            json: () => Promise.resolve(resp.json || JSON.parse(typeof resp.body === 'string' ? resp.body : '{}')),
                                                            text: () => Promise.resolve(typeof resp.body === 'string' ? resp.body : JSON.stringify(resp.json || {})),
                                                            headers: new Headers(resp.headers || {'content-type': 'application/json'})
                                                        });
                                                    }
                                                    return Promise.reject(new Error('Route handler did not fulfill'));
                                                });
                                            }
                                        }
                                    }

                                    if (typeof url === 'string' && url.includes('/api/data')) {
                                        return Promise.resolve({
                                            ok: true,
                                            status: 200,
                                            json: () => Promise.resolve({ success: true, count: 5 }),
                                            text: () => Promise.resolve('{"success":true}'),
                                            headers: new Headers({'content-type': 'application/json'})
                                        });
                                    }

                                    return Promise.resolve({
                                        ok: true,
                                        status: 404,
                                        json: () => Promise.resolve({}),
                                        text: () => Promise.resolve('Not Found')
                                    });
                                };

                                    window.alert = function(message) {
                                    console.log('[Dialog] alert: ' + message);
                                    if (window.__MOCK_DIALOG_HANDLER__) {
                                        window.__MOCK_DIALOG_HANDLER__('alert', message);
                                    }
                                };

                                // VFS Navigation Shim for Initial Render
                                // (Only active if files/VFS is enabled)
                                ${options?.files
                ? `
                                window.__VFS_NAVIGATE__ = function(path) {
                                    console.log('[VFS] Navigating to ' + path);
                                    if (window.page) {
                                        window.page.goto(path).catch(e => console.error('Navigation failed:', e));
                                    } else {
                                        console.error('window.page not found for VFS navigation');
                                    }
                                };

                                window.addEventListener('click', function(e) {
                                    const link = e.target.closest('a[href]');
                                    if (link && !link.getAttribute('target')) {
                                        const href = link.getAttribute('href');
                                        if (href && (href.startsWith('/') || href.endsWith('.html'))) {
                                            e.preventDefault();
                                            window.__VFS_NAVIGATE__(href);
                                        }
                                    }
                                }, true);

                                window.addEventListener('submit', function(e) {
                                    const form = e.target;
                                    const action = form.getAttribute('action');
                                    if (action && (action.startsWith('/') || action.endsWith('.html'))) {
                                        e.preventDefault();
                                        window.__VFS_NAVIGATE__(action);
                                    }
                                }, true);
                                `
                : `
                                window.addEventListener('click', function(e) {
                                    const link = e.target.closest('a[href]');
                                    if (link && !link.getAttribute('target')) {
                                        const href = link.getAttribute('href');
                                        // Block navigation for relative links or anything that would navigate the frame
                                        // We allow anchor links (#) if they don't have a path
                                        if (href && (href.startsWith('/') || href.startsWith('http') || (href.startsWith('#') && href.length > 1))) {
                                           // Special case for purely local anchors?
                                           // Actually, let's just block everything that looks like a page navigation
                                           if (!href.startsWith('#')) {
                                               e.preventDefault();
                                           }
                                        }
                                    }
                                }, true);

                                window.addEventListener('submit', function(e) {
                                    e.preventDefault();
                                }, true);
                                `
              }
                              })();
                            </script>
                          </head>
                          <body>
                            ${finalHtml}
                          </body>
                        </html>
                    `);
            iframeDoc.close();

            // Manually execute scripts using scoped execution
            // Skip internal scripts marked with data-internal="true"
            const scripts = Array.from(
              iframeDoc.querySelectorAll('script'),
            );

            scripts.forEach((script) => {
              if (script.textContent) {
                try {
                  /* eslint-disable @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-explicit-any */
                  const win = iframe.contentWindow as any;
                  const doc = iframe.contentDocument;
                  if (!win || !doc) return;
                  /* eslint-enable @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-explicit-any */

                  const scriptCode = script.textContent;

                  // Extract function names and assign them to window
                  const funcMatches = Array.from(
                    scriptCode.matchAll(/function\s+(\w+)\s*\(/g),
                  );
                  const funcNames: string[] = [];
                  for (const match of funcMatches) {
                    funcNames.push(match[1]);
                  }

                  const code = `
                                    return (function(window, document) {
                                        try {
                                            ${scriptCode}
                                            ${funcNames.map((name) => `if (typeof ${name} === 'function') window.${name} = ${name};`).join('\n')}
                                        } catch(err) {
                                            console.error('Error in injected script:', err);
                                        }
                                    }).call(window, window, document);
                                `;

                  // eslint-disable-next-line @typescript-eslint/no-implied-eval
                  const fn = new Function('window', 'document', code);
                  // eslint-disable-next-line @typescript-eslint/no-unsafe-call
                  fn(win, doc);
                } catch (e) {
                  console.error('Failed to execute script shim:', e);
                }
              }
            });

            // Manually attach onclick handlers using scoped execution
            // This works around HappyDOM limitation where inline event handlers don't verify consistently
            const elementsWithClick = Array.from(
              iframeDoc.querySelectorAll('[onclick]'),
            );
            elementsWithClick.forEach((el) => {
              const handlerCode = el.getAttribute('onclick');
              if (handlerCode) {
                try {
                  /* eslint-disable @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-explicit-any, @typescript-eslint/no-unsafe-member-access, @typescript-eslint/no-unsafe-argument */
                  const win = iframe.contentWindow as any;
                  const doc = iframe.contentDocument;
                  if (!win || !doc) return;

                  // Extract function names from window that were defined in script tags
                  // and create local references for them
                  const windowFuncs = Object.keys(win).filter(
                    (key) =>
                      // eslint-disable-next-line security/detect-object-injection
                      typeof win[key] === 'function' &&
                      ![
                        'fetch',
                        'setTimeout',
                        'setInterval',
                        'clearTimeout',
                        'clearInterval',
                      ].includes(key),
                  );
                  /* eslint-enable @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-explicit-any, @typescript-eslint/no-unsafe-member-access, @typescript-eslint/no-unsafe-argument */
                  const funcDestructure =
                    windowFuncs.length > 0
                      ? `const { ${windowFuncs.join(', ')} } = window;`
                      : '';

                  const code = `
                                    const fetch = window.fetch;
                                    ${funcDestructure}
                                    return (function(window, document, event) {
                                        try {
                                            ${handlerCode}
                                        } catch(err) {
                                            console.error('Error in onclick handler:', err);
                                        }
                                    }).call(this, window, document, event);
                                `;

                  // eslint-disable-next-line @typescript-eslint/no-implied-eval
                  const fn = new Function('window', 'document', 'event', code);

                  el.addEventListener('click', (event) => {
                    fn.call(el, win, doc, event);
                  });
                  // Remove attribute to prevent double-execution if HappyDOM ever fixes this
                  el.removeAttribute('onclick');
                } catch (e) {
                  console.error('Failed to attach onclick shim:', e);
                }
              }
            });

            // Create mocked page object
            const remainingBudget = Math.max(0, (startTime + timeout) - Date.now());
            const globalDeadline = startTime + timeout - 500; // 500ms safety buffer for cleanup

            const actionTimeout = Math.min(5000, Math.max(2000, remainingBudget - 1000));
            const page = new MockedPlaywrightPage(iframeDoc, { 
                timeout: actionTimeout,
                deadline: globalDeadline 
            });

            // Set up VFS for multi-page E2E challenges
            if (options?.files) {
              page.setVFS(options.files, {
                onNavigate: options.onNavigate,
                cssContent: options.cssContent,
              });
            }

            // Create an intercepted console object that logs to our logs array
            const logCounterRef = { current: logCounter };
            const interceptedConsole = createInterceptedConsole(logs, logCounterRef);
            // Sync back the counter if needed, though logCounterRef.current handles it

            // Create an enhanced document wrapper with friendlier error messages
            const createEnhancedDocument = (doc: Document) => {
              const handler: ProxyHandler<Document> = {
                get(target, prop) {
                  if (prop === 'querySelectorAll') {
                    return (selector: string) => {
                      const elements = target.querySelectorAll(selector);
                      if (elements.length === 0) {
                        console.warn(`Warning: No elements found for selector '${selector}'`);
                      }
                      return elements;
                    };
                  }
                  const value = (target as any)[prop];
                  return typeof value === 'function' ? value.bind(target) : value;
                },
              };
              return new Proxy(doc, handler);
            };

            const enhancedDocument = createEnhancedDocument(iframeDoc);

            // Prepare the iframe execution environment
            const contentWindow = iframe.contentWindow as any;

            // Initialize promise tracker for async tests
            contentWindow.__testPromises = [];

            // Mock test runner object (Support both test.step and standard test('name', ...))
            const testInstance = async (name: string, callback: (fixtures: any) => Promise<void>) => {
              // Create a tracking promise for this test
              const testPromise = (async () => {
                interceptedConsole.log(`[Test] ${name}`);
                try {
                  await callback({ page, expect });
                } catch (error) {
                  interceptedConsole.error(`[Test] ${name} FAILED: ${String(error)}`);
                  throw error;
                }
              })();

              // Track it so we can await it later
              if (Array.isArray(contentWindow.__testPromises)) {
                contentWindow.__testPromises.push(testPromise);
              }

              return testPromise;
            };
            (testInstance as any).step = async (name: string, callback: () => Promise<unknown>) => {
              interceptedConsole.log(`[Step] ${name}`);
              try {
                await callback();
              } catch (error) {
                interceptedConsole.error(`[Step] ${name} FAILED: ${String(error)}`);
                throw error;
              }
            };
            const test = testInstance;

            // Inject tools into the iframe context
            contentWindow.page = page;

            // Standardize timeouts: assertions/actions should fail before the global execution timeout
            // to provide clear error messages instead of a generic "Process timed out".
            const assertionTimeout = Math.min(5000, Math.max(2000, remainingBudget - 1000));
            const { expect, getAssertionCount, getTestResults } = createExpect({ 
                timeout: assertionTimeout,
                deadline: globalDeadline
            });

            contentWindow.expect = expect;
            contentWindow.test = test;

            // Inject console interceptor
            const originalIframeConsole = contentWindow.console;
            contentWindow.console = {
              ...originalIframeConsole,
              ...interceptedConsole
            };

            const wrappedCode = `
                        return (async () => {
                            try {
                                const result = (async () => {
                                    ${executableCode}
                                })();

                                const finalResult = await result;

                                // Wait for all tests to complete
                                if (window.__testPromises && Array.isArray(window.__testPromises)) {
                                    await Promise.all(window.__testPromises);
                                }

                                window.__returnValue = finalResult;
                                return finalResult;
                            } catch (e) {
                                window.__executionError = e.message || String(e);
                                throw e;
                            }
                        })();
                    `;


            let returnValue;
            if (typeof contentWindow.eval === 'function') {
              /* eslint-disable @typescript-eslint/no-unsafe-call, @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-unsafe-member-access */
              returnValue = await contentWindow.eval(
                `(function() { ${wrappedCode} })()`,
              );
              /* eslint-enable @typescript-eslint/no-unsafe-call, @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-unsafe-member-access */
            } else {
              // Fallback for environments without iframe eval (e.g. HappyDOM tests)
              // This runs in parent context, so 'Array' !== iframe.contentWindow.Array
              console.warn(
                'iframe.contentWindow.eval not supported, falling back to new Function() in parent context.',
              );
              // eslint-disable-next-line @typescript-eslint/no-implied-eval
              const fallbackFn = new Function(
                'page',
                'expect',
                'test',
                'window',
                'document',
                'console',
                wrappedCode,
              );
              await fallbackFn(
                page,
                expect,
                test,
                contentWindow,
                enhancedDocument,
                contentWindow.console,
              );
              returnValue = (contentWindow).__returnValue;

            }

            const executionTime = Date.now() - startTime;
            cleanup();

            // Check for soft failures
            const softFailures = getTestResults().filter((r) => !r.passed);
            if (softFailures.length > 0) {
              resolve({
                status: 'FAILED',
                output: `Test failed with ${softFailures.length} soft assertion error(s):\n${softFailures.map((f) => `- ${f.message}`).join('\n')}`,
                executionTime,
                error: softFailures[0].message, // Return first error
                logs,
                assertionCount: getAssertionCount(),
              });
              return;
            }

            // Validate expected DOM state if defined
            if (options?.expectedState && options.expectedState.length > 0) {
              const stateValidation = validateExpectedState(iframeDoc, options.expectedState);
              if (!stateValidation.passed) {
                resolve({
                  status: 'FAILED',
                  output: `DOM State Validation Failed: ${stateValidation.error}`,
                  executionTime,
                  error: stateValidation.error,
                  logs,
                  assertionCount: getAssertionCount(),
                });
                return;
              }
            }

            resolve({
              status: 'PASSED',
              output: 'All steps completed successfully',
              executionTime,
              returnValue,
              logs,
              assertionCount: getAssertionCount(),
            });
          } catch (error) {
            const executionTime = Date.now() - startTime;
            cleanup();

            const errorMessage = formatError(error);
            resolve({
              status: 'FAILED',
              output: errorMessage,
              executionTime,
              error: errorMessage,
              logs,
            });
          }
        };

        if (useExistingIframe) {
          // Execute immediately for existing iframe
          void executeCode();
        } else {
          // Wait for iframe to be ready
          iframe.onload = executeCode;
          // Trigger load event by setting src
          iframe.src = 'about:blank';
        }
      } catch (error) {
        const executionTime = Date.now() - startTime;
        cleanup();

        const errorMessage = formatError(error);
        resolve({
          status: 'ERROR',
          output: `Execution error: ${errorMessage}`,
          executionTime,
          error: errorMessage,
          logs,
        });
      }
    });
  } finally {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    logger.setHandler(null as any);
  }
}

/**
 * Format error messages to be more user-friendly
 */
function formatError(error: unknown): string {
  const msg = error instanceof Error ? error.message : String(error);

  if (msg.includes('Element not found')) {
    return `${msg}\n\n💡 Tip: Check if your selector matches the HTML structure in the Preview tab.`;
  }
  if (msg.includes('Timeout') && msg.includes('waiting')) {
    return `${msg}\n\n💡 Tip: The element might not be visible yet, or the operation took too long.`;
  }
  if (msg.includes('is not defined')) {
    return `${msg}\n\n💡 Tip: You might have a typo in a variable name.`;
  }
  if (msg.includes('Expected')) {
    // Assertion error
    return `${msg}\n\n💡 Tip: Your assertion failed. Check the Expected vs Actual values.`;
  }

  if (msg.includes('Cannot read properties of null')) {
    if (msg.includes('click')) {
      return `${msg}\n\n💡 Tip: You are trying to click on an element that doesn't exist. Check your selector for typos.`;
    }
    return `${msg}\n\n💡 Tip: You are trying to access a property on a null value. Did your selector fail to find an element?`;
  }

  if (msg.includes('Cannot read properties of undefined')) {
    return `${msg}\n\n💡 Tip: You are trying to access a property on an undefined value. Check your logic.`;
  }

  return msg;
}


/**
 * Execute code with multiple test cases
 */
export async function executeWithTestCases(
  code: string,
  htmlContent: string,
  testCases: TestCase[],
  options?: { timeout?: number },
): Promise<{
  overall: ExecutionResult;
  results: TestCaseResult[];
}> {
  const timeout = options?.timeout || 10000;
  const startTime = Date.now();
  const results: TestCaseResult[] = [];

  // First, run the user code
  const codeResult = await executePlaywrightCode(code, htmlContent, {
    timeout,
  });

  if (codeResult.status !== 'PASSED') {
    return {
      overall: codeResult,
      results: testCases.map((tc) => ({
        id: tc.id,
        name: tc.name,
        passed: false,
        error: 'Code execution failed',
      })),
    };
  }

  // Re-run with test case validation
  const iframe = document.createElement('iframe');
  iframe.style.display = 'none';
  document.body.appendChild(iframe);

  try {
    iframe.contentDocument?.open();
    iframe.contentDocument?.write(`
      <!DOCTYPE html>
      <html><body>${htmlContent}</body></html>
    `);
    iframe.contentDocument?.close();

    const page = new MockedPlaywrightPage(iframe.contentDocument!, { timeout });

    // Run user code first
    // eslint-disable-next-line @typescript-eslint/no-implied-eval
    const userFunction = new Function(
      'page',
      'expect',
      `
      return (async () => { ${code} })();
    `,
    );
    // eslint-disable-next-line @typescript-eslint/no-unsafe-call
    await userFunction(page, createExpect());

    // Run test cases
    for (const testCase of testCases) {
      try {
        const passed = await testCase.validate(page);
        results.push({
          id: testCase.id,
          name: testCase.name,
          passed,
        });
      } catch (error) {
        results.push({
          id: testCase.id,
          name: testCase.name,
          passed: false,
          error: error instanceof Error ? error.message : String(error),
        });
      }
    }
  } finally {
    if (iframe.parentNode) {
      document.body.removeChild(iframe);
    }
  }

  const allPassed = results.every((r) => r.passed);
  const executionTime = Date.now() - startTime;

  return {
    overall: {
      status: allPassed ? 'PASSED' : 'FAILED',
      output: allPassed
        ? `All ${results.length} test cases passed`
        : `${results.filter((r) => !r.passed).length} of ${results.length} test cases failed`,
      executionTime,
    },
    results,
  };
}




/**
 * Helper to show iframe preview during development
 */
export function createPreviewIframe(
  htmlContent: string,
  container: HTMLElement,
): { iframe: HTMLIFrameElement; page: MockedPlaywrightPage } {
  const iframe = document.createElement('iframe');
  iframe.style.cssText = `
    width: 100%;
    height: 100%;
    border: none;
    background: white;
  `;

  container.appendChild(iframe);

  iframe.contentDocument?.open();
  iframe.contentDocument?.write(`
    <!DOCTYPE html>
    <html>
      <head>
        <style>
          * { box-sizing: border-box; }
          body { font-family: system-ui, sans-serif; padding: 16px; margin: 0; }
        </style>
      </head>
      <body>${htmlContent}</body>
    </html>
  `);
  iframe.contentDocument?.close();

  const page = new MockedPlaywrightPage(iframe.contentDocument!);

  return { iframe, page };
}

/**
 * Mocked Playwright Shim
 *
 * A client-side compatibility layer that mimics Playwright's API.
 * Runs entirely in the browser using DOM APIs.
 *
 * Based on: docs/TDD.md Section 5.2
 */

import { logger } from '@/lib/logger';

import { ROLE_TO_TAG } from './role-mappings';
import { createShimError } from './shim-errors';
import type {
  FilePayload,
  Locator,
  LocatorOptions,
  ActionOptions,
  ClickOptions,
  FillOptions,
  APIRequestContext,
  APIResponse,
  Route,
  APIRequest,
  Dialog,
  BrowserContext,
  Keyboard,
  Mouse,
  FrameLocator,
  WaitOptions,
} from './shim.types';

/**
 * MockedPlaywrightPage - Implements a subset of Playwright's Page API
 * that works with DOM elements in an iframe.
 */
export class MockedPlaywrightPage {
  private targetDocument: Document;
  private defaultTimeout: number;
  private globalDeadline?: number;
  public request: APIRequestContext;
  public keyboard: Keyboard;
  public mouse: Mouse;
  private currentUrl: string = 'about:blank';
  private _context: BrowserContext;

  private routes: any[] = [];

  // VFS (Virtual File System) for multi-page E2E support
  private vfs: Record<string, string> | null = null;
  // private currentPath: string = '/index.html'; // Unused
  private onNavigate?: (path: string) => void;
  private cssContent?: string;

  constructor(iframeDocument: Document, options?: { timeout?: number; deadline?: number }) {
    this.targetDocument = iframeDocument;
    this.defaultTimeout = options?.timeout || 5000;
    this.globalDeadline = options?.deadline;
    this.request = this._createAPIRequestContext();
    this._context = this._createBrowserContext();
    this.keyboard = this._createKeyboard();
    this.mouse = this._createMouse();
  }

  /**
   * Set up Virtual File System for multi-page navigation
   */
  setVFS(
    files: Record<string, string>,
    options?: {
      onNavigate?: (path: string) => void;
      cssContent?: string;
    },
  ): void {
    // Normalize keys to ensure they start with /
    const normalizedFiles: Record<string, string> = {};
    for (const [key, value] of Object.entries(files)) {
      const normalizedKey = key.startsWith('/') ? key : '/' + key;
      // eslint-disable-next-line security/detect-object-injection
      normalizedFiles[normalizedKey] = value;
    }
    this.vfs = normalizedFiles;
    this.onNavigate = options?.onNavigate;
    this.cssContent = options?.cssContent;
  }

  // ============================================
  // Core Actions
  // ============================================

  private _createKeyboard(): Keyboard {
    const getActiveElement = () =>
      (this.targetDocument.activeElement as HTMLElement) ||
      this.targetDocument.body;

    return {
      down: async (key: string) => {
        logger.debug(`[Keyboard] down: ${key}`);
        const el = getActiveElement();
        el.dispatchEvent(new KeyboardEvent('keydown', { key, bubbles: true }));
        await Promise.resolve(); // satisfying require-await
      },
      up: async (key: string) => {
        logger.debug(`[Keyboard] up: ${key}`);
        const el = getActiveElement();
        el.dispatchEvent(new KeyboardEvent('keyup', { key, bubbles: true }));
        await Promise.resolve(); // satisfying require-await
      },
      insertText: async (text: string) => {
        logger.debug(`[Keyboard] insertText: ${text}`);
        const el = getActiveElement();
        if ('value' in el) {
          (el as HTMLInputElement).value += text;
          el.dispatchEvent(new Event('input', { bubbles: true }));
        } else {
          el.textContent += text;
        }
        await Promise.resolve(); // satisfying require-await
      },
      type: async (text: string, options) => {
        logger.debug(`[Keyboard] type: ${text}`);
        const el = getActiveElement();
        for (const char of text) {
          el.dispatchEvent(
            new KeyboardEvent('keydown', { key: char, bubbles: true }),
          );
          el.dispatchEvent(
            new KeyboardEvent('keypress', { key: char, bubbles: true }),
          );
          if ('value' in el) {
            (el as HTMLInputElement).value += char;
            el.dispatchEvent(new Event('input', { bubbles: true }));
          } else {
            // Very basic contenteditable shim
            el.textContent += char;
          }
          el.dispatchEvent(
            new KeyboardEvent('keyup', { key: char, bubbles: true }),
          );
          if (options?.delay) await this.delay(options.delay);
        }
      },
      press: async (key: string, options) => {
        logger.debug(`[Keyboard] press: ${key}`);
        const el = getActiveElement();
        el.dispatchEvent(new KeyboardEvent('keydown', { key, bubbles: true }));
        el.dispatchEvent(new KeyboardEvent('keypress', { key, bubbles: true }));
        el.dispatchEvent(new KeyboardEvent('keyup', { key, bubbles: true }));
        if (options?.delay) await this.delay(options.delay);
      },
    };
  }

  private _createMouse(): Mouse {
    let x = 0;
    let y = 0;

    return {
      move: async (newX, newY) => {
        // logger.debug(`[Mouse] move: ${newX}, ${newY}`); // Too spammy
        x = newX;
        y = newY;
        const el =
          this.targetDocument.elementFromPoint(x, y) ||
          this.targetDocument.body;
        el.dispatchEvent(
          new MouseEvent('mousemove', {
            clientX: x,
            clientY: y,
            bubbles: true,
            view: this.targetDocument.defaultView,
          }),
        );
        await Promise.resolve();
      },
      down: async (options) => {
        logger.debug(`[Mouse] down`);
        const el =
          this.targetDocument.elementFromPoint(x, y) ||
          this.targetDocument.body;
        el.dispatchEvent(
          new MouseEvent('mousedown', {
            clientX: x,
            clientY: y,
            button: options?.button === 'right' ? 2 : 0,
            bubbles: true,
            view: this.targetDocument.defaultView,
          }),
        );
        await Promise.resolve();
      },
      up: async (options) => {
        logger.debug(`[Mouse] up`);
        const el =
          this.targetDocument.elementFromPoint(x, y) ||
          this.targetDocument.body;
        el.dispatchEvent(
          new MouseEvent('mouseup', {
            clientX: x,
            clientY: y,
            button: options?.button === 'right' ? 2 : 0,
            bubbles: true,
            view: this.targetDocument.defaultView,
          }),
        );
        await Promise.resolve();
      },
      click: async (targetX, targetY, options) => {
        logger.debug(`[Mouse] click at ${targetX},${targetY}`);
        x = targetX;
        y = targetY;
        const el =
          this.targetDocument.elementFromPoint(x, y) ||
          this.targetDocument.body;

        // Highlight target if found
        if (el instanceof HTMLElement) {
          void this._highlight(el, '#3b82f6'); // Blue for mouse click
        }

        el.dispatchEvent(
          new MouseEvent('mousemove', {
            clientX: x,
            clientY: y,
            bubbles: true,
          }),
        );
        el.dispatchEvent(
          new MouseEvent('mousedown', {
            clientX: x,
            clientY: y,
            bubbles: true,
          }),
        );
        el.dispatchEvent(
          new MouseEvent('mouseup', { clientX: x, clientY: y, bubbles: true }),
        );
        el.dispatchEvent(
          new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }),
        );
        if (options?.delay) await this.delay(options.delay);
      },
      dblclick: async (targetX, targetY, options) => {
        logger.debug(`[Mouse] dblclick at ${targetX},${targetY}`);
        x = targetX;
        y = targetY;
        const el =
          this.targetDocument.elementFromPoint(x, y) ||
          this.targetDocument.body;

        if (el instanceof HTMLElement) {
          void this._highlight(el, '#3b82f6');
        }

        el.dispatchEvent(
          new MouseEvent('mousemove', {
            clientX: x,
            clientY: y,
            bubbles: true,
          }),
        );
        el.dispatchEvent(
          new MouseEvent('mousedown', {
            clientX: x,
            clientY: y,
            bubbles: true,
          }),
        );
        el.dispatchEvent(
          new MouseEvent('mouseup', { clientX: x, clientY: y, bubbles: true }),
        );
        el.dispatchEvent(
          new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }),
        );
        el.dispatchEvent(
          new MouseEvent('mousedown', {
            clientX: x,
            clientY: y,
            bubbles: true,
          }),
        );
        el.dispatchEvent(
          new MouseEvent('mouseup', { clientX: x, clientY: y, bubbles: true }),
        );
        el.dispatchEvent(
          new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }),
        );
        el.dispatchEvent(
          new MouseEvent('dblclick', { clientX: x, clientY: y, bubbles: true }),
        );
        if (options?.delay) await this.delay(options.delay);
      },
    };
  }

  /**
   * Handle dialogs
   */
  async on(event: string, handler: (dialog: Dialog) => void): Promise<void> {
    if (event === 'dialog') {
      // Register global handler that iframe logic can call
      /* eslint-disable @typescript-eslint/require-await */
      const iframeWindow = this.targetDocument.defaultView as any;
      if (!iframeWindow) return;

      if (!iframeWindow.__MOCK_DIALOG_HANDLER__) {
        iframeWindow.__MOCK_DIALOG_HANDLER__ = (
          type: string,
          message: string,
          defaultValue?: string,
        ) => {
          return new Promise((resolve) => {
            const dialog: Dialog = {
              type: () => type as any,
              message: () => message,
              defaultValue: () => defaultValue || '',
              accept: async (promptText) => {
                resolve({ action: 'accept', promptText });
              },
              dismiss: async () => {
                resolve({ action: 'dismiss' });
              },
            };
            handler(dialog);
          });
        };
      }
      /* eslint-enable @typescript-eslint/require-await */
    }
    await Promise.resolve();
  }

  /**
   * Visual feedback helper
   * Highlights an element briefly to show interaction
   */
  private async _highlight(
    element: HTMLElement,
    color = '#dc2626',
  ): Promise<void> {
    // Skip if document is hidden or detached (safety check)
    if (!element.isConnected) return;

    const originalTransition = element.style.transition;
    const originalOutline = element.style.outline;
    const originalBoxShadow = element.style.boxShadow;

    // Apply highlight
    element.style.transition = 'all 0.1s ease';
    element.style.outline = `2px solid ${color}`;
    element.style.boxShadow = `0 0 0 4px ${color}40`; // 40 is alpha for hex

    // Wait a bit so user sees it
    await this.delay(300);

    // Restore
    element.style.outline = originalOutline;
    element.style.boxShadow = originalBoxShadow;
    element.style.transition = originalTransition;
  }

  async route(
    urlOrPredicate: string | RegExp | ((url: URL) => boolean),
    handler: (route: Route, request: APIRequest) => Promise<void> | void,
  ): Promise<void> {
    // Register route in global registry on the iframe window
    // The iframe fetch polyfill will read from this
    /* eslint-disable @typescript-eslint/require-await */
    const iframeWindow = this.targetDocument.defaultView as any;
    if (!iframeWindow) return;

    if (!iframeWindow.__MOCK_FETCH_PATCHED__) {
      iframeWindow.__MOCK_FETCH_PATCHED__ = true;
      const originalFetch = iframeWindow.fetch;
      iframeWindow.fetch = (input: any, init: any) => {
        let url = input;
        if (typeof input === 'string') {
          if (input.startsWith('/')) {
            url = 'http://localhost' + input;
          }
        } else if (input instanceof Request) {
          url = input.url;
        } else if (input && typeof input === 'object' && 'toString' in input) {
          url = input.toString();
        }

        if (iframeWindow.__MOCK_ROUTES__) {
          for (const route of iframeWindow.__MOCK_ROUTES__) {
            let isMatch = false;
            if (typeof route.matcher === 'string') {
              isMatch = url.includes(route.matcher);
            } else if (route.matcher instanceof RegExp) {
              isMatch = route.matcher.test(url);
            } else if (typeof route.matcher === 'function') {
              try {
                isMatch = route.matcher(new URL(url as string));
              } catch {
                isMatch = false;
              }
            }

            if (isMatch) {
              return route
                .handler({
                  url,
                  method: init?.method || 'GET',
                  headers: init?.headers,
                  body: init?.body,
                })
                .then((r: any) => {
                  if (r?.type === 'fulfill') {
                    return Promise.resolve({
                      ok:
                        (r.response.status || 200) >= 200 &&
                        (r.response.status || 200) < 300,
                      status: r.response.status || 200,
                      statusText: r.response.statusText || 'OK',
                      json: () =>
                        Promise.resolve(
                          r.response.json ||
                            (r.response.body ? JSON.parse(r.response.body) : {}),
                        ),
                      text: () =>
                        Promise.resolve(
                          r.response.body || JSON.stringify(r.response.json || {}),
                        ),
                      arrayBuffer: () =>
                        Promise.resolve(
                          new TextEncoder().encode(
                            r.response.body || JSON.stringify(r.response.json || {}),
                          ).buffer,
                        ),
                      headers: new Headers(
                        (r.response.headers as HeadersInit) || {},
                      ),
                    });
                  }
                  return Promise.reject(new Error('Route not fulfilled'));
                });
            }
          }
        }
        return originalFetch
          ? originalFetch(input, init)
          : Promise.resolve({ ok: false, status: 404 });
      };
    }

    const routeEntry = {
      matcher: urlOrPredicate,
      handler: async (requestInfo: any) => {
        const route: Route = {
          fulfill: async (response) => {
            return Promise.resolve(response) as any;
          },
          continue: async (options) => {
            return Promise.resolve(options) as any;
          },
          request: () => ({
            url: () => requestInfo.url,
            method: () => requestInfo.method,
            headers: () => requestInfo.headers,
            postData: () => requestInfo.body,
          }),
        };

        const request: APIRequest = route.request();

        return new Promise<any>((resolve) => {
          // Override fulfill/continue to resolve our promise
          route.fulfill = async (response) => {
            resolve({ type: 'fulfill', response });
          };
          route.continue = async (options) => {
            resolve({ type: 'continue', options });
          };

          // eslint-disable-next-line @typescript-eslint/no-floating-promises
          handler(route, request);
        });
      },
    };

    this.routes.push(routeEntry);

    if (!iframeWindow.__MOCK_ROUTES__) {
      iframeWindow.__MOCK_ROUTES__ = [];
    }
    iframeWindow.__MOCK_ROUTES__.push(routeEntry);
    /* eslint-enable @typescript-eslint/require-await */
    await Promise.resolve();
  }

  async unroute(
    urlOrPredicate: string | RegExp | ((url: URL) => boolean),
  ): Promise<void> {

    const iframeWindow = this.targetDocument.defaultView as any;
    if (!iframeWindow || !iframeWindow.__MOCK_ROUTES__) return;

    // Remove matching routes
    this.routes = this.routes.filter(
      (r: any) => r.matcher.toString() !== urlOrPredicate.toString(),
    );

    iframeWindow.__MOCK_ROUTES__ = iframeWindow.__MOCK_ROUTES__.filter(
      (r: any) => r.matcher.toString() !== urlOrPredicate.toString(),
    );

    await Promise.resolve();
  }

  async goto(url: string): Promise<void> {
    logger.debug(`Navigating to ${url}`);

    // Normalize URL to path
    let path = url;
    if (url.startsWith('http')) {
      try {
        path = new URL(url).pathname;
      } catch {
        // If URL parsing fails, use as-is
      }
    }
    if (!path.startsWith('/')) {
      path = '/' + path;
    }

    // VFS Mode: Replace iframe content with virtual file
    if (this.vfs) {
      // eslint-disable-next-line security/detect-object-injection
      const content = this.vfs[path];
      if (!content) {
        throw new Error(`Page not found in VFS: ${path}. Available pages: ${Object.keys(this.vfs).join(', ')}`);
      }

      // Save state that must persist across page navigations

      const oldWin = this.targetDocument.defaultView as any;
      const preservedAppState = oldWin?.__APP_STATE__ || {};

      // Wrap content with necessary HTML structure including restored state
      const wrappedHtml = this._wrapVfsContent(content, preservedAppState);

      // Update iframe content
      this.targetDocument.open();
      this.targetDocument.write(wrappedHtml);
      this.targetDocument.close();

      // Restore window references BEFORE executing scripts so app scripts can access state
      if (this.targetDocument.defaultView) {

        const win = this.targetDocument.defaultView as any;
        win.page = this;
        // Re-inject active routes
        win.__MOCK_ROUTES__ = this.routes;
        // Restore persisted app state across navigation (redundant but safe)
        win.__APP_STATE__ = preservedAppState;
      }

      // Re-execute scripts in new content (now with __APP_STATE__ available)
      this._executeScripts();

      this.currentUrl = path;

      // Notify parent about navigation for URL bar update
      this.onNavigate?.(path);

      // Artificial delay to allow TestApp scripts (like localStorage checks) to settle
      await this.delay(50);
      return;
    }

    // Legacy mode (no VFS) - just update URL tracking
    this.currentUrl = url;
    await this.delay(50);
  }

  /**
   * Wrap VFS content with full HTML structure including styles and polyfills
   */
  private _wrapVfsContent(content: string, appState: any = {}): string {
    const appStateScript = `
      <script>
        // Restore persisted app state immediately
        window.__APP_STATE__ = ${JSON.stringify(appState)};
      </script>
    `;

    return `
      <!DOCTYPE html>
      <html>
      <head>
        <meta charset="utf-8">
        <base href="http://localhost/" />
        ${appStateScript}
        <style>
          * { box-sizing: border-box; }
          body { 
            font-family: system-ui, sans-serif; 
            padding: 16px;
            margin: 0;
          }
          ${this.cssContent || ''}
        </style>
        <script data-internal="true">
          (function() {
            if (window['__tweVfsPolyfillInstalled']) return;
            window['__tweVfsPolyfillInstalled'] = true;

            // Polyfill fetch to handle mock routes

            window.fetch = function(input, init) {
              let url = input;
              if (typeof input === 'string') {
                if (input.startsWith('/')) {
                  url = 'http://localhost' + input;
                }
              } else if (input instanceof Request) {
                url = input.url;
              } else if (input && typeof input === 'object' && 'toString' in input) {
                 url = input.toString();
              }

              if (window.__MOCK_ROUTES__) {
                for (const route of window.__MOCK_ROUTES__) {
                  let isMatch = false;
                  if (typeof route.matcher === 'string') {
                    isMatch = url.includes(route.matcher);
                  } else if (route.matcher instanceof RegExp) {
                    isMatch = route.matcher.test(url);
                  }
                  if (isMatch) {
                    return route.handler({ url, method: init?.method || 'GET' }).then(r => {
                      if (r?.type === 'fulfill') {
                        return Promise.resolve({
                          ok: (r.response.status || 200) >= 200 && (r.response.status || 200) < 300,
                        status: r.response.status || 200,
                        json: () => Promise.resolve(r.response.json || {}),
                        text: () => Promise.resolve(r.response.body || '')
                      });
                    }
                    return Promise.reject(new Error('Route not fulfilled'));
                  });
                }
              }
            }
            return Promise.resolve({ ok: true, status: 404, json: () => Promise.resolve({}) });
          };

          // Define VFS Navigation Helper
          window.__VFS_NAVIGATE__ = function(path) {
            // console.log('[VFS] Navigating to ' + path);
            if (window.page) {
                window.page.goto(path).catch(e => console.error('Navigation failed:', e));
            } else {
                console.error('window.page not found for VFS navigation');
            }
          };

          // Handle navigation for VFS
          window.addEventListener('click', function(e) {
            const link = e.target.closest('a[href]');
            if (link && !link.getAttribute('target')) {
              const href = link.getAttribute('href');
              if (href && (href.startsWith('/') || href.endsWith('.html'))) {
                e.preventDefault();
                // VFS navigation will be handled by the shim via location change detection
                window.__VFS_NAVIGATE__ && window.__VFS_NAVIGATE__(href);
              }
            }
          }, true);

          // Handle form submission for VFS
          window.addEventListener('submit', function(e) {
            const form = e.target;
            const action = form.getAttribute('action');
            if (action && (action.startsWith('/') || action.endsWith('.html'))) {
              e.preventDefault();
              window.__VFS_NAVIGATE__ && window.__VFS_NAVIGATE__(action);
            }
          }, true);
          })();
        </script>
      </head>
      <body>${content}</body>
      </html>
    `;
  }

  /**
   * Re-execute scripts after VFS page navigation
   */
  private _executeScripts(): void {
    const scripts = Array.from(
      this.targetDocument.querySelectorAll('script'),
    );

    scripts.forEach((script) => {
      if (script.textContent) {
        try {

          const win = this.targetDocument.defaultView as any;
          if (!win) return;

          // eslint-disable-next-line @typescript-eslint/no-implied-eval
          const fn = new Function('window', 'document', `
            return (function(window, document) {
              try {
                ${script.textContent}
              } catch(err) {
                console.error('Error in VFS script:', err);
              }
            }).call(window, window, document);
          `);

          fn(win, this.targetDocument);
        } catch (e) {
          console.error('Failed to execute VFS script:', e);
        }
      }
    });

    // Re-attach onclick handlers for VFS pages (was missing, causing issues in multi-page challenges)
    this._attachOnclickHandlers();
  }

  /**
   * Manually attach onclick handlers for elements with the attribute
   * This is required because HappyDOM/iframe.write() doesn't always 
   * wire up inline attributes to the correctly scoped window.
   */
  private _attachOnclickHandlers(): void {
    const elementsWithClick = Array.from(
      this.targetDocument.querySelectorAll('[onclick]'),
    );
    elementsWithClick.forEach((el) => {
      const handlerCode = el.getAttribute('onclick');
      if (handlerCode) {
        try {

          const win = this.targetDocument.defaultView as any;
          if (!win) return;

          const windowFuncs = Object.keys(win).filter(
            (key) =>
              typeof win[key] === 'function' &&
              ![
                'fetch',
                'setTimeout',
                'setInterval',
                'clearTimeout',
                'clearInterval',
                '__MOCK_ROUTES__',
                '__VFS_NAVIGATE__',
                'page'
              ].includes(key),
          );

          const funcDestructure =
            windowFuncs.length > 0
              ? `const { ${windowFuncs.join(', ')} } = window;`
              : '';

          const code = `
            const fetch = window.fetch;
            ${funcDestructure}
            return (function(window, document, event) {
                try {
                    ${handlerCode}
                } catch(err) {
                    console.error('Error in VFS onclick handler:', err);
                }
            }).call(this, window, document, event);
          `;

          // eslint-disable-next-line @typescript-eslint/no-implied-eval
          const fn = new Function('window', 'document', 'event', code);

          el.addEventListener('click', (event) => {
            fn.call(el, win, this.targetDocument, event);
          });
          // Remove attribute to prevent double-execution in real browsers
          el.removeAttribute('onclick');
        } catch (e) {
          console.error('Failed to attach VFS onclick handler:', e);
        }
      }
    });
  }

  url(): string {
    return this.currentUrl;
  }

  async reload(): Promise<void> {
    logger.debug('Reloading page');
    this.targetDocument.location.reload();
    await this.delay(100);
  }

  async goBack(): Promise<void> {
    logger.debug('Navigating back');
    this.targetDocument.defaultView?.history.back();
    await this.delay(100);
  }

  async goForward(): Promise<void> {
    logger.debug('Navigating forward');
    this.targetDocument.defaultView?.history.forward();
    await this.delay(100);
  }

  async evaluate<R, Arg>(
    pageFunction: ((arg: Arg) => R | Promise<R>) | string,
    arg?: Arg,
  ): Promise<R> {

    const iframeWindow = this.targetDocument.defaultView as any;
    if (!iframeWindow) throw new Error('Iframe window not available');

    if (typeof pageFunction === 'function') {
      // Execute in the context of the iframe window
      // Note: Arrow functions will still capture parent context, but this is the best we can do without eval
      return Promise.resolve(pageFunction.call(iframeWindow, arg as Arg));
    }
    if (typeof pageFunction === 'string') {
      // eslint-disable-next-line @typescript-eslint/no-implied-eval
      const fn = new Function('window', 'document', 'arg', `return (async () => { ${pageFunction} })(arg)`);

      return fn(iframeWindow, this.targetDocument, arg);
    }
    throw new Error('evaluate only supports functions or strings');
  }

  async click(selector: string): Promise<void> {
    // Auto-wait for element to be visible
    await this.waitForSelector(selector, { state: 'visible' });

    const element = this.targetDocument.querySelector(selector) as HTMLElement;
    if (!element)
      throw createShimError('element_not_found', { selector, action: 'click' });

    logger.debug(`[Action] click selector: ${selector}`);
    await this._highlight(element);
    element.click();
  }

  async dblclick(selector: string): Promise<void> {
    await this.waitForSelector(selector, { state: 'visible' });
    const element = this.targetDocument.querySelector(selector) as HTMLElement;
    if (!element) throw createShimError('element_not_found', { selector, action: 'dblclick' });
    element.dispatchEvent(
      new MouseEvent('dblclick', {
        bubbles: true,
        cancelable: true,
        view: window,
      }),
    );
  }

  async focus(selector: string): Promise<void> {
    await this.waitForSelector(selector, { state: 'visible' });
    const element = this.targetDocument.querySelector(selector) as HTMLElement;
    if (!element) throw createShimError('element_not_found', { selector, action: 'focus' });
    element.focus();
  }

  async dispatchEvent(
    selector: string,
    type: string,
    eventInit?: CustomEventInit,
  ): Promise<void> {
    await this.waitForSelector(selector, { state: 'visible' });
    const element = this.targetDocument.querySelector(selector) as HTMLElement;
    if (!element) throw createShimError('element_not_found', { selector, action: 'dispatchEvent' });
    element.dispatchEvent(
      new CustomEvent(type, { bubbles: true, cancelable: true, ...eventInit }),
    );
  }

  /**
   * Fill an input or textarea with text
   */
  async fill(selector: string, value: string): Promise<void> {
    // Auto-wait for element to be visible
    await this.waitForSelector(selector, { state: 'visible' });

    const element = this.targetDocument.querySelector(selector) as
      | HTMLInputElement
      | HTMLTextAreaElement;

    if (!element) throw createShimError('element_not_found', { selector, action: 'fill' });
    if (!('value' in element)) {
      throw createShimError('invalid_element_type', {
        selector,
        action: 'fill',
        elementType: (element as HTMLElement).tagName?.toLowerCase() || 'unknown',
        hint: 'input or textarea'
      });
    }

    element.focus();
    element.value = value;
    element.dispatchEvent(new Event('input', { bubbles: true }));
    element.dispatchEvent(new Event('change', { bubbles: true }));
  }

  /**
   * Check a checkbox or radio button
   */
  async check(selector: string): Promise<void> {
    await this.waitForSelector(selector, { state: 'visible' });
    const element = this.targetDocument.querySelector(
      selector,
    ) as HTMLInputElement;

    if (!element) throw createShimError('element_not_found', { selector, action: 'check' });
    if (element.type !== 'checkbox' && element.type !== 'radio') {
      throw createShimError('invalid_element_type', {
        selector,
        action: 'check',
        elementType: element.type || element.tagName.toLowerCase(),
        hint: 'checkbox or radio'
      });
    }

    if (!element.checked) {
      element.click();
    }
  }

