import { describe, it, expect as bunExpect } from 'bun:test';
import { createExpect } from './expect-matchers';

// Mock implementation of the IFrame Executor logic
async function simulateExecutor(userCodeFn: (test: any, expect: any) => void) {
    const { expect, getAssertionCount, cleanup } = createExpect({ timeout: 100 });
    const contentWindow: any = { __testPromises: [] };
    const interceptedConsole = { error: (msg: string) => console.error(msg) };

    const test = (name: string, callback: (args: any) => Promise<void>) => {
        const testPromise = (async () => {
            try {
                await callback({ page: {}, expect });
            } catch (error) {
                // console.error(`[Step] ${name} FAILED: ${String(error)}`);
                throw error;
            }
        })();
        if (Array.isArray(contentWindow.__testPromises)) {
            contentWindow.__testPromises.push(testPromise);
        }
        return testPromise;
    };

    // User code execution (sync usually, starts tests)
    // For top-level await simulation, we await it.
    await userCodeFn(test, expect);

    // Executor wait loop (simulates wrappedCode)
    try {
        if (contentWindow.__testPromises && Array.isArray(contentWindow.__testPromises)) {
            await Promise.all(contentWindow.__testPromises);
        }

        cleanup();
        return { status: 'PASSED', count: getAssertionCount() };
    } catch (e) {
        console.error('Executor Caught Error:', e);
        cleanup();
        return { status: 'FAILED', count: getAssertionCount(), error: e };
    }
}

describe('Executor Logic with Wrapper', () => {
    it('captures assertions inside test wrapper', async () => {
        const result = await simulateExecutor((test, expect) => {
            test('wrapped test', async ({ expect }: any) => {
                try {
                    await expect('actual').toHaveText('actual', { timeout: 50 });
                } catch(e) { console.error('Test Internal Error:', e); throw e; }
            });
        });

        if (result.status === 'FAILED') console.log('Result Error:', result.error);
        bunExpect(result.status).toBe('PASSED');
        bunExpect(result.count).toBeGreaterThan(0);
    });

    it('captures failure inside test wrapper', async () => {
        const result = await simulateExecutor((test, expect) => {
            test('wrapped failing test', async ({ expect }: any) => {
                await expect('actual').toHaveText('mismatch', { timeout: 50 });
            });
        });

        bunExpect(result.status).toBe('FAILED');
        bunExpect(result.count).toBeGreaterThan(0);
    });

    it('captures assertions at top level (unwrapped)', async () => {
        const result = await simulateExecutor(async (test, expect) => {
             await expect('actual').toHaveText('actual', { timeout: 50 });
        });

        bunExpect(result.status).toBe('PASSED');
        bunExpect(result.count).toBeGreaterThan(0);
    });
});

/**
 * Shim Error Factory
 * 
 * Generates consistent, descriptive error messages for the Playwright shim.
 * Modeled after real Playwright error patterns.
 */

/**
 * All possible error types thrown by the shim
 */
export type ShimErrorType =
    | 'element_not_found'
    | 'element_not_visible'
    | 'element_not_interactive'
    | 'element_detached'
    | 'element_disabled'
    | 'strict_mode_violation'
    | 'timeout'
    | 'assertion_failed'
    | 'invalid_element_type';

/**
 * Options for creating a shim error
 */
export interface ShimErrorOptions {
    /** The CSS selector or locator description */
    selector?: string;
    /** The action being performed (e.g., 'click', 'fill') */
    action?: string;
    /** Expected value for assertions */
    expected?: unknown;
    /** Actual value for assertions */
    actual?: unknown;
    /** Timeout value in milliseconds */
    timeout?: number;
    /** The actual element type found (e.g., 'div' instead of 'checkbox') */
    elementType?: string;
    /** Number of elements matched (for strict mode violations) */
    matchCount?: number;
    /** Additional context or hints */
    hint?: string;
}

/**
 * Error message templates for each error type
 */
const ERROR_TEMPLATES: Record<ShimErrorType, (opts: ShimErrorOptions) => string> = {
    element_not_found: (opts) =>
        `${opts.action ? `locator.${opts.action}: ` : ''}Error: Element not found.${opts.selector ? ` Selector: '${opts.selector}'` : ''
        }${opts.hint ? `\n${opts.hint}` : ''}`,

    element_not_visible: (opts) =>
        `${opts.action ? `locator.${opts.action}: ` : ''}Error: Element is hidden.${opts.selector ? ` Selector: '${opts.selector}'` : ''
        }${opts.hint ? `\n${opts.hint}` : ''}`,

    element_not_interactive: (opts) =>
        `${opts.action ? `locator.${opts.action}: ` : ''}Error: Element is not interactable.${opts.selector ? ` Selector: '${opts.selector}'` : ''
        }${opts.hint ? `\n${opts.hint}` : ''}`,

    element_detached: (opts) =>
        `${opts.action ? `locator.${opts.action}: ` : ''}Error: Element was detached from the DOM during action.${opts.selector ? ` Selector: '${opts.selector}'` : ''
        }${opts.hint ? `\n${opts.hint}` : '\nThis usually happens when the page navigates or the element is dynamically removed.'}`,

    element_disabled: (opts) =>
        `${opts.action ? `locator.${opts.action}: ` : ''}Error: Element is disabled.${opts.selector ? ` Selector: '${opts.selector}'` : ''
        }${opts.hint ? `\n${opts.hint}` : ''}`,

    strict_mode_violation: (opts) =>
        `${opts.action ? `locator.${opts.action}: ` : ''}Error: Strict mode violation: ` +
        `selector '${opts.selector || 'unknown'}' resolved to ${opts.matchCount || 'multiple'} elements.` +
        `\nUse .nth(), .first(), .last(), or a more specific selector.`,

    timeout: (opts) =>
        `${opts.action ? `locator.${opts.action}: ` : ''}Timeout ${opts.timeout || 'unknown'}ms exceeded` +
        `${opts.selector ? ` waiting for selector '${opts.selector}'` : ''}` +
        `${opts.hint ? ` ${opts.hint}` : ''}`,

    assertion_failed: (opts) => {
        const expected = typeof opts.expected === 'string' ? `"${opts.expected}"` : String(opts.expected);
        const actual = typeof opts.actual === 'string' ? `"${opts.actual}"` : String(opts.actual);
        return `${opts.action ? `expect(locator).${opts.action}: ` : ''}` +
            `Expected ${expected} but got ${actual}.` +
            `${opts.selector ? ` Selector: '${opts.selector}'` : ''}`;
    },

    invalid_element_type: (opts) =>
        `${opts.action ? `locator.${opts.action}: ` : ''}Error: Expected ${opts.hint || 'specific element type'
        } but got '${opts.elementType || 'unknown'}'.${opts.selector ? ` Selector: '${opts.selector}'` : ''
        }`,
};

/**
 * Creates a standardized error with a descriptive message
 * 
 * @example
 * throw createShimError('element_not_found', { 
 *   selector: '#submit-btn', 
 *   action: 'click' 
 * });
 * // => "locator.click: Error: Element not found. Selector: '#submit-btn'"
 */
export function createShimError(
    type: ShimErrorType,
    options: ShimErrorOptions = {}
): Error {
    const template = ERROR_TEMPLATES[type];
    const message = template(options);

    const error = new Error(message);
    error.name = `PlaywrightShimError`;

    // Attach metadata for programmatic access
    (error as any).type = type;
    (error as any).selector = options.selector;
    (error as any).action = options.action;

    return error;
}

/**
 * Type guard to check if an error is a ShimError
 */
export function isShimError(error: unknown): error is Error & { type: ShimErrorType } {
    return error instanceof Error && 'type' in error;
}

export interface FilePayload {
    name: string;
    mimeType: string;
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    buffer: any;
}

/**
 * Options for action methods like click, fill, check, etc.
 * Modeled after Playwright's action options.
 */
export interface ActionOptions {
    /** Maximum time in milliseconds. Defaults to 2500ms. */
    timeout?: number;
    /** Bypasses actionability checks. Use with caution. */
    force?: boolean;
    /** Do not wait for the action to complete before continuing. */
    noWaitAfter?: boolean;
    /** Absolute timestamp (ms) to force early timeout. */
    deadline?: number;
}

/**
 * Extended options for click actions.
 */
export interface ClickOptions extends ActionOptions {
    /** Clicks on the element at the specified position. */
    position?: { x: number; y: number };
    /** Number of clicks. Defaults to 1. */
    clickCount?: number;
    /** Time to wait between mousedown and mouseup in milliseconds. */
    delay?: number;
}

/**
 * Extended options for fill actions.
 */
export interface FillOptions extends ActionOptions {
    /** Focus the element before filling. Defaults to true. */
    focus?: boolean;
}

export interface Locator {
    click(options?: ClickOptions): Promise<void>;
    dblclick(options?: ClickOptions): Promise<void>;
    fill(value: string, options?: FillOptions): Promise<void>;
    textContent(): Promise<string | null>;
    inputValue(): Promise<string>;
    isVisible(): Promise<boolean>;
    isChecked(): Promise<boolean>;
    isDisabled(): Promise<boolean>;
    isEditable(): Promise<boolean>;
    check(options?: ActionOptions): Promise<void>;
    uncheck(options?: ActionOptions): Promise<void>;
    selectOption(value: string | string[], options?: ActionOptions): Promise<void>;
    getAttribute(name: string): Promise<string | null>;
    innerHTML(): Promise<string>;
    count(): Promise<number>;
    first(): Locator;
    last(): Locator;
    nth(index: number): Locator;
    focus(options?: ActionOptions): Promise<void>;
    blur(options?: ActionOptions): Promise<void>;
    clear(options?: ActionOptions): Promise<void>;
    dispatchEvent(type: string, eventInit?: CustomEventInit): Promise<void>;
    setInputFiles(files: FilePayload | FilePayload[], options?: ActionOptions): Promise<void>;
    dragTo(target: Locator, options?: ActionOptions): Promise<void>;
    dragAndDrop(target: Locator, options?: ActionOptions): Promise<void>;
    press(key: string, options?: ActionOptions): Promise<void>;
    evaluate<R, Arg>(
        pageFunction: (element: HTMLElement, arg: Arg) => R | Promise<R>,
        arg?: Arg,
    ): Promise<R>;
    locator(
        selector: string,
        options?: { hasText?: string | RegExp; has?: Locator },
    ): Locator;
    filter(options: { hasText?: string | RegExp; has?: Locator }): Locator;
    all(): Promise<Locator[]>;
    allTextContents(): Promise<string[]>;
    elementHandles(): Promise<HTMLElement[]>; // Internal helper exposed for filter({ has })
    getByRole(role: string, options?: LocatorOptions): Locator;
    getByText(text: string | RegExp, options?: { exact?: boolean }): Locator;
    getByLabel(text: string | RegExp, options?: { exact?: boolean }): Locator;
    getByPlaceholder(
        text: string | RegExp,
        options?: { exact?: boolean },
    ): Locator;
    getByTestId(testId: string): Locator;
    hover(options?: ActionOptions & { position?: { x: number; y: number } }): Promise<void>;
    waitFor(options?: {
        state?: 'attached' | 'detached' | 'visible' | 'hidden';
        timeout?: number;
    }): Promise<void>;
}

export interface LocatorOptions {
    name?: string | RegExp;
    exact?: boolean;
    checked?: boolean;
    disabled?: boolean;
    expanded?: boolean;
    pressed?: boolean;
    selected?: boolean;
    level?: number;
    includeHidden?: boolean;
}

