                                <div className="space-y-2">
                                    <Label htmlFor="message">{t('contact.form.message')}</Label>
                                    <Textarea
                                        id="message"
                                        name="message"
                                        required
                                        placeholder="Tell me about what's your inquiry..."
                                        className="min-h-[150px]"
                                    />
