import { createFileRoute, redirect } from '@tanstack/react-router';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { getAdminBugs, updateBugStatus } from '@/server/admin.fn';
import { Card, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { ArrowLeft, AlertTriangle } from 'lucide-react';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import { Link } from '@tanstack/react-router';
import { Button } from '@/components/ui/button';
import { toast } from 'sonner';
import { useState, useMemo, useEffect } from 'react';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from '@/components/ui/dialog';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { DataTablePagination } from '@/components/admin/data-table-pagination';

type BugStatus =
  | 'NEW'
  | 'OPEN'
  | 'IN_PROGRESS'
  | 'RESOLVED'
  | 'CLOSED'
  | 'WONT_FIX';

export const Route = createFileRoute('/admin/bugs')({
  component: BugManager,
});

function BugManager() {
  const queryClient = useQueryClient();
  const [selectedBug, setSelectedBug] = useState<BugReport | null>(null);
  const [adminNote, setAdminNote] = useState('');
  const [status, setStatus] = useState<BugStatus>('OPEN');
  const [isOpen, setIsOpen] = useState(false);
  const [currentPage, setCurrentPage] = useState(1);
  const [pageSize, setPageSize] = useState(10);

  const { data: bugs, isLoading } = useQuery({
    queryKey: ['admin-bugs'],
    queryFn: async () => {
      const res = await getAdminBugs();
      if (!res.success) throw new Error(res.error || 'Failed to fetch bugs');
      return res.data;
    },
  });

  type BugReport = NonNullable<typeof bugs>[number];

  const totalPages = Math.ceil((bugs?.length || 0) / pageSize);
  const paginatedBugs = useMemo(() => {
    if (!bugs) return [];
    const start = (currentPage - 1) * pageSize;
    return bugs.slice(start, start + pageSize);
  }, [bugs, currentPage, pageSize]);

  const updateMutation = useMutation({
    mutationFn: async (data: {
      id: string;
      status?: BugStatus;
      adminNotes?: string;
    }) => {
      const res = await updateBugStatus({ data });
      if (!res.success) throw new Error(res.error || 'Failed to update bug');
      return res;
    },
    onSuccess: async () => {
      await queryClient.invalidateQueries({ queryKey: ['admin-bugs'] });
      toast.success('Bug report updated successfully');
      setIsOpen(false);
    },
    onError: () => {
      toast.error('Failed to update bug report');
    },
  });

  const handleEdit = (bug: BugReport) => {
    setSelectedBug(bug);
    setAdminNote(bug.adminNotes || '');
    setStatus(bug.status);
    setIsOpen(true);
  };

  const handleSave = () => {
    if (!selectedBug) return;
    updateMutation.mutate({
      id: selectedBug.id,
      status: status,
      adminNotes: adminNote,
    });
  };

  if (isLoading) return <div className="p-8 text-center">Loading bugs...</div>;

  return (
    <div className="container mx-auto p-6 space-y-8 animate-fade-in">
      <div className="flex items-center gap-4">
        <Link to="/admin">
          <Button variant="ghost" size="icon">
            <ArrowLeft className="h-4 w-4" />
          </Button>
        </Link>
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Bug Reports</h1>
          <p className="text-muted-foreground mt-1">
            Manage user-submitted issues.
          </p>
        </div>
      </div>

      <Card>
        <CardContent className="p-0">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Status</TableHead>
                <TableHead>Severity</TableHead>
                <TableHead>Title</TableHead>
                <TableHead>Reporter</TableHead>
                <TableHead>Date</TableHead>
                <TableHead className="text-right">Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {paginatedBugs.length === 0 ? (
                <TableRow>
                  <TableCell
                    colSpan={6}
                    className="text-center h-24 text-muted-foreground"
                  >
                    No bug reports found.
                  </TableCell>
                </TableRow>
              ) : (
                paginatedBugs.map((bug) => (
                  <TableRow key={bug.id}>
                    <TableCell>
                      <StatusBadge status={bug.status} />
                    </TableCell>
                    <TableCell>
                      <SeverityBadge severity={bug.severity} />
                    </TableCell>
                    <TableCell
                      className="font-medium max-w-[300px] truncate"
                      title={bug.title}
                    >
                      {bug.title}
                    </TableCell>
                    <TableCell>
                      <div className="flex items-center gap-2">
                        {bug.user?.image && (
                          <img
                            src={bug.user.image}
                            className="h-5 w-5 rounded-full"
                          />
                        )}
                        <span className="text-sm">
                          {bug.user?.name || bug.reporterEmail || 'Anonymous'}
                        </span>
                      </div>
                    </TableCell>
                    <TableCell className="text-muted-foreground text-sm">
                      {new Date(bug.createdAt).toLocaleDateString()}
                    </TableCell>
                    <TableCell className="text-right">
                      <Button
                        variant="outline"
                        size="sm"
                        onClick={() => handleEdit(bug)}
                      >
                        Manage
                      </Button>
                    </TableCell>
                  </TableRow>
                ))
              )}
            </TableBody>
          </Table>
          <DataTablePagination
            currentPage={currentPage}
            totalPages={totalPages}
            pageSize={pageSize}
            setPageSize={setPageSize}
            onPageChange={setCurrentPage}
            totalItems={bugs?.length || 0}
          />
        </CardContent>
      </Card>

      <Dialog open={isOpen} onOpenChange={setIsOpen}>
        <DialogContent className="sm:max-w-[600px]">
          {selectedBug && (
            <>
              <DialogHeader>
                <DialogTitle>Manage Bug Report</DialogTitle>
                <DialogDescription>
                  Reported by{' '}
                  {selectedBug.user?.name ||
                    selectedBug.reporterEmail ||
                    'Anonymous'}{' '}
                  on {new Date(selectedBug.createdAt).toLocaleDateString()}
                </DialogDescription>
              </DialogHeader>

              <div className="grid gap-4 py-4 max-h-[60vh] overflow-y-auto pr-2">
                <div className="space-y-2">
                  <Label className="font-semibold">Title</Label>
                  <div className="border p-2 rounded-md bg-muted/50 text-sm">
                    {selectedBug.title}
                  </div>
                </div>

                <div className="space-y-2">
                  <Label className="font-semibold">Steps to Reproduce</Label>
                  <div className="border p-2 rounded-md bg-muted/50 text-sm whitespace-pre-wrap">
                    {selectedBug.stepsToReproduce}
                  </div>
                </div>

                {selectedBug.expectedBehavior && (
                  <div className="space-y-2">
                    <Label className="font-semibold">Expected Behavior</Label>
                    <div className="border p-2 rounded-md bg-muted/50 text-sm whitespace-pre-wrap">
                      {selectedBug.expectedBehavior}
                    </div>
                  </div>
                )}

                {selectedBug.actualBehavior && (
                  <div className="space-y-2">
                    <Label className="font-semibold">Actual Behavior</Label>
                    <div className="border p-2 rounded-md bg-muted/50 text-sm whitespace-pre-wrap">
                      {selectedBug.actualBehavior}
                    </div>
                  </div>
                )}

                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <Label>Status</Label>
                    <Select
                      value={status}
                      onValueChange={(value) => setStatus(value as BugStatus)}
                    >
                      <SelectTrigger>
                        <SelectValue placeholder="Select status" />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="NEW">New</SelectItem>
                        <SelectItem value="IN_PROGRESS">In Progress</SelectItem>
                        <SelectItem value="RESOLVED">Resolved</SelectItem>
                        <SelectItem value="CLOSED">
                          Closed (Won't Fix)
                        </SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                </div>

                <div className="space-y-2">
                  <Label>Admin Notes</Label>
                  <Textarea
                    value={adminNote}
                    onChange={(e) => setAdminNote(e.target.value)}
                    placeholder="Internal notes about resolution..."
                    className="min-h-[100px]"
                  />
                </div>
              </div>

              <DialogFooter>
                <Button variant="outline" onClick={() => setIsOpen(false)}>
                  Cancel
                </Button>
                <Button
                  onClick={handleSave}
                  disabled={updateMutation.isPending}
                >
                  {updateMutation.isPending ? 'Saving...' : 'Save Changes'}
                </Button>
              </DialogFooter>
            </>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
}

function StatusBadge({ status }: { status: string }) {
  switch (status) {
    case 'NEW':
      return (
        <Badge
          variant="outline"
          className="bg-blue-500/10 text-blue-500 border-blue-500/20"
        >
          New
        </Badge>
      );
    case 'IN_PROGRESS':
      return (
        <Badge
          variant="outline"
          className="bg-yellow-500/10 text-yellow-500 border-yellow-500/20"
        >
          In Progress
        </Badge>
      );
    case 'RESOLVED':
      return (
        <Badge
          variant="outline"
          className="bg-green-500/10 text-green-500 border-green-500/20"
        >
          Resolved
        </Badge>
      );
    case 'CLOSED':
      return <Badge variant="secondary">Closed</Badge>;
    default:
      return <Badge variant="outline">{status}</Badge>;
  }
}

function SeverityBadge({ severity }: { severity: string }) {
  switch (severity) {
    case 'CRITICAL':
      return (
        <div className="flex items-center text-red-500 font-medium text-xs">
          <AlertTriangle className="h-3 w-3 mr-1" /> Critical
        </div>
      );
    case 'HIGH':
      return <div className="text-orange-500 font-medium text-xs">High</div>;
    case 'MEDIUM':
      return <div className="text-yellow-500 font-medium text-xs">Medium</div>;
    case 'LOW':
      return <div className="text-green-500 font-medium text-xs">Low</div>;
    default:
      return <span className="text-muted-foreground text-xs">{severity}</span>;
  }
}

import { createFileRoute, redirect } from '@tanstack/react-router';
import { useSuspenseQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { adminChallengesQueryOptions } from '@/lib/admin.query';
import { updateChallengeStatus } from '@/server/admin.fn';
import { Card, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { ArrowLeft, Clock, Layout, Search } from 'lucide-react';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import { Link } from '@tanstack/react-router';
import { Button } from '@/components/ui/button';
import { toast } from 'sonner';
import { Switch } from '@/components/ui/switch';
import { useState, useMemo, useEffect } from 'react';
import { Input } from '@/components/ui/input';
import { motion, AnimatePresence } from 'framer-motion';
import { DataTablePagination } from '@/components/admin/data-table-pagination';

interface AdminChallenge {
  id: string;
  title: string | { en: string;[key: string]: string }; // Updated to support localized title
  slug: string;
  type: 'JAVASCRIPT' | 'PLAYWRIGHT' | 'CSS_SELECTOR' | 'XPATH_SELECTOR';
  difficulty: 'EASY' | 'MEDIUM' | 'HARD';
  xpReward: number;
  order: number;
  isPublished: boolean;
  tags: string[] | null;
}

export const Route = createFileRoute('/admin/challenges')({
  loader: async ({ context }) => {
    await context.queryClient.ensureQueryData(adminChallengesQueryOptions);
  },
  component: ChallengeManager,
});

function ChallengeManager() {
  const queryClient = useQueryClient();
  const [searchQuery, setSearchQuery] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const [pageSize, setPageSize] = useState(10);

  const { data: challenges } = useSuspenseQuery(adminChallengesQueryOptions);

  const filteredChallenges = useMemo(() => {
    if (!challenges) return [];
    const query = searchQuery.toLowerCase().trim();
    const result = query
      ? challenges.filter(
        (c: AdminChallenge) => {
          const title = typeof c.title === 'object' ? c.title?.en || '' : c.title;
          return title.toLowerCase().includes(query) ||
            c.slug?.toLowerCase().includes(query)
        }
      )
      : challenges;

    return result;
  }, [challenges, searchQuery]);

  const totalPages = Math.ceil(filteredChallenges.length / pageSize);
  const paginatedChallenges = useMemo(() => {
    const start = (currentPage - 1) * pageSize;
    return filteredChallenges.slice(start, start + pageSize);
  }, [filteredChallenges, currentPage, pageSize]);

  // Reset to page 1 on search
  useEffect(() => {
    setCurrentPage(1);
  }, [searchQuery]);

  const updateMutation = useMutation({
    mutationFn: async (data: {
      id: string;
      isPublished?: boolean;
      isComingSoon?: boolean;
    }) => {
      const res = await updateChallengeStatus({ data });
      if (!res.success)
        throw new Error(res.error || 'Failed to update challenge');
      return res;
    },
    onSuccess: async () => {
      await queryClient.invalidateQueries({ queryKey: ['admin-challenges'] });
      toast.success('Challenge updated successfully');
    },
    onError: () => {
      toast.error('Failed to update challenge');
    },
  });


  return (
    <div className="container mx-auto p-6 space-y-8 animate-fade-in relative z-10">
      {/* Header Section */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 border-b border-border/40 pb-6">
        <div className="flex items-center gap-4">
          <Link to="/admin">
            <Button
              variant="ghost"
              size="icon"
              className="rounded-full hover:bg-primary/10"
            >
              <ArrowLeft className="h-4 w-4" />
            </Button>
          </Link>
          <div>
            <h1 className="text-3xl font-bold tracking-tight bg-gradient-to-r from-primary to-purple-600 bg-clip-text text-transparent">
              Challenge Manager
            </h1>
            <p className="text-muted-foreground mt-1">
              Control visibility and upcoming content.
            </p>
          </div>
        </div>

        <div className="relative group w-full md:w-auto">
          <div className="absolute -inset-0.5 bg-gradient-to-r from-primary/50 to-purple-600/50 rounded-lg blur opacity-0 group-hover:opacity-75 transition duration-500"></div>
          <div className="relative flex items-center">
            <Search className="absolute left-3 h-4 w-4 text-muted-foreground group-focus-within:text-primary transition-colors" />
            <Input
              placeholder="Search challenges..."
              className="pl-10 w-full md:w-[300px] bg-background/80 backdrop-blur-sm border-muted-foreground/20 focus-visible:ring-primary/50 transition-all"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
          </div>
        </div>
      </div>

      <Card>
        <CardContent className="p-0">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Challenge</TableHead>
                <TableHead>Type</TableHead>
                <TableHead>Difficulty</TableHead>
                <TableHead className="text-center">Published</TableHead>
                <TableHead className="text-center">Coming Soon</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              <AnimatePresence mode="popLayout">
                {paginatedChallenges.length === 0 ? (
                  <TableRow>
                    <TableCell
                      colSpan={5}
                      className="text-center h-24 text-muted-foreground"
                    >
                      {searchQuery
                        ? `No challenges matching "${searchQuery}"`
                        : 'No challenges found.'}
                    </TableCell>
                  </TableRow>
                ) : (
                  paginatedChallenges.map((challenge: AdminChallenge) => {
                    const isComingSoon =
                      challenge.tags?.includes('coming-soon');

                    // Badge Colors
                    const typeColors = {
                      JAVASCRIPT:
                        'bg-yellow-500/10 text-yellow-600 border-yellow-500/20 dark:text-yellow-400',
                      PLAYWRIGHT:
                        'bg-green-500/10 text-green-600 border-green-500/20 dark:text-green-400',
                      CSS_SELECTOR:
                        'bg-blue-500/10 text-blue-600 border-blue-500/20 dark:text-blue-400',
                      XPATH_SELECTOR:
                        'bg-purple-500/10 text-purple-600 border-purple-500/20 dark:text-purple-400',
                    };

                    const difficultyColors = {
                      EASY: 'bg-emerald-500/10 text-emerald-600 border-emerald-500/20 dark:text-emerald-400',
                      MEDIUM:
                        'bg-orange-500/10 text-orange-600 border-orange-500/20 dark:text-orange-400',
                      HARD: 'bg-red-500/10 text-red-600 border-red-500/20 dark:text-red-400',
                    };

                    return (
                      <motion.tr
                        key={challenge.id}
                        layout
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, scale: 0.95 }}
                        transition={{ duration: 0.2 }}
                        className="group border-b transition-colors hover:bg-muted/50 data-[state=selected]:bg-muted"
                      >
                        <TableCell component="th">
                          {' '}
                          {/* Workaround for motion.tr typings if needed, but usually motion.tr works fine as child of tbody if TableBody accepts valid nodes? Actually radix/shadcn TableBody is basically a tbody. Framer motion needs direct direct parent context sometimes or replace TableRow with motion copy of it. */}
                          {/* Ideally I should use a custom component for motion row or just motion.tr inside standard tbody. 
                                                     However, shadcn TableRow is a component. I should make it a motion component.
                                                     Or better: wrap the content of TableRow? No, animation needs to be on the row.
                                                     Let's try using standard motion.tr but keeping ShadCN classes on it.
                                                   */}
                          <div className="flex flex-col py-2">
                            <span className="font-medium text-sm group-hover:text-primary transition-colors">
                              {typeof challenge.title === 'object' ? challenge.title?.en : challenge.title}
                            </span>
                            <span className="text-xs text-muted-foreground font-mono">
                              {challenge.slug}
                            </span>
                          </div>
                        </TableCell>
                        <TableCell>
                          <Badge
                            variant="outline"
                            className={`text-[10px] uppercase shadow-sm ${typeColors[challenge.type] || ''}`}
                          >
                            {challenge.type.replace('_', ' ')}
                          </Badge>
                        </TableCell>
                        <TableCell>
                          <Badge
                            variant="secondary"
                            className={`text-[10px] shadow-sm ${difficultyColors[challenge.difficulty] || ''}`}
                          >
                            {challenge.difficulty}
                          </Badge>
                        </TableCell>
                        <TableCell className="text-center">
                          <div className="flex items-center justify-center gap-2">
                            <Switch
                              checked={challenge.isPublished}
                              onCheckedChange={(checked) =>
                                updateMutation.mutate({
                                  id: challenge.id,
                                  isPublished: checked,
                                })
                              }
                              disabled={updateMutation.isPending}
                              className="data-[state=checked]:bg-green-600"
                            />
                          </div>
                        </TableCell>
                        <TableCell className="text-center">
                          <div className="flex items-center justify-center gap-2">
                            <Switch
                              checked={isComingSoon}
                              onCheckedChange={(checked) =>
                                updateMutation.mutate({
                                  id: challenge.id,
                                  isComingSoon: checked,
                                })
                              }
                              disabled={updateMutation.isPending}
                              className="data-[state=checked]:bg-orange-500"
                            />
                          </div>
                        </TableCell>
                      </motion.tr>
                    );
                  })
                )}
              </AnimatePresence>
            </TableBody>
          </Table>
          <DataTablePagination
            currentPage={currentPage}
            totalPages={totalPages}
            pageSize={pageSize}
            setPageSize={setPageSize}
            onPageChange={setCurrentPage}
            totalItems={filteredChallenges.length}
          />
        </CardContent>
      </Card>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <Card className="bg-blue-500/5 border-blue-200/20 shadow-none dark:bg-blue-500/10">
          <CardContent className="p-4 flex gap-4 items-start">
            <div className="p-2 bg-blue-500/10 rounded-lg shrink-0">
              <Layout className="h-5 w-5 text-blue-600 dark:text-blue-400" />
            </div>
            <div>
              <h3 className="font-semibold text-sm text-blue-700 dark:text-blue-300 mb-1">
                Visibility
              </h3>
              <p className="text-xs text-muted-foreground leading-relaxed">
                Unpublishing a challenge hides it from the list & prevents
                access to the playground. Changes reflect immediately.
              </p>
            </div>
          </CardContent>
        </Card>

        <Card className="bg-orange-500/5 border-orange-200/20 shadow-none dark:bg-orange-500/10">
          <CardContent className="p-4 flex gap-4 items-start">
            <div className="p-2 bg-orange-500/10 rounded-lg shrink-0">
              <Clock className="h-5 w-5 text-orange-600 dark:text-orange-400" />
            </div>
            <div>
              <h3 className="font-semibold text-sm text-orange-700 dark:text-orange-300 mb-1">
                Teasing
              </h3>
              <p className="text-xs text-muted-foreground leading-relaxed">
                Marking as "Coming Soon" shows a lock icon and blocks access,
                but keeps the title visible. Useful for roadmap items.
              </p>
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

import { createFileRoute } from '@tanstack/react-router';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { getAdminSubscribers, updateSubscriberStatus } from '@/server/admin.fn';
import { Card, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { ArrowLeft, Download, Mail } from 'lucide-react';
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from '@/components/ui/table';
import { Link } from '@tanstack/react-router';
import { Button } from '@/components/ui/button';
import { toast } from 'sonner';
import { useState, useMemo } from 'react';
import { DataTablePagination } from '@/components/admin/data-table-pagination';
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';

export const Route = createFileRoute('/admin/newsletter')({
    component: NewsletterManager,
});

type SubscriberStatus = 'PENDING' | 'CONFIRMED' | 'UNSUBSCRIBED';

function NewsletterManager() {
    const queryClient = useQueryClient();
    const [currentPage, setCurrentPage] = useState(1);
    const [pageSize, setPageSize] = useState(10);

    const { data: subscribers, isLoading } = useQuery({
        queryKey: ['admin-subscribers'],
        queryFn: async () => {
            const res = await getAdminSubscribers();
            if (!res.success)
                throw new Error(res.error || 'Failed to fetch subscribers');
            return res.data;
        },
    });

    const totalPages = Math.ceil((subscribers?.length || 0) / pageSize);
    const paginatedSubscribers = useMemo(() => {
        if (!subscribers) return [];
        const start = (currentPage - 1) * pageSize;
        return subscribers.slice(start, start + pageSize);
    }, [subscribers, currentPage, pageSize]);

    const updateMutation = useMutation({
        mutationFn: async (data: { id: string; status: SubscriberStatus }) => {
            const res = await updateSubscriberStatus({ data });
            if (!res.success)
                throw new Error(res.error || 'Failed to update subscriber');
            return res;
        },
        onSuccess: async () => {
            await queryClient.invalidateQueries({ queryKey: ['admin-subscribers'] });
            toast.success('Subscriber updated successfully');
        },
        onError: () => {
            toast.error('Failed to update subscriber');
        },
    });

    const handleExportCSV = () => {
        if (!subscribers) return;

        const headers = ['Email', 'Status', 'Date Subscribed', 'Date Confirmed'];
        const csvContent = [
            headers.join(','),
            ...subscribers.map((sub) =>
                [
                    sub.email,
                    sub.status,
                    new Date(sub.createdAt).toISOString(),
                    sub.confirmedAt ? new Date(sub.confirmedAt).toISOString() : '',
                ].join(','),
            ),
        ].join('\n');

        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.setAttribute('href', url);
        link.setAttribute(
            'download',
            `newsletter_subscribers_${new Date().toISOString().split('T')[0]}.csv`,
        );
        link.style.visibility = 'hidden';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    if (isLoading)
        return <div className="p-8 text-center">Loading subscribers...</div>;

    return (
        <div className="container mx-auto p-6 space-y-8 animate-fade-in">
            <div className="flex items-center justify-between gap-4">
                <div className="flex items-center gap-4">
                    <Link to="/admin">
                        <Button variant="ghost" size="icon">
                            <ArrowLeft className="h-4 w-4" />
                        </Button>
                    </Link>
                    <div>
                        <h1 className="text-3xl font-bold tracking-tight">Newsletter</h1>
                        <p className="text-muted-foreground mt-1">
                            Manage subscribers and exports.
                        </p>
                    </div>
                </div>
                <Button onClick={handleExportCSV} variant="outline" className="gap-2">
                    <Download className="h-4 w-4" />
                    Export CSV
                </Button>
            </div>

            <Card>
                <CardContent className="p-0">
                    <Table>
                        <TableHeader>
                            <TableRow>
                                <TableHead>Status</TableHead>
                                <TableHead>Email</TableHead>
                                <TableHead>Subscribed</TableHead>
                                <TableHead>Confirmed</TableHead>
                                <TableHead className="text-right">Actions</TableHead>
                            </TableRow>
                        </TableHeader>
                        <TableBody>
                            {paginatedSubscribers.length === 0 ? (
                                <TableRow>
                                    <TableCell
                                        colSpan={5}
                                        className="text-center h-24 text-muted-foreground"
                                    >
                                        No subscribers found.
                                    </TableCell>
                                </TableRow>
                            ) : (
                                paginatedSubscribers.map((sub) => (
                                    <TableRow key={sub.id}>
                                        <TableCell>
                                            <StatusBadge status={sub.status} />
                                        </TableCell>
                                        <TableCell className="font-medium">{sub.email}</TableCell>
                                        <TableCell className="text-muted-foreground text-sm">
                                            {new Date(sub.createdAt).toLocaleDateString()}
                                        </TableCell>
                                        <TableCell className="text-muted-foreground text-sm">
                                            {sub.confirmedAt
                                                ? new Date(sub.confirmedAt).toLocaleDateString()
                                                : '-'}
                                        </TableCell>
                                        <TableCell className="text-right">
                                            <DropdownMenu>
                                                <DropdownMenuTrigger asChild>
                                                    <Button variant="ghost" size="sm">
                                                        Manage
                                                    </Button>
                                                </DropdownMenuTrigger>
                                                <DropdownMenuContent align="end">
                                                    <DropdownMenuItem
                                                        onClick={() =>
                                                            updateMutation.mutate({
                                                                id: sub.id,
                                                                status: 'CONFIRMED',
                                                            })
                                                        }
                                                        disabled={sub.status === 'CONFIRMED'}
                                                    >
                                                        Mark Confirmed
                                                    </DropdownMenuItem>
                                                    <DropdownMenuItem
                                                        onClick={() =>
                                                            updateMutation.mutate({
                                                                id: sub.id,
                                                                status: 'UNSUBSCRIBED',
                                                            })
                                                        }
                                                        disabled={sub.status === 'UNSUBSCRIBED'}
                                                        className="text-red-600 focus:text-red-600"
                                                    >
                                                        Unsubscribe
                                                    </DropdownMenuItem>
                                                </DropdownMenuContent>
                                            </DropdownMenu>
                                        </TableCell>
                                    </TableRow>
                                ))
                            )}
                        </TableBody>
                    </Table>
                    <DataTablePagination
                        currentPage={currentPage}
                        totalPages={totalPages}
                        pageSize={pageSize}
                        setPageSize={setPageSize}
                        onPageChange={setCurrentPage}
                        totalItems={subscribers?.length || 0}
                    />
                </CardContent>
            </Card>
        </div>
    );
}

function StatusBadge({ status }: { status: string }) {
    switch (status) {
        case 'PENDING':
            return (
                <Badge
                    variant="outline"
                    className="bg-yellow-500/10 text-yellow-500 border-yellow-500/20"
                >
                    Pending
                </Badge>
            );
        case 'CONFIRMED':
            return (
                <Badge
                    variant="outline"
                    className="bg-green-500/10 text-green-500 border-green-500/20"
                >
                    Confirmed
                </Badge>
            );
        case 'UNSUBSCRIBED':
            return <Badge variant="secondary">Unsubscribed</Badge>;
        default:
            return <Badge variant="outline">{status}</Badge>;
    }
}

import { createFileRoute } from '@tanstack/react-router';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { getAdminTutorials, updateTutorialStatus } from '@/server/admin.fn';
import { Card, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { BookOpen, Search, Eye, Clock } from 'lucide-react';
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from '@/components/ui/table';
import { Switch } from '@/components/ui/switch';
import { useState, useMemo, useEffect } from 'react';
import { Input } from '@/components/ui/input';
import { DataTablePagination } from '@/components/admin/data-table-pagination';
import { toast } from 'sonner';

export const Route = createFileRoute('/admin/tutorials')({
    component: TutorialsManager,
});

function TutorialsManager() {
    const queryClient = useQueryClient();
    const [searchQuery, setSearchQuery] = useState('');
    const [currentPage, setCurrentPage] = useState(1);
    const [pageSize, setPageSize] = useState(10);

    const { data: tutorials, isLoading } = useQuery({
        queryKey: ['admin-tutorials'],
        queryFn: async () => {
            const res = await getAdminTutorials();
            if (!res.success) throw new Error(res.error || 'Failed to fetch tutorials');
            return res.data;
        },
    });

    const filteredTutorials = useMemo(() => {
        if (!tutorials) return [];
        const query = searchQuery.toLowerCase().trim();
        if (!query) return tutorials;
        return tutorials.filter((t) => {
            const title = typeof t.title === 'object' ? t.title.en : t.title;
            return title.toLowerCase().includes(query) || t.slug.toLowerCase().includes(query);
        });
    }, [tutorials, searchQuery]);

    const totalPages = Math.ceil(filteredTutorials.length / pageSize);
    const paginatedTutorials = useMemo(() => {
        const start = (currentPage - 1) * pageSize;
        return filteredTutorials.slice(start, start + pageSize);
    }, [filteredTutorials, currentPage, pageSize]);

    const updateMutation = useMutation({
        mutationFn: async (data: { id: string; isPublished: boolean }) => {
            const res = await updateTutorialStatus({ data });
            if (!res.success) throw new Error(res.error || 'Failed to update tutorial');
            return res;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['admin-tutorials'] });
            toast.success('Tutorial visibility updated');
        },
        onError: () => {
            toast.error('Failed to update tutorial');
        },
    });

    useEffect(() => {
        setCurrentPage(1);
    }, [searchQuery]);

    if (isLoading) return <div className="p-8 text-center animate-pulse">Loading tutorials...</div>;

    return (
        <div className="container mx-auto p-6 space-y-8 animate-fade-in text-card-foreground">
            <div>
                <h1 className="text-3xl font-bold tracking-tight">Tutorials Manager</h1>
                <p className="text-muted-foreground mt-1">
                    Manage step-by-step learning content.
                </p>
            </div>

            <div className="relative max-w-md">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                <Input
                    placeholder="Search tutorials..."
                    className="pl-10"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                />
            </div>

            <Card>
                <CardContent className="p-0">
                    <Table>
                        <TableHeader>
                            <TableRow>
                                <TableHead>Tutorial</TableHead>
                                <TableHead>Stats</TableHead>
                                <TableHead>Created</TableHead>
                                <TableHead className="text-right">Published</TableHead>
                            </TableRow>
                        </TableHeader>
                        <TableBody>
                            {paginatedTutorials.length === 0 ? (
                                <TableRow>
                                    <TableCell
                                        colSpan={4}
                                        className="text-center h-24 text-muted-foreground"
                                    >
                                        No tutorials found.
                                    </TableCell>
                                </TableRow>
                            ) : (
                                paginatedTutorials.map((tut) => (
                                    <TableRow key={tut.id}>
                                        <TableCell>
                                            <div className="flex flex-col py-1">
                                                <span className="font-semibold text-sm">
                                                    {typeof tut.title === 'object' ? tut.title.en : tut.title}
                                                </span>
                                                <span className="text-[10px] text-muted-foreground font-mono">
                                                    /{tut.slug}
                                                </span>
                                            </div>
                                        </TableCell>
                                        <TableCell>
                                            <div className="flex items-center gap-3 text-xs text-muted-foreground">
                                                <span className="flex items-center gap-1">
                                                    <Eye className="h-3 w-3" />
                                                    {tut.viewCount || 0} views
                                                </span>
                                            </div>
                                        </TableCell>
                                        <TableCell className="text-sm text-muted-foreground">
                                            <span className="flex items-center gap-1">
                                                <Clock className="h-3 w-3" />
                                                {new Date(tut.createdAt).toLocaleDateString()}
                                            </span>
                                        </TableCell>
                                        <TableCell className="text-right">
                                            <Switch
                                                checked={tut.isPublished}
                                                onCheckedChange={(checked) =>
                                                    updateMutation.mutate({
                                                        id: tut.id,
                                                        isPublished: checked,
                                                    })
                                                }
                                                disabled={updateMutation.isPending}
                                            />
                                        </TableCell>
                                    </TableRow>
                                ))
                            )}
                        </TableBody>
                    </Table>
                    <DataTablePagination
                        currentPage={currentPage}
                        totalPages={totalPages}
                        pageSize={pageSize}
                        setPageSize={setPageSize}
                        onPageChange={setCurrentPage}
                        totalItems={filteredTutorials.length}
                    />
                </CardContent>
            </Card>
        </div>
    );
}

import { createFileRoute, Link, getRouteApi } from '@tanstack/react-router';
