import fs from 'node:fs';
import path from 'node:path';

const challengesDir = path.resolve(process.cwd(), 'content/challenges');
const outputPath = path.resolve(process.cwd(), 'docs/solutions.md');

interface Challenge {
    slug: string;
    type: string;
    title: { en: string; id: string };
    solution?: string;
}

interface ChallengeTier {
    tier: string;
    challenges: Challenge[];
}

function generateMarkdown() {
    const files = fs.readdirSync(challengesDir).filter(f => f.endsWith('.json') && !f.startsWith('_'));

    let markdown = '# Challenge Solutions Reference\n\n';
    markdown += 'This document contains the **official solutions** for all coding challenges, extracted directly from the challenge definitions.\n\n---\n\n## Table of Contents\n\n';

    const tiers: ChallengeTier[] = [];

    for (const file of files) {
        const filePath = path.join(challengesDir, file);
        const content = JSON.parse(fs.readFileSync(filePath, 'utf-8')) as ChallengeTier;
        tiers.push(content);
    }

    // Sort tiers if needed, for now just use them
    // Map tier names to display names
    const tierDisplayNames: Record<string, string> = {
        basic: 'Basic Tier',
        beginner: 'Beginner Tier',
        intermediate: 'Intermediate Tier',
        typescript: 'TypeScript Tier',
        e2e: 'E2E Tier',
    };

    // Sort challenges by order or hierarchy? The JSONs have "order" field.
    // But let's keep it simple first.

    for (const tier of tiers) {
        const displayName = tierDisplayNames[tier.tier] || tier.tier;
        markdown += `- [${displayName}](#${tier.tier}-tier)\n`;
    }

    markdown += '\n---\n\n';

    for (const tier of tiers) {
        const displayName = tierDisplayNames[tier.tier] || tier.tier;
        markdown += `## ${displayName}\n\n`;

        for (const challenge of tier.challenges) {
            if (!challenge.solution) continue;

            markdown += `### ${challenge.slug} - ${challenge.title.en}\n\n`;

            const lang = getLanguage(challenge.type);
            markdown += `\`\`\`${lang}\n${challenge.solution}\n\`\`\`\n\n`;
        }

        markdown += '---\n\n';
    }

    fs.writeFileSync(outputPath, markdown);
    console.log(`Generated ${outputPath} successfully.`);
}

function getLanguage(type: string): string {
    switch (type) {
        case 'CSS_SELECTOR': return 'css';
        case 'XPATH': return 'xpath';
        case 'JAVASCRIPT':
        case 'DOM':
        case 'ASYNC':
        case 'PLAYWRIGHT':
        case 'E2E':
            return 'javascript';
        case 'TYPESCRIPT': return 'typescript';
        default: return 'text';
    }
}

generateMarkdown();

/**
 * Server function to get BetterAuth session
 * Used by route beforeLoad to check authentication
 */
import { createServerFn } from '@tanstack/react-start';
import { z } from 'zod';
import { getRequestHeaders } from '@tanstack/react-start/server';
import { auth } from './auth.server';
import { db } from '@/db';
import { users, accounts } from '@/db/schema';
import { eq, and } from 'drizzle-orm';
import { sendVerificationEmail } from '@/server/email.server';
import { logger } from '@/lib/logger';

export type SessionUser = {
  id: string;
  email: string;
  name: string | null;
  image: string | null;
  emailVerified: boolean;
  role: string | null;
};

export type AuthSession = {
  user: SessionUser | null;
  isAuthenticated: boolean;
  gaMeasurementId?: string;
};

// Helper to update user image from Google if missing (Lazy Migration)
async function ensureUserImage(userId: string): Promise<string | null> {
  try {
    // Check for Google account
    const account = await db.query.accounts.findFirst({
      where: and(eq(accounts.userId, userId), eq(accounts.providerId, 'google')),
    });

    if (account?.idToken) {
      // Decode ID Token to get picture
      try {
        const payload = JSON.parse(
          Buffer.from(account.idToken.split('.')[1], 'base64').toString(),
        );
        if (payload.picture) {
          await db
            .update(users)
            .set({ image: payload.picture })
            .where(eq(users.id, userId));
          return payload.picture as string;
        }
      } catch (e) {
        // Ignore decoding errors
      }
    }
  } catch (error) {
    console.error('[Auth] Failed to lazy update user image:', error);
  }
  return null;
}

export const getServerSession = createServerFn({ method: 'GET' }).handler(
  async (): Promise<AuthSession> => {
    try {
      // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment
      const headers = getRequestHeaders();

      // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment
      const session = await auth.api.getSession({ headers });

      if (session?.user) {
        let image = session.user.image;
        if (!image) {
          const newImage = await ensureUserImage(session.user.id);
          if (newImage) image = newImage;
        }

        return {
          user: {
            id: session.user.id,
            email: session.user.email,
            name: session.user.name || null,
            image: image || null,
            emailVerified: session.user.emailVerified || false,
            // eslint-disable-next-line @typescript-eslint/no-explicit-any, @typescript-eslint/no-unsafe-member-access, @typescript-eslint/no-unsafe-assignment
            role: (session.user as any).role || 'USER',
          },
          isAuthenticated: true,
          gaMeasurementId: process.env.VITE_GA_MEASUREMENT_ID,
        };
      }
    } catch (error) {
      console.error('[Auth] Failed to get session:', error);
    }

    return {
      user: null,
      isAuthenticated: false,
      gaMeasurementId: process.env.VITE_GA_MEASUREMENT_ID,
    };
  },
);

// Simple in-memory rate limiting (per email, 60 second cooldown)
// Note: This resets on server restart/redeploy
const rateLimitMap = new Map<string, number>();
const COOLDOWN_MS = 60 * 1000;

// Zod schema for email validation
const ResendVerificationSchema = z.object({
  email: z.string().email('Invalid email format'),
});

export const resendVerification = createServerFn({ method: 'POST' })
  .inputValidator((data: unknown) => ResendVerificationSchema.parse(data))
  .handler(async ({ data }) => {
    try {
      const { email } = data;

      const normalizedEmail = email.toLowerCase().trim();

      // Rate limiting check
      const lastSent = rateLimitMap.get(normalizedEmail);
      const now = Date.now();

      if (lastSent && now - lastSent < COOLDOWN_MS) {
        const remainingSeconds = Math.ceil(
          (COOLDOWN_MS - (now - lastSent)) / 1000,
        );
        return {
          success: false,
          error: `Please wait ${remainingSeconds} seconds before requesting another email`,
          cooldownRemaining: remainingSeconds,
        };
      }

      // Find user by email
      const user = await db.query.users.findFirst({
        where: eq(users.email, normalizedEmail),
      });

      if (!user) {
        // Don't reveal if email exists - return success anyway
        return {
          success: true,
          message:
            'If an account with that email exists, a verification email has been sent.',
        };
      }

      // Check if already verified
      if (user.emailVerified) {
        return {
          success: true,
          message: 'Your email is already verified. You can sign in.',
          alreadyVerified: true,
        };
      }

      // Generate verification URL
      const baseUrl = process.env.BETTER_AUTH_URL || 'http://localhost:3000';
      const token = crypto.randomUUID();
      const verificationUrl = `${baseUrl}/api/auth/verify-email?token=${token}&callbackURL=/login`;

      // Send the verification email
      // Fire and forget email sending
      sendVerificationEmail(
        user.email,
        verificationUrl,
        user.name || undefined,
      ).catch((error) => {
        console.error(
          '[Auth] Background resend verification email failed:',
          error,
        );
      });

      // Update rate limit
      rateLimitMap.set(normalizedEmail, now);
      logger.info(`[Auth] Resent verification email to ${normalizedEmail}`);

      return {
        success: true,
        message: 'Verification email sent! Please check your inbox.',
      };
    } catch (error) {
      console.error('Error resending verification email:', error);
      return { success: false, error: 'Failed to resend verification email' };
    }
  });

/**
 * Composable Auth Middleware for TanStack Start
 * Follows 2026 TanStack Start middleware pattern
 *
 * Usage:
 * export const protectedFn = createServerFn({ method: 'POST' })
 *   .middleware([authMiddleware])
 *   .handler(async ({ context }) => {
 *     const userId = context.userId; // Type-safe, guaranteed to exist
 *   });
 */
import { createMiddleware } from '@tanstack/react-start';
import { getRequestHeaders } from '@tanstack/react-start/server';
import { auth } from './auth.server';

// Type for authenticated user context
export interface AuthUser {
    id: string;
    email: string;
    name: string | null;
    image: string | null;
    role: string | null;
}

// Context provided by authMiddleware (user guaranteed to exist)
export interface AuthContext {
    user: AuthUser;
    userId: string;
}

/**
 * Strict auth middleware - throws if not authenticated.
 * Use for protected endpoints that require login.
 *
 * The error is thrown and should be caught by your error boundary
 * or handled by TanStack Start's built-in error handling.
 */
export const authMiddleware = createMiddleware({ type: 'function' }).server(
    async ({ next }) => {
        const headers = getRequestHeaders();

        const session = await auth.api.getSession({ headers });

        if (!session?.user?.id) {
            throw new Error('Unauthorized');
        }

        return next({
            context: {
                user: {
                    id: session.user.id,
                    email: session.user.email,
                    name: session.user.name || null,
                    image: session.user.image || null,
                    // eslint-disable-next-line @typescript-eslint/no-explicit-any, @typescript-eslint/no-unsafe-member-access
                    role: (session.user as any).role || 'USER',
                },
                userId: session.user.id,
            },
        });
    },
);

/**
 * Optional auth middleware - does NOT throw if not authenticated.
 * Use for public endpoints that can be enhanced with user data.
 */
export const optionalAuthMiddleware = createMiddleware({
    type: 'function',
}).server(async ({ next }) => {
    const headers = getRequestHeaders();

    const session = await auth.api.getSession({ headers });

    return next({
        context: {
            user: session?.user
                ? {
                    id: session.user.id,
                    email: session.user.email,
                    name: session.user.name || null,
                    image: session.user.image || null,
                    // eslint-disable-next-line @typescript-eslint/no-explicit-any, @typescript-eslint/no-unsafe-member-access
                    role: (session.user as any).role || 'USER',
                }
                : null,
            userId: session?.user?.id || null,
            isAuthenticated: !!session?.user,
        },
    });
});

/**
 * Admin middleware - ensures user has ADMIN role.
 * Extends authMiddleware.
 */
export const adminMiddleware = createMiddleware({ type: 'function' })
    .middleware([authMiddleware])
    .server(async ({ next, context }) => {
        if (context.user.role !== 'ADMIN') {
            throw new Error('Unauthorized: Admin access required');
        }

        return next({
            context: {
                user: context.user,
                userId: context.userId,
            },
        });
    });

