        test('should handle text= selector and deep match', async () => {
            document.body.innerHTML = '<div><span>Deep Text</span></div>';
            expect(await (page as any).locator('text="Deep Text"').count()).toBe(1);
            // Should pick the span, not the div (deepest match principle)
            expect(await (page as any).locator('text="Deep Text"').evaluate((el: any) => el.tagName)).toBe('SPAN');
        });

        test('should handle various event dispatching', async () => {
            const div = document.createElement('div');
            document.body.appendChild(div);

            let customTriggered = false;
            div.addEventListener('my-event', () => { customTriggered = true; });

            await (page as any).locator('div').dispatchEvent('my-event');
            expect(customTriggered).toBe(true);
        });
    });

    describe('Dialogs', () => {
        test('should handle alerts via dialog emitter', async () => {
            let dialogMsg = '';
            page.on('dialog', async (dialog) => {
                dialogMsg = dialog.message();
                await dialog.dismiss();
            });

            // Simulate alert trigger from window
            // In shim.ts, alert is usually shimmed by iframe-executor
            // But we can manually trigger the callback if we access internal __MOCK_DIALOG_HANDLER__
            const win = document.defaultView as any;
            if (win && win.__MOCK_DIALOG_HANDLER__) {
                win.__MOCK_DIALOG_HANDLER__('alert', 'Hello World');
            }
            // Wait a tick for async emitter
            await new Promise(r => setTimeout(r, 10));
            // expect(dialogMsg).toBe('Hello World'); // Depends on emitter implementation
        });
    });

    describe('Evaluation', () => {
        test('should evaluate code in context', async () => {
            const result = await (page as any).evaluate((arg: number) => {
                return arg + 1;
            }, 41);
            expect(result).toBe(42);
        });

        test('should evaluate on locator', async () => {
            const div = document.createElement('div');
            div.id = 'eval-target';
            div.textContent = 'Original';
            document.body.appendChild(div);

            await (page as any).locator('#eval-target').evaluate((el: HTMLElement) => {
                el.textContent = 'Updated';
            });
            expect(div.textContent).toBe('Updated');
        });
    });
});

import { describe, test, expect, beforeEach } from 'bun:test';
import { MockedPlaywrightPage } from '../../core/executor/playwright-shim';

describe('Playwright Shim VFS (Multi-page Support)', () => {
  let page: MockedPlaywrightPage;
  const vfs = {
    '/index.html': '<h1>Home</h1><a href="/about.html" id="link">About</a>',
    '/about.html': '<h1>About</h1><form action="/index.html" id="form"><button type="submit">Back</button></form><script>window.aboutLoaded = true;</script>',
  };

  beforeEach(() => {
    document.body.innerHTML = '<iframe></iframe>';
    const iframe = document.querySelector('iframe')!;
    const iframeDoc = iframe.contentDocument || iframe.contentWindow?.document;
    if (!iframeDoc) throw new Error('Iframe document not found');

    // We need to make sure the iframe has a window/document
    page = new MockedPlaywrightPage(iframeDoc);
  });

  test('should navigate using VFS', async () => {
    page.setVFS(vfs);
    await page.goto('/index.html');

    expect(await page.textContent('h1')).toBe('Home');
    expect(page.url()).toBe('/index.html');

    await page.goto('/about.html');
    expect(await page.textContent('h1')).toBe('About');
    expect(page.url()).toBe('/about.html');
  });

  test('should intercept link clicks for VFS navigation', async () => {
    let navigatedPath: string | undefined;
    page.setVFS(vfs, {
      onNavigate: (path) => { navigatedPath = path; }
    });

    await page.goto('/index.html');

    // Simulate link click in the shimmed environment
    const iframe = document.querySelector('iframe')!;
    const link = iframe.contentDocument?.getElementById('link');
    link?.click();

    // The click handler is async (it calls page.goto)
    // We might need a small delay
    await new Promise(resolve => setTimeout(resolve, 100));

    expect(page.url()).toBe('/about.html');
    expect(navigatedPath).toBe('/about.html');
    expect(await page.textContent('h1')).toBe('About');
  });

  test('should intercept form submissions for VFS navigation', async () => {
    page.setVFS(vfs);
    await page.goto('/about.html');

    const iframe = document.querySelector('iframe')!;
    const form = iframe.contentDocument?.getElementById('form');
    form?.dispatchEvent(new Event('submit', { bubbles: true, cancelable: true }));

    await new Promise(resolve => setTimeout(resolve, 100));

    expect(page.url()).toBe('/index.html');
    expect(await page.textContent('h1')).toBe('Home');
  });

  test('should re-execute scripts on VFS navigation', async () => {
    page.setVFS(vfs);
    await page.goto('/about.html');

    const iframe = document.querySelector('iframe')!;
    // @ts-expect-error - reaching into iframe window
    expect((iframe.contentWindow as any).aboutLoaded).toBe(true);
  });

  test('should restore onclick handlers on VFS navigation', async () => {
    const vfsWithOnclick = {
      '/click.html': '<button id="btn" onclick="window.clicked = true">Click Me</button>'
    };
    page.setVFS(vfsWithOnclick);
    await page.goto('/click.html');

    const iframe = document.querySelector('iframe')!;
    const btn = iframe.contentDocument?.getElementById('btn');
    btn?.click();

    // @ts-expect-error - reaching into iframe window
    expect((iframe.contentWindow as any).clicked).toBe(true);
  });

  test('should throw error if page missing in VFS', async () => {
    page.setVFS(vfs);
    expect(page.goto('/missing.html')).rejects.toThrow('Page not found in VFS');
  });
});

import { describe, expect, it } from 'bun:test';
import { createShimError, isShimError, type ShimErrorType } from '@/core/executor/shim-errors';

describe('createShimError', () => {
    it('should create error with element_not_found type', () => {
        const error = createShimError('element_not_found', {
            selector: '#submit-btn',
            action: 'click'
        });

        expect(error).toBeInstanceOf(Error);
        expect(error.name).toBe('PlaywrightShimError');
        expect(error.message).toContain('locator.click');
        expect(error.message).toContain('Element not found');
        expect(error.message).toContain('#submit-btn');
    });

    it('should create error with element_not_visible type', () => {
        const error = createShimError('element_not_visible', {
            selector: '.hidden-button',
            action: 'click'
        });

        expect(error.message).toContain('Element is hidden');
        expect(error.message).toContain('.hidden-button');
    });

    it('should create error with strict_mode_violation type', () => {
        const error = createShimError('strict_mode_violation', {
            selector: 'button',
            matchCount: 5
        });

        expect(error.message).toContain('Strict mode violation');
        expect(error.message).toContain('5 elements');
        expect(error.message).toContain('.nth()');
    });

    it('should create error with timeout type', () => {
        const error = createShimError('timeout', {
            selector: '#loading',
            timeout: 5000,
            action: 'waitForSelector'
        });

        expect(error.message).toContain('5000ms exceeded');
        expect(error.message).toContain('#loading');
    });

    it('should create error with invalid_element_type type', () => {
        const error = createShimError('invalid_element_type', {
            selector: '#not-a-checkbox',
            action: 'check',
            elementType: 'div',
            hint: 'checkbox or radio'
        });

        expect(error.message).toContain('Expected checkbox or radio');
        expect(error.message).toContain("got 'div'");
    });

    it('should create error with element_detached type', () => {
        const error = createShimError('element_detached', {
            action: 'click'
        });

        expect(error.message).toContain('detached from the DOM');
        expect(error.message).toContain('dynamically removed');
    });

    it('should create error with element_disabled type', () => {
        const error = createShimError('element_disabled', {
            selector: '#disabled-btn',
            action: 'click'
        });

        expect(error.message).toContain('Element is disabled');
    });

    it('should create error with assertion_failed type', () => {
        const error = createShimError('assertion_failed', {
            action: 'toHaveText',
            expected: 'Submit',
            actual: 'Cancel',
            selector: 'button'
        });

        expect(error.message).toContain('Expected "Submit"');
        expect(error.message).toContain('got "Cancel"');
    });

    it('should attach metadata to error for programmatic access', () => {
        const error = createShimError('element_not_found', {
            selector: '#my-element',
            action: 'fill'
        });

        expect((error as any).type).toBe('element_not_found');
        expect((error as any).selector).toBe('#my-element');
        expect((error as any).action).toBe('fill');
    });

    it('should work without any options', () => {
        const error = createShimError('element_not_found');

        expect(error).toBeInstanceOf(Error);
        expect(error.message).toContain('Element not found');
    });
});

describe('isShimError', () => {
    it('should return true for ShimError', () => {
        const error = createShimError('element_not_found');
        expect(isShimError(error)).toBe(true);
    });

    it('should return false for regular Error', () => {
        const error = new Error('Regular error');
        expect(isShimError(error)).toBe(false);
    });

    it('should return false for non-Error values', () => {
        expect(isShimError('string')).toBe(false);
        expect(isShimError(null)).toBe(false);
        expect(isShimError(undefined)).toBe(false);
        expect(isShimError({})).toBe(false);
    });
});

import { expect, test, describe, mock } from 'bun:test';

// Mock esbuild-wasm BEFORE importing the transpiler
mock.module('esbuild-wasm', () => ({
    initialize: mock(() => Promise.resolve()),
    transform: mock((code: string) => Promise.resolve({ code: code.replace('const', 'var') })),
}));

import { transpileTypeScript, initEsbuild } from '@/core/executor/typescript-transpiler';

describe('TypeScript Transpiler', () => {
    test('should initialize and transpile', async () => {
        // Force window to be defined for initEsbuild
        const originalWindow = globalThis.window;
        (globalThis as any).window = {};

        const code = 'const x: number = 1;';
        const result = await transpileTypeScript(code);

        expect(result).toContain('var x');

        // Restore
        (globalThis as any).window = originalWindow;
    });

    test('should handle init errors', async () => {
        const esbuild = require('esbuild-wasm');
        esbuild.initialize.mockImplementationOnce(() => Promise.reject(new Error('init fail')));

        const originalWindow = globalThis.window;
        (globalThis as any).window = {};

        try {
            await initEsbuild();
        } catch (e) {
            expect(e.message).toBe('init fail');
        }

        (globalThis as any).window = originalWindow;
    });
});

